      var statusOpts=['Pending','Processing','Ready','Completed'].map(function(s){
        return '<option value="'+s+'"'+(o.status===s?' selected':'')+'>'+s+'</option>';
      }).join('');

      var waNum=(o.phone||'').replace(/[^0-9]/g,'');

      // Gift images block
      var giftImgs=(o.items||[]).filter(function(it){return it.giftImage||(it.giftSides&&it.giftSides.length);});
      var giftBlock='';
