 var qtyStep2 = cfg.steps.find ? cfg.steps.find(function(s){return s.type==='qty';}) : null;
  var mult0 = (qtyStep2 && qtyStep2.labelMultiplier) || 1;
  var actualQtyForUnit = qty * mult0;
  var perUnit = (totalPrice > 0 && actualQtyForUnit > 0) ? 'S$' + (totalPrice / actualQtyForUnit).toFixed(2) + '/pc' : '';

