function cfgAddToCart(slug) {
  var cfg = CONFIGURATOR[slug];
  if (!cfg) { alert('Product not found'); return; }
  var prod = PRODUCTS_DATA[slug];
  if (!prod) { alert('Product data missing'); return; }

  // Ensure state exists
  if (!CFG_STATE[slug]) CFG_STATE[slug] = {};
  var state = CFG_STATE[slug];

  // Get qty step
  var qtyStep = null;
  for (var si = 0; si < cfg.steps.length; si++) {
    if (cfg.steps[si].type === 'qty') { qtyStep = cfg.steps[si]; break; }
  }
  var mult = (qtyStep && qtyStep.labelMultiplier) || 1;
  var rawQty = parseInt(state.qty) || (qtyStep && qtyStep.min) || 1;
  var actualQty = rawQty * mult;

  // Calculate total
  var result = cfgCalcTotal(slug, rawQty);
  var total = (result && result.total > 0) ? result.total : 0;

  // Build full config string from ALL steps
  var configParts = [];
  for (var si2 = 0; si2 < cfg.steps.length; si2++) {
    var step = cfg.steps[si2];
    if (step.type === 'qty') continue;
    var val = state[step.id];
    if (!val && val !== 0) continue;
    if (step.type === 'number') {
      if (parseFloat(val) > 0) configParts.push(step.label.replace(' (cm)','') + ': ' + val + 'cm');
    } else if (step.type === 'text') {
      if (val) configParts.push(step.label + ': ' + val);
    } else {
      // swatch or select
      var opts = step.options || [];
      for (var oi = 0; oi < opts.length; oi++) {
        if (opts[oi].slug === val) {
          var lbl = opts[oi].label;
          // Skip "No X" / "None" as they add no info
          if (lbl !== 'None' && lbl.indexOf('No ') !== 0) configParts.push(lbl);
          break;
        }
      }
    }
  }
  configParts.push(actualQty + (actualQty === 1 ? ' pc' : 'pcs'));

  var ppu = (actualQty > 0 && total > 0) ? total / actualQty : 0;
  var item = {
    id: slug + '_' + Date.now(),
    slug: slug,
    icon: prod.icon || '🖨️',
    product: prod.name,
    qty: actualQty,
    price: parseFloat(total.toFixed(2)),
    unit: total > 0 ? 'S$' + ppu.toFixed(2) + '/pc' : 'Quote on WhatsApp',
    config: configParts.join(' · ') || '—',
    notes: ''
  };

  cart.push(item);
  updateCartCount();
  showToast((prod.icon || '') + ' ' + prod.name + ' added to cart!');
  goSub('cart');
}

// -- addToCart: routes to cfgAddToCart or ppAddToCart --
function addToCart(slug) {
  var prod = PRODUCTS_DATA[slug];
  if (!prod) { alert('Product not found: ' + slug); return; }
  var isGift = prod.type==='gift' || (GIFT_CATS && GIFT_CATS.has(prod.category));
  if (isGift) {
    ppAddToCart(slug);
  } else {
    cfgAddToCart(slug);
  }
}

// -- updateCartCount: updates cart item count badge --
function updateCartCount() {
  var label = document.getElementById('cart-count-label');
  if (!label) return;
  var count = cart.length;
  if (count > 0) {
    label.textContent = count;
    label.style.display = 'inline-block';
  } else {
    label.style.display = 'none';
  }
}

