// -- PP3 STATE & INTERACTIONS ------------------


// ══════════════════════════════════════════════
// AI GIFT FLOW
// ══════════════════════════════════════════════

// ══════════════════════════════════════════════════════════════════════════════
// GIFT FLOW  —  unified engine driven by ex.giftConfig
// ══════════════════════════════════════════════════════════════════════════════
//
// ex.giftConfig = {
//   method: 'Laser Engraving' | 'UV Print' | 'Sublimation' | etc,
//   inputs: [
//     { type:'photo', label:'Upload photo', required:true },
//     { type:'text',  label:'Name',         placeholder:'e.g. Sarah', required:true, maxLength:40 }
//   ],
//   styleOptions: [            // empty = no style choice shown to customer
//     { label:'Oil Painting', prompt:'Transform into regal oil painting...' },
//     { label:'Watercolour',  prompt:'Soft watercolour illustration...' }
//   ],
//   textLayers: [              // drawn live on product image for engraving preview
//     { label:'Line 1', x:50, y:60, fontSize:18, fontStyle:'Georgia,serif',
//       color:'#c8a96e', align:'center', canMove:false, required:true }
//   ]
// }
//
// Flow logic:
//   hasPhoto && styleOptions.length  → upload → (style pick) → AI transform → preview/annotate → accept
//   hasPhoto && !styleOptions.length → upload → AI transform (single prompt) → preview → accept
//   !hasPhoto && textLayers.length   → overlay: text typed onto product image live → accept
//   hasPhoto && textLayers.length    → upload → overlay text on result → accept
// ══════════════════════════════════════════════════════════════════════════════

var _giftFlow = {};
// _giftFlow[slug] = {
//   phase: 'upload'|'style'|'processing'|'preview'|'overlay'|'accepted'
//   originalDataUrl, processedDataUrl,
//   selectedStyle,   // index into styleOptions
//   annotLines, drawMode, modifyPrompt,
//   ovTexts, ovPositions
// }

var GF_OV_FONTS = [
  { label:'Classic Serif',  value:'Georgia, serif' },
  { label:'Modern Sans',    value:'Helvetica Neue, Arial, sans-serif' },
  { label:'Script',         value:'Brush Script MT, cursive' },
  { label:'Monospace',      value:'Courier New, monospace' },
  { label:'Elegant',        value:'Palatino Linotype, serif' }
];

var GF_MODIFY_CHIPS = [
  'Simpler background',
  'More vibrant colours',
  'Softer style',
  'Higher contrast',
  'Add decorative border',
  'Make it look like a painting'
];

// ── Helpers ────────────────────────────────────────────────────────────────

function gfConfig(slug) {
  var ex = PP_EXTRA[slug] || {};
  return ex.giftConfig || {};
}
function gfIsTemplate(slug) {
  return gfConfig(slug).flowType === 'template';
}
function gfTemplateLayers(slug) {
  var gc = gfConfig(slug);
  if (gc.flowType === 'template' && gc.sides && gc.sides.length) {
    var st = _giftFlow[slug] || {};
    var si = st.currentSideIdx || 0;
    return (gc.sides[si] && gc.sides[si].templateFields) || gc.templateFields || [];
  }
  return gc.flowType === 'template' ? (gc.templateFields||[]) : (gc.textLayers||[]);
}
function gfHasPhoto(slug) {
  var inputs = gfConfig(slug).inputs || [];
  return inputs.some(function(i){ return i.type === 'photo'; });
}
function gfHasText(slug) {
  var inputs = gfConfig(slug).inputs || [];
  return inputs.some(function(i){ return i.type === 'text'; });
}
function gfHasOverlay(slug) {
  var gc = gfConfig(slug);
  if (gc.flowType === 'template') return (gc.templateFields||[]).length > 0;
  var tl = gc.textLayers || [];
  return tl.length > 0;
}
function gfStyleOptions(slug) {
  return gfConfig(slug).styleOptions || [];
}

// ── Init ────────────────────────────────────────────────────────────────────

function gfInit(slug) {
  if (!_giftFlow[slug]) {
    _giftFlow[slug] = {
      phase: 'start',
      originalDataUrl: null, processedDataUrl: null,
      selectedStyle: 0,
      annotLines: [], drawMode: false, modifyPrompt: '',
      ovTexts: {}, ovPositions: {},
      sides: {},        // {sideIdx: {canvasDataUrl, texts}}
      currentSideIdx: 0
    };
  }
  // Determine starting phase from flowType
  var st = _giftFlow[slug];
  var _gcFT = gfConfig(slug).flowType;
  if (st.phase === 'start') {
    if (_gcFT === 'template' || _gcFT === 'overlay' || (!_gcFT && !gfHasPhoto(slug) && gfHasOverlay(slug))) {
      st.phase = 'overlay';
      // Init overlay positions from config defaults
      var layers = gfTemplateLayers(slug);  // handles both overlay and template modes
      layers.forEach(function(l, li) {
        if (!st.ovPositions[li]) st.ovPositions[li] = { xPct: l.x != null ? l.x : 50, yPct: l.y != null ? l.y : 50 };
      });
    } else {
      st.phase = 'upload'; // fallback
    }
  }
  gfRender(slug);
}

// ── Render dispatcher ────────────────────────────────────────────────────────

function gfRender(slug) {
  var wrap = document.getElementById('gf-wrap-' + slug);
  if (!wrap) return;
  var st = _giftFlow[slug];
  if (!st) return;
  switch (st.phase) {
    case 'upload':     wrap.innerHTML = gfHtmlUpload(slug);     break;
    case 'style':      wrap.innerHTML = gfHtmlStyle(slug);      break;
    case 'processing': wrap.innerHTML = gfHtmlProcessing();     break;
    case 'preview':    wrap.innerHTML = gfHtmlPreview(slug);    setTimeout(function(){ gfWireCanvas(slug); }, 0); break;
    case 'overlay':    wrap.innerHTML = gfHtmlOverlay(slug);    setTimeout(function(){ gfOvInit(slug); }, 0);   break;
    case 'accepted':   wrap.innerHTML = gfHtmlAccepted(slug);   break;
    default:           wrap.innerHTML = gfHtmlUpload(slug);
  }
}

// ── Phase: upload ────────────────────────────────────────────────────────────

function gfHtmlUpload(slug) {
  // Also render any text inputs from inputs config
  var inputs = gfConfig(slug).inputs || [];
  var textFields = inputs.filter(function(i){ return i.type === 'text'; }).map(function(inp, fi) {
    return '<div style="margin-top:12px">' +
      '<label style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#555;display:block;margin-bottom:5px">' +
        inp.label + (inp.required ? ' <span style="font-size:10px;background:#E91E8C;color:#fff;padding:1px 7px;border-radius:20px">Required</span>' : '') +
      '</label>' +
      '<input class="gf-ov-input" id="gf-txt-' + slug + '-' + fi + '" ' +
        'placeholder="' + (inp.placeholder || '') + '" maxlength="' + (inp.maxLength || 80) + '">' +
    '</div>';
  }).join('');

  return '<div class="gf-upload-zone" id="gf-zone-' + slug + '" ' +
    'onclick="document.getElementById(\'gf-inp-' + slug + '\').click()" ' +
    'ondragover="event.preventDefault();this.classList.add(\'drag\')" ' +
    'ondragleave="this.classList.remove(\'drag\')" ' +
    'ondrop="gfDrop(event,\'' + slug + '\')">' +
    '<div class="gf-upload-icon">&#128247;</div>' +
    '<div class="gf-upload-title">Upload your photo</div>' +
    '<div class="gf-upload-sub">JPG, PNG, HEIC &bull; Max 20MB</div>' +
  '</div>' +
  '<input type="file" id="gf-inp-' + slug + '" accept="image/*" style="display:none" ' +
    'onchange="gfHandleFile(this,\'' + slug + '\')">' +
  textFields;
}

function gfHandleFile(input, slug) {
  var file = input.files[0];
  if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    var st = _giftFlow[slug] || (_giftFlow[slug] = { phase:'start', originalDataUrl:null, processedDataUrl:null, selectedStyle:0, annotLines:[], drawMode:false, modifyPrompt:'', ovTexts:{}, ovPositions:{} });
    st.originalDataUrl = e.target.result;
    st.processedDataUrl = null;
    st.annotLines = [];
    st.drawMode = false;
    st.modifyPrompt = '';
    // Save any text inputs typed before upload
    var inputs = gfConfig(slug).inputs || [];
    inputs.forEach(function(inp, fi) {
      if (inp.type === 'text') {
        var el = document.getElementById('gf-txt-' + slug + '-' + fi);
        if (el) st.ovTexts[fi] = el.value;
      }
    });
    // Next phase: style picker (if options exist) or transform directly
    if (gfStyleOptions(slug).length > 1) {
      st.phase = 'style';
    } else {
      gfTransform(slug);
      return;
    }
    gfRender(slug);
  };
  reader.readAsDataURL(file);
}

function gfDrop(event, slug) {
  event.preventDefault();
  var zone = document.getElementById('gf-zone-' + slug);
  if (zone) zone.classList.remove('drag');
  var dt = event.dataTransfer;
  if (dt && dt.files && dt.files[0]) {
    gfHandleFile({ files: dt.files }, slug);
  }
}

// ── Phase: style picker ──────────────────────────────────────────────────────

function gfHtmlStyle(slug) {
  var st = _giftFlow[slug];
  var options = gfStyleOptions(slug);
  var thumb = st.originalDataUrl
    ? '<div style="margin-bottom:14px;text-align:center"><img src="' + st.originalDataUrl + '" style="max-height:120px;max-width:100%;object-fit:contain;border-radius:2px;border:1px solid #e0e0e0"></div>'
    : '';
  var btns = options.map(function(opt, oi) {
    var active = st.selectedStyle === oi;
    return '<div onclick="gfSelectStyle(\'' + slug + '\',' + oi + ')" ' +
      'style="border:2px solid ' + (active ? '#E91E8C' : '#e0e0e0') + ';background:' + (active ? '#fff0f7' : '#fafafa') + ';' +
      'padding:14px 16px;cursor:pointer;border-radius:2px;transition:all .15s;margin-bottom:8px">' +
      '<div style="font-size:14px;font-weight:700;color:' + (active ? '#E91E8C' : '#0a0a0a') + '">' +
        (active ? '&#10003; ' : '') + opt.label +
      '</div>' +
      (opt.description ? '<div style="font-size:12px;color:#888;margin-top:3px">' + opt.description + '</div>' : '') +
    '</div>';
  }).join('');
  return thumb +
    '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#555;margin-bottom:10px">Choose a style</div>' +
    btns +
    '<div class="gf-action-row" style="margin-top:14px">' +
      '<button class="gf-retry-btn" onclick="gfReset(\'' + slug + '\')">&#8592; Change photo</button>' +
      '<button class="gf-accept-btn" onclick="gfTransform(\'' + slug + '\')">&#10003; Transform</button>' +
    '</div>';
}

function gfSelectStyle(slug, oi) {
  var st = _giftFlow[slug];
  if (st) st.selectedStyle = oi;
  gfRender(slug);
}

// ── Phase: processing ────────────────────────────────────────────────────────

function gfHtmlProcessing() {
  return '<div class="gf-processing">' +
    '<div class="gf-spinner"></div>' +
    '<div class="gf-processing-title">Transforming your photo&#8230;</div>' +
    '<div class="gf-processing-sub">Usually 10–20 seconds</div>' +
  '</div>';
}

// ── AI Transform ─────────────────────────────────────────────────────────────

function gfTransform(slug) {
  var st = _giftFlow[slug];
  if (!st || !st.originalDataUrl) return;
  st.phase = 'processing';
  gfRender(slug);

  var gc      = gfConfig(slug);
  var options = gc.styleOptions || [];
  var chosen  = options[st.selectedStyle] || options[0] || {};
  var _methodData = DB.getMethods().filter(function(m){return m.name===gc.method;})[0] || {};
  var baseP = gc.basePrompt || _methodData.basePrompt || 'Transform this photo into a beautiful personalised gift image suitable for printing. Keep the subject clearly recognisable.';
  var styleP  = chosen.prompt || '';
  var modify  = (st.modifyPrompt || '').trim();
  var annotNote = st.annotLines.length
    ? ' The customer marked ' + st.annotLines.length + ' area(s) they want changed.'
    : '';
  // Compose: base prompt + style instruction + customer modification
  var fullPrompt = baseP
    + (styleP ? ' Style: ' + styleP : '')
    + (modify  ? ' Also: ' + modify  : '')
    + annotNote;

  // ── TODO_AI ───────────────────────────────────────────────────────────────
  // Wire your image generation API here.
  // Inputs:
  //   st.originalDataUrl — base64 photo from customer
  //   fullPrompt         — combined prompt string
  //   gc.method          — production method (e.g. 'UV Print', 'Sublimation')
  //
  // On success:
  //   st.processedDataUrl = resultDataUrl; (base64 JPEG)
  //   st.phase = gfHasOverlay(slug) ? 'overlay' : 'preview';
  //   gfRender(slug);
  //
  // On error: gfShowError(slug, 'message');
  //
  // STUB (pass-through until AI is wired):
  console.log('[GF] TODO_AI | method:', gc.method, '| prompt:', fullPrompt);
  setTimeout(function() {
    st.processedDataUrl = st.originalDataUrl;
    st.phase = gfHasOverlay(slug) ? 'overlay' : 'preview';
    if (st.phase === 'overlay') {
      var layers = gc.textLayers || [];
      layers.forEach(function(l, li) {
        if (!st.ovPositions[li]) st.ovPositions[li] = { xPct: l.x != null ? l.x : 50, yPct: l.y != null ? l.y : 50 };
      });
    }
    gfRender(slug);
  }, 1200);
  // ── END STUB ──────────────────────────────────────────────────────────────
}

// ── Phase: preview (annotation + re-prompt) ──────────────────────────────────

function gfHtmlPreview(slug) {
  var st      = _giftFlow[slug];
  var imgSrc  = st.processedDataUrl || st.originalDataUrl;
  var options = gfStyleOptions(slug);
  var chosenLabel = options.length ? ' · Style: ' + (options[st.selectedStyle] || options[0] || {}).label : '';

  return '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#555;margin-bottom:8px">' +
      'Preview' + chosenLabel +
    '</div>' +
    '<div class="gf-annot-toolbar">' +
      '<button class="gf-tool-btn' + (st.drawMode ? ' on' : '') + '" onclick="gfToggleDraw(\'' + slug + '\')" title="Mark areas to change">' +
        '&#9998; Mark area' +
      '</button>' +
      '<button class="gf-tool-btn gf-tool-clear" onclick="gfClearAnnot(\'' + slug + '\')">' +
        '&#215; Clear marks' +
      '</button>' +
      (st.annotLines.length ? '<span style="font-size:11px;color:#E91E8C;align-self:center">' + st.annotLines.length + ' mark' + (st.annotLines.length !== 1 ? 's' : '') + '</span>' : '') +
    '</div>' +
    '<div class="gf-preview-wrap" id="gf-prevwrap-' + slug + '">' +
      '<img class="gf-preview-img" id="gf-previmg-' + slug + '" src="' + imgSrc + '" alt="Preview">' +
      '<canvas class="gf-annot-canvas' + (st.drawMode ? ' active' : '') + '" id="gf-canvas-' + slug + '"></canvas>' +
    '</div>' +
    // ── Accept row (primary CTA — shown first) ──────────────────────────
    '<div style="margin-bottom:16px">' +
      '<button class="gf-accept-btn" style="width:100%" onclick="gfAccept(\'' + slug + '\')">&#10003; Use this image</button>' +
    '</div>' +

    // ── Modify section (secondary — collapsed feel) ──────────────────────
    '<details class="gf-modify-details" style="border:1px solid #e0e0e0;border-radius:4px;overflow:hidden">' +
      '<summary style="padding:12px 14px;font-size:13px;font-weight:700;cursor:pointer;list-style:none;display:flex;justify-content:space-between;align-items:center;background:#fafafa">' +
        '&#9998; Want to change something?' +
        '<span style="font-size:11px;font-weight:400;color:#aaa">tap to expand</span>' +
      '</summary>' +
      '<div style="padding:12px 14px;border-top:1px solid #e0e0e0">' +
        '<div style="font-size:11px;color:#aaa;margin-bottom:8px;line-height:1.5">Pick a suggestion or type your own, then tap <strong>Re-transform</strong>.</div>' +
        '<div class="gf-chips">' +
          GF_MODIFY_CHIPS.map(function(c) {
            return '<span class="gf-chip" onclick="gfChipClick(\'' + slug + '\',this,\'' + c.replace(/'/g, "\\'") + '\')">' + c + '</span>';
          }).join('') +
        '</div>' +
        '<textarea class="gf-prompt-ta" id="gf-prompt-' + slug + '" placeholder="Or describe what to change e.g. make the background darker, add a gold frame&#8230;" rows="3">' +
          (st.modifyPrompt || '') +
        '</textarea>' +
        '<div style="display:flex;gap:8px;margin-top:10px;flex-wrap:wrap">' +
          (options.length > 1 ? '<button class="gf-retry-btn" style="flex:0" onclick="gfBackToStyle(\'' + slug + '\')">&#8592; Styles</button>' : '') +
          '<button class="gf-accept-btn" style="flex:1" onclick="gfRetry(\'' + slug + '\')">&#8635; Re-transform</button>' +
        '</div>' +
        '<div style="margin-top:10px;text-align:center">' +
          '<button onclick="gfReset(\'' + slug + '\')" style="background:none;border:none;font-size:12px;color:#aaa;cursor:pointer;font-family:var(--sans);text-decoration:underline">&#128247; Upload a different photo</button>' +
        '</div>' +
      '</div>' +
    '</details>' +
    '<p class="gf-passthru-note" style="margin-top:10px">&#128274; Your photo is never shared publicly.</p>';
}

// Annotation canvas (freehand draw over preview image)
function gfWireCanvas(slug) {
  var canvas = document.getElementById('gf-canvas-' + slug);
  var img    = document.getElementById('gf-previmg-' + slug);
  if (!canvas || !img) return;
  var st = _giftFlow[slug];

  function resize() {
    canvas.width  = img.offsetWidth  || 300;
    canvas.height = img.offsetHeight || 300;
    gfRedrawAnnot(slug);
  }
  img.onload = resize;
  if (img.complete) resize();
  setTimeout(resize, 100);

  var drawing = false, currentStroke = [];
  function pos(e) {
    var r = canvas.getBoundingClientRect(), src = e.touches ? e.touches[0] : e;
    return { x: src.clientX - r.left, y: src.clientY - r.top };
  }
  function start(e) { if (!st.drawMode) return; e.preventDefault(); drawing = true; currentStroke = [pos(e)]; }
  function move(e)  { if (!drawing || !st.drawMode) return; e.preventDefault(); currentStroke.push(pos(e)); gfRedrawAnnot(slug, currentStroke); }
  function end()    { if (!drawing) return; drawing = false; if (currentStroke.length > 1) { st.annotLines.push(currentStroke.slice()); gfRender(slug); } currentStroke = []; }

  canvas.addEventListener('mousedown',  start);
  canvas.addEventListener('mousemove',  move);
  canvas.addEventListener('mouseup',    end);
  canvas.addEventListener('mouseleave', end);
  canvas.addEventListener('touchstart', start, { passive:false });
  canvas.addEventListener('touchmove',  move,  { passive:false });
  canvas.addEventListener('touchend',   end);
}

function gfRedrawAnnot(slug, liveStroke) {
  var canvas = document.getElementById('gf-canvas-' + slug);
  if (!canvas) return;
  var ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.strokeStyle = '#E91E8C'; ctx.lineWidth = 3; ctx.lineCap = 'round'; ctx.lineJoin = 'round'; ctx.globalAlpha = 0.85;
  var st = _giftFlow[slug];
  var strokes = (st.annotLines || []).concat(liveStroke ? [liveStroke] : []);
  strokes.forEach(function(s) {
    if (!s || s.length < 2) return;
    ctx.beginPath(); ctx.moveTo(s[0].x, s[0].y);
    s.slice(1).forEach(function(p) { ctx.lineTo(p.x, p.y); });
    ctx.stroke();
  });
}

function gfToggleDraw(slug) {
  var st = _giftFlow[slug]; if (!st) return;
  st.drawMode = !st.drawMode;
  var canvas = document.getElementById('gf-canvas-' + slug);
  if (canvas) canvas.classList.toggle('active', st.drawMode);
  var btn = document.querySelector('#gf-wrap-' + slug + ' .gf-tool-btn');
  if (btn) btn.classList.toggle('on', st.drawMode);
}

function gfClearAnnot(slug) {
  var st = _giftFlow[slug]; if (!st) return;
  st.annotLines = [];
  gfRedrawAnnot(slug);
  var badge = document.querySelector('#gf-wrap-' + slug + ' .gf-annot-toolbar span');
  if (badge) badge.textContent = '';
}

function gfChipClick(slug, el, text) {
  el.classList.toggle('on');
  var ta = document.getElementById('gf-prompt-' + slug);
  if (!ta) return;
  var cur = ta.value.trim();
  ta.value = el.classList.contains('on')
    ? (cur ? cur + '. ' + text : text)
    : cur.replace('. ' + text, '').replace(text, '').trim().replace(/^\.\s*/, '');
  _giftFlow[slug].modifyPrompt = ta.value;
  // Auto-open the modify panel when a chip is selected
  var details = ta.closest('details');
  if (details && el.classList.contains('on')) details.open = true;
}

function gfRetry(slug) {
  var ta = document.getElementById('gf-prompt-' + slug);
  var st = _giftFlow[slug]; if (!st) return;
  if (ta) st.modifyPrompt = ta.value.trim();
  gfTransform(slug);
}

function gfBackToStyle(slug) {
  var st = _giftFlow[slug]; if (!st) return;
  st.phase = 'style';
  gfRender(slug);
}

function gfAccept(slug) {
  var st = _giftFlow[slug]; if (!st) return;
  var ta = document.getElementById('gf-prompt-' + slug);
  if (ta) st.modifyPrompt = ta.value.trim();
  var linkEl = document.getElementById('gf-link-' + slug);
  if (linkEl && linkEl.value.trim()) st.customerLink = linkEl.value.trim();
  st.phase = 'accepted';
  gfRender(slug);
}

// ── Phase: overlay (text on product image) ────────────────────────────────────

function gfHtmlOverlay(slug) {
  var gc     = gfConfig(slug);
  var layers = gfTemplateLayers(slug);   // handles overlay + template + multi-side
  var st     = _giftFlow[slug] || {};
  var hasMovable = layers.some(function(l){ return l.canMove; });
  // Also include text-type inputs from inputs config
  var inputs = (gc.inputs || []).filter(function(i){ return i.type === 'text'; });

  var inputsHtml = inputs.map(function(inp, fi) {
    var val = (st.ovTexts && st.ovTexts['t' + fi]) || '';
    return '<div class="gf-ov-field-row">' +
      '<label class="gf-ov-label">' + inp.label +
        (inp.required ? ' <span style="font-size:10px;background:#E91E8C;color:#fff;padding:1px 7px;border-radius:20px">Required</span>' : '') +
      '</label>' +
      '<input class="gf-ov-input" id="gf-ov-tinp-' + slug + '-' + fi + '" ' +
        'placeholder="' + (inp.placeholder || '') + '" ' +
        'value="' + val.replace(/"/g, '&quot;') + '" ' +
        'maxlength="' + (inp.maxLength || 80) + '" ' +
        'oninput="gfOvUpdate(\'' + slug + '\')">' +
    '</div>';
  }).join('');

  var layerFields = layers.map(function(layer, li) {
    var val = (st.ovTexts && st.ovTexts[li] != null ? st.ovTexts[li] : '');
    // Build font picker if template has custom/multiple fonts
    var gc_lf = gfConfig(slug);
    var allowedIds = gc_lf.printConfig && gc_lf.printConfig.allowedFonts && gc_lf.printConfig.allowedFonts.length
      ? gc_lf.printConfig.allowedFonts : null;
    var fontOpts = typeof admGetFontOptions === 'function' ? admGetFontOptions(allowedIds) : [];
    var hasFontChoice = fontOpts.length > 1;
    var fontPickerHtml = hasFontChoice
      ? '<select class="gf-font-sel" id="gf-font-' + slug + '-' + li + '" ' +
          'onchange="gfOvUpdateFont(\'' + slug + '\',' + li + ',this.value)" ' +
          'style="width:100%;border:1.5px solid #e0e0e0;padding:7px 10px;font-size:12px;border-radius:6px;font-family:var(--sans);margin-bottom:6px;background:#fff">' +
          fontOpts.map(function(o){ return '<option value="'+o.value+'"'+(layer.font===o.value?' selected':'')+'>'+o.label+'</option>'; }).join('') +
        '</select>'
      : '';
    return '<div class="gf-ov-field-row">' +
      '<label class="gf-ov-label">' + (layer.label || 'Text') +
        (layer.required ? ' <span style="font-size:10px;background:#E91E8C;color:#fff;padding:1px 7px;border-radius:20px">Required</span>' : '') +
      '</label>' +
      fontPickerHtml +
      '<input class="gf-ov-input" id="gf-ov-inp-' + slug + '-' + li + '" ' +
        'placeholder="' + (layer.placeholder || 'Your text') + '" ' +
        'value="' + val.replace(/"/g, '&quot;') + '" ' +
        'maxlength="' + (layer.maxLength || 60) + '" ' +
        'oninput="gfOvUpdate(\'' + slug + '\')">' +
    '</div>';
  }).join('');

  // If we got here from a photo transform, show original photo option to go back
  var backBtn = st.processedDataUrl
    ? '<button class="gf-retry-btn" onclick="gfBackToPreview(\'' + slug + '\')">&#8592; Edit photo</button>'
    : '';

  // Side progress for multi-side templates
  var allSidesHtml = '';
  var gc4 = gfConfig(slug);
  if (gc4.sides && gc4.sides.length > 1) {
    var si4 = ((_giftFlow[slug]||{}).currentSideIdx)||0;
    allSidesHtml = '<div style="display:flex;gap:5px;margin-bottom:10px;flex-wrap:wrap">' +
      gc4.sides.map(function(side, idx) {
        var isDone = !!((_giftFlow[slug]||{}).sides && (_giftFlow[slug]||{}).sides[idx]);
        var isCur  = idx === si4;
        return '<div style="display:flex;align-items:center;gap:4px;padding:4px 10px;border-radius:10px;font-size:11px;font-weight:700;'+
          'background:'+(isCur?'#E91E8C':isDone?'#d1fae5':'#f5f5f5')+';'+
          'color:'+(isCur?'#fff':isDone?'#059669':'#aaa')+'">' +
          (isDone && !isCur ? '&#10003; ' : '') + side.name +
        '</div>';
      }).join('') +
    '</div>';
  }

  return allSidesHtml +
    (hasMovable ? '<div class="gf-ov-drag-tip">&#9998; Drag the text on the preview to reposition</div>' : '') +
    '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#555;margin-bottom:8px">Live Preview</div>' +
    '<div class="gf-ov-wrap">' +
      '<canvas class="gf-ov-canvas' + (hasMovable ? ' movable' : '') + '" id="gf-ov-canvas-' + slug + '"></canvas>' +
    '</div>' +
    '<div class="gf-ov-fields">' + inputsHtml + layerFields + '</div>' +
    '<div class="gf-action-row">' +
      backBtn +
      '<button class="gf-accept-btn" style="flex:3" onclick="gfOvAccept(\'' + slug + '\')">&#10003; Looks good &mdash; use this</button>' +
    '</div>' +
    '<p class="gf-passthru-note">&#9998; Text will be ' + (gc.method || 'engraved/printed') + ' exactly as shown.</p>';
}

function gfBackToPreview(slug) {
  var st = _giftFlow[slug]; if (!st) return;
  st.phase = 'preview';
  gfRender(slug);
}

function gfOvInit(slug) {
  var gc  = gfConfig(slug);
  var st  = _giftFlow[slug]; if (!st) return;
  var layers = gc.textLayers || [];
  layers.forEach(function(l, li) {
    if (!st.ovPositions[li]) st.ovPositions[li] = { xPct: l.x != null ? l.x : 50, yPct: l.y != null ? l.y : 50 };
  });
  var canvas = document.getElementById('gf-ov-canvas-' + slug);
  if (!canvas) return;
  var baseImg = new Image();
  baseImg.crossOrigin = 'anonymous';
  baseImg.onload = function() {
    st._ovBaseImg = baseImg;
    // Customer preview canvas: 72dpi-equivalent — fast, low memory, enough for screen display
    // Print-ready image for PDF is rendered separately at 300dpi when staff downloads
    var nw = baseImg.naturalWidth  || 1200;
    var nh = baseImg.naturalHeight || 1200;
    // 72dpi preview: cap at ~900px wide (plenty for screen display)
    var previewMaxPx = 900;
    var _previewScale = Math.min(1, previewMaxPx / nw);
    var pw = Math.round(nw * _previewScale);
    var ph = Math.round(nh * _previewScale);
    canvas.width  = pw;
    canvas.height = ph;
    canvas.style.width  = '100%';
    canvas.style.height = 'auto';
    // Store full-res base image reference for later 300dpi PDF export
    st._ovBaseImgNative = baseImg;
    st._ovNativeW = nw;
    st._ovNativeH = nh;
    gfOvDraw(slug); gfOvWireDrag(slug);
  };
  baseImg.onerror = function() {
    canvas.width = 1200; canvas.height = 1200;
    canvas.style.width = '100%'; canvas.style.height = 'auto';
    st._ovBaseImg = null; gfOvDraw(slug);
  };
  // Use: AI-processed photo > configured mockup image for current side > product listing image
  var ex = PP_EXTRA[slug] || {};
  var gc2 = ex.giftConfig || {};
  var sideIdx2 = st.currentSideIdx || 0;
  var allSides2 = gc2.sides || [{ mockupImage: gc2.mockupImage||'' }];
  var sideMockup = (allSides2[sideIdx2] && allSides2[sideIdx2].mockupImage) || gc2.mockupImage || '';
  baseImg.src = st.processedDataUrl || sideMockup || ex.image || '';
  if (!baseImg.src) baseImg.onerror();
}

function gfOvDraw(slug) {
  var gc     = gfConfig(slug);
  var st     = _giftFlow[slug]; if (!st) return;
  var canvas = document.getElementById('gf-ov-canvas-' + slug); if (!canvas) return;
  var ctx    = canvas.getContext('2d');
  var W = canvas.width, H = canvas.height;
  var layers = gfTemplateLayers(slug);   // handles overlay + template + multi-side
  ctx.clearRect(0, 0, W, H);
  if (st._ovBaseImg) {
    ctx.drawImage(st._ovBaseImg, 0, 0, W, H);
  } else {
    ctx.fillStyle = '#1a1a1a'; ctx.fillRect(0, 0, W, H);
    ctx.fillStyle = '#555'; ctx.font = '13px sans-serif'; ctx.textAlign = 'center';
    ctx.fillText('Product image not set — upload one in admin', W / 2, H / 2);
  }
  layers.forEach(function(layer, li) {
    var text = (st.ovTexts && st.ovTexts[li]) || '';
    if (!text) return;
    var pos   = (st.ovPositions && st.ovPositions[li]) || { xPct:50, yPct:50 };
    var x     = W * (pos.xPct / 100);
    var y     = H * (pos.yPct / 100);
    // fontSize is set at '800px canvas' reference. Scale to native buffer width.
    var fSize = Math.max(10, Math.round((layer.fontSize || 20) * (W / 800)));
    // Use customer-selected font if set, else layer default
    var chosenFont = (st.ovFonts && st.ovFonts[li]) ? st.ovFonts[li] : (layer.font || layer.fontStyle || 'Georgia, serif');
    var fWeight = layer.bold ? 'bold' : '';
    var fItalic = layer.italic ? 'italic' : '';
    var fPrefix = [fItalic, fWeight].filter(Boolean).join(' ') || 'normal';
    ctx.save();
    ctx.font         = fPrefix + ' ' + fSize + 'px ' + chosenFont;
    ctx.fillStyle    = layer.color || '#ffffff';
    ctx.textAlign    = layer.align || 'center';
    ctx.textBaseline = 'middle';
    ctx.shadowColor  = 'rgba(0,0,0,0.6)'; ctx.shadowBlur = 6; ctx.shadowOffsetX = 1; ctx.shadowOffsetY = 1;
    ctx.fillText(text, x, y);
    if (layer.canMove) {
      ctx.shadowBlur = 0; ctx.beginPath(); ctx.arc(x, y, 5, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(233,30,140,0.7)'; ctx.fill();
    }
    ctx.restore();
  });
}


function gfOvUpdateFont(slug, li, fontValue) {
  var gc = gfConfig(slug);
  var layers = gfTemplateLayers(slug);
  if (layers[li]) layers[li].font = fontValue;
  // Also store in flow state so it persists
  var st = _giftFlow[slug];
  if (st) {
    if (!st.ovFonts) st.ovFonts = {};
    st.ovFonts[li] = fontValue;
  }
  gfOvDraw(slug);
}

function gfOvUpdate(slug) {
  var gc     = gfConfig(slug);
  var st     = _giftFlow[slug]; if (!st) return;
  var layers = gfTemplateLayers(slug);
  layers.forEach(function(layer, li) {
    var inp = document.getElementById('gf-ov-inp-' + slug + '-' + li);
    if (inp) st.ovTexts[li] = inp.value;
  });
  // Also capture text-type inputs
  var inputs = (gc.inputs || []).filter(function(i){ return i.type === 'text'; });
  inputs.forEach(function(inp, fi) {
    var el = document.getElementById('gf-ov-tinp-' + slug + '-' + fi);
    if (el) st.ovTexts['t' + fi] = el.value;
  });
  gfOvDraw(slug);
}

function gfOvWireDrag(slug) {
  var layers = gfTemplateLayers(slug);
  var canvas = document.getElementById('gf-ov-canvas-' + slug); if (!canvas) return;
  var st     = _giftFlow[slug];
  var movable = layers.map(function(l, i){ return l.canMove ? i : -1; }).filter(function(i){ return i >= 0; });
  if (!movable.length) return;
  var dragging = null;
  function hit(cx, cy) {
    var best = null, bd = 40;
    movable.forEach(function(li) {
      var p = st.ovPositions[li] || { xPct:50, yPct:50 };
      var d = Math.sqrt(Math.pow(cx - canvas.width*(p.xPct/100), 2) + Math.pow(cy - canvas.height*(p.yPct/100), 2));
      if (d < bd) { bd = d; best = li; }
    });
    return best;
  }
  function cp(e) {
    var r = canvas.getBoundingClientRect(), src = e.touches ? e.touches[0] : e;
    return { x:(src.clientX-r.left)*(canvas.width/r.width), y:(src.clientY-r.top)*(canvas.height/r.height) };
  }
  function onS(e){ var p=cp(e); dragging=hit(p.x,p.y); if(dragging!==null) e.preventDefault(); }
  function onM(e){ if(dragging===null) return; e.preventDefault(); var p=cp(e); st.ovPositions[dragging]={xPct:Math.max(5,Math.min(95,(p.x/canvas.width)*100)),yPct:Math.max(5,Math.min(95,(p.y/canvas.height)*100))}; gfOvDraw(slug); }
  function onE(){ dragging=null; }
  canvas.addEventListener('mousedown',onS); canvas.addEventListener('mousemove',onM); canvas.addEventListener('mouseup',onE); canvas.addEventListener('mouseleave',onE);
  canvas.addEventListener('touchstart',onS,{passive:false}); canvas.addEventListener('touchmove',onM,{passive:false}); canvas.addEventListener('touchend',onE);
}

function gfOvAccept(slug) {
  var gc     = gfConfig(slug);
  var st     = _giftFlow[slug]; if (!st) return;
  var layers = gc.textLayers || [];
  // Validate required overlay layers
  for (var li = 0; li < layers.length; li++) {
    if (layers[li].required && !((st.ovTexts && st.ovTexts[li]) || '').trim()) {
      var inp = document.getElementById('gf-ov-inp-' + slug + '-' + li);
      if (inp) { inp.style.borderColor = '#E91E8C'; inp.focus(); }
      showToast('&#9888; Please fill in "' + (layers[li].label || 'text') + '"');
      return;
    }
  }
  // Validate required text inputs
  var inputs = (gc.inputs || []).filter(function(i){ return i.type === 'text'; });
  for (var fi = 0; fi < inputs.length; fi++) {
    if (inputs[fi].required && !((st.ovTexts && st.ovTexts['t' + fi]) || '').trim()) {
      var el = document.getElementById('gf-ov-tinp-' + slug + '-' + fi);
      if (el) { el.style.borderColor = '#E91E8C'; el.focus(); }
      showToast('&#9888; Please fill in "' + inputs[fi].label + '"');
      return;
    }
  }
  // Sync DOM input values into state before saving
  var canvas = document.getElementById('gf-ov-canvas-' + slug);
  // Read layer inputs from DOM
  layers.forEach(function(l, li) {
    var el = document.getElementById('gf-ov-inp-' + slug + '-' + li);
    if (el) { if (!st.ovTexts) st.ovTexts = {}; st.ovTexts[li] = el.value; }
  });

  // Store preview (72dpi) from screen canvas
  if (canvas) st.processedDataUrl = canvas.toDataURL('image/jpeg', 0.85);

  // Generate 300dpi print-ready image for PDF export
  // 300dpi: pixel width = (physical mm / 25.4) * 300
  var _printCanvas = document.createElement('canvas');
  var _gcPrint = gfConfig(slug);
  var _pcPrint = ((PP_EXTRA[slug]||{}).giftConfig||{}).printConfig || {};
  var _toMmP = _pcPrint.unit==='in'?25.4:_pcPrint.unit==='px'?0.264583:1;
  var _physWmm = (_pcPrint.w||0)*_toMmP + (_pcPrint.bleed||0)*2;
  var _physHmm = (_pcPrint.h||0)*_toMmP + (_pcPrint.bleed||0)*2;
  var _printW, _printH;
  if (_physWmm > 0 && _physHmm > 0) {
    // True 300dpi based on physical dimensions
    _printW = Math.round((_physWmm / 25.4) * 300);
    _printH = Math.round((_physHmm / 25.4) * 300);
  } else if (st._ovNativeW) {
    // Fall back to native image resolution
    _printW = st._ovNativeW;
    _printH = st._ovNativeH;
  } else {
    _printW = canvas ? canvas.width * 4 : 2400;
    _printH = canvas ? canvas.height * 4 : 2400;
  }
  // Cap at 6000px to avoid memory issues
  var _printCap = 6000;
  if (_printW > _printCap) { _printH = Math.round(_printH * _printCap/_printW); _printW = _printCap; }
  _printCanvas.width  = _printW;
  _printCanvas.height = _printH;
  var _printCtx = _printCanvas.getContext('2d');
  // Draw base image
  var _baseForPrint = st._ovBaseImgNative || st._ovBaseImg;
  if (_baseForPrint) {
    _printCtx.drawImage(_baseForPrint, 0, 0, _printW, _printH);
  }
  // Draw text layers at print resolution
  var _printLayers = gfTemplateLayers(slug);
  _printLayers.forEach(function(layer, li) {
    var text = (st.ovTexts && st.ovTexts[li]) || '';
    if (!text) return;
    var pos   = (st.ovPositions && st.ovPositions[li]) || { xPct: layer.x||50, yPct: layer.y||50 };
    var x     = _printW * (pos.xPct / 100);
    var y     = _printH * (pos.yPct / 100);
    var fSize = Math.max(10, Math.round((layer.fontSize || 20) * (_printW / 800)));
    var chosenFont = (st.ovFonts && st.ovFonts[li]) ? st.ovFonts[li] : (layer.font || layer.fontStyle || 'Georgia, serif');
    var fPrefix = (layer.italic ? 'italic ' : '') + (layer.bold ? 'bold ' : '') || 'normal ';
    _printCtx.save();
    _printCtx.font         = fPrefix + fSize + 'px ' + chosenFont;
    _printCtx.fillStyle    = layer.color || '#ffffff';
    _printCtx.textAlign    = layer.align || 'center';
    _printCtx.textBaseline = 'middle';
    _printCtx.fillText(text, x, y);
    _printCtx.restore();
  });
  var _printDataUrl = _printCanvas.toDataURL('image/jpeg', 0.95);

  // Save this side's result — preview for customer display, print for PDF
  var gc = gfConfig(slug);
  var sideIdx = st.currentSideIdx || 0;
  if (!st.sides) st.sides = {};
  var sideTexts = {};
  layers.forEach(function(l,li){ sideTexts[li] = (st.ovTexts && st.ovTexts[li]) || ''; });
  st.sides[sideIdx] = { canvasDataUrl: _printDataUrl, previewDataUrl: st.processedDataUrl, texts: sideTexts, fonts: st.ovFonts||{} };

  // Check if this is a multi-side template and there are more sides to fill
  var allSides = gc.sides || [{ mockupImage: gc.mockupImage, templateFields: gc.templateFields||gc.textLayers||[] }];
  var nextSideIdx = sideIdx + 1;
  if (nextSideIdx < allSides.length && allSides[nextSideIdx].templateFields && allSides[nextSideIdx].templateFields.length) {
    // Move to next side
    st.currentSideIdx = nextSideIdx;
    st.ovTexts = {};
    st.ovPositions = {};
    st.processedDataUrl = null;
    gfRender(slug);
    showToast('&#10003; Side '+(sideIdx+1)+' saved — now fill in: ' + allSides[nextSideIdx].name);
    return;
  }

  st.phase = 'accepted';
  gfRender(slug);
}

// ── Phase: accepted ──────────────────────────────────────────────────────────

function gfHtmlAccepted(slug) {
  var st    = _giftFlow[slug] || {};
  var thumb = st.processedDataUrl || st.originalDataUrl;
  var extraHtml = '';
  if (st.customerLink) extraHtml += '<div style="font-size:12px;color:#555;margin-top:6px;word-break:break-all">&#128279; '+st.customerLink+'</div>';
  if (st.uploadedFileName) extraHtml += '<div style="font-size:12px;color:#555;margin-top:4px">&#128193; '+st.uploadedFileName+'</div>';
  return '<div class="gf-accepted">' +
    (thumb && !st.uploadedFileName ? '<img class="gf-accepted-thumb" src="' + thumb + '" alt="Your design">' : '') +
    '<div class="gf-accepted-info">' +
      '<div class="gf-accepted-title">&#10003; ' + (st.uploadedFileName ? 'File received' : st.customerLink ? 'Link saved' : 'Design saved') + '</div>' +
      '<div class="gf-accepted-sub">Will be ' + (gfConfig(slug).method || 'produced') + ' exactly as shown</div>' +
      extraHtml +
      '<button class="gf-change-btn" onclick="gfReset(\\\'' + slug + '\\\')">Start over</button>' +
    '</div>' +
  '</div>';
}

// ── Shared utilities ──────────────────────────────────────────────────────────

function gfReset(slug) {
  _giftFlow[slug] = { phase:'start', originalDataUrl:null, processedDataUrl:null,
    selectedStyle:0, annotLines:[], drawMode:false, modifyPrompt:'',
    ovTexts:{}, ovPositions:{}, ovFonts:{}, sides:{}, currentSideIdx:0 };
  gfInit(slug);
}

function gfShowError(slug, msg) {
  var wrap = document.getElementById('gf-wrap-' + slug);
  if (!wrap) return;
  wrap.innerHTML = '<div class="gf-err">&#9888; ' + msg + '</div>' + gfHtmlUpload(slug);
}

// -- Pricing table column selection (print product pages) --
function pp3SelectCol(btn, ci, slug) {
 var table = btn.closest('.pp3-price-table-wrap') || document.querySelector('.pp3-price-table-wrap');
 if (!table) return;
 // Update column buttons
 table.querySelectorAll('.pp3-cfg-btn').forEach(function(b,i){ b.classList.toggle('active', i===ci); });
 // Update price cells - show only selected column
 table.querySelectorAll('.pp3-price-cell').forEach(function(cell){ cell.classList.toggle('active', +cell.dataset.ci===ci); });
 // Update selected config on the state
 if (!window._pp3State) window._pp3State = {};
 if (!window._pp3State[slug]) window._pp3State[slug] = {};
 window._pp3State[slug].col = ci;
 pp3UpdateGiftTotal(slug);
}

// -- Pricing table row selection --
function pp3SelectRow(row, ri, slug) {
 var wrap = row.closest('.pp3-price-table-wrap') || document.querySelector('.pp3-price-table-wrap');
 if (!wrap) return;
 wrap.querySelectorAll('.pp3-pr-row').forEach(function(r){ r.classList.remove('active'); });
 row.classList.add('active');
 if (!window._pp3State) window._pp3State = {};
 if (!window._pp3State[slug]) window._pp3State[slug] = {};
 window._pp3State[slug].row = ri;
 pp3UpdateGiftTotal(slug);
}

// -- Qty adjust for gift products --
function pp3AdjustQty(slug, delta) {
 var el = document.getElementById('pp3qty-'+ slug);
 if (!el) return;
 var val = Math.max(1, parseInt(el.textContent||'1') + delta);
 el.textContent = val;
 if (!window._pp3State) window._pp3State = {};
 if (!window._pp3State[slug]) window._pp3State[slug] = {};
 window._pp3State[slug].qty = val;
 pp3UpdateGiftTotal(slug);
}

function pp3UpdateGiftTotal(slug) {
 var totalEl = document.getElementById('pp3total-'+ slug);
 if (!totalEl) return;
 var state = (window._pp3State && window._pp3State[slug]) || {};
 var qty = state.qty || 1;
 var p = PRODUCTS_DATA[slug];
 if (!p || !p.pricing || !p.pricing.rows) return;
 var ri = state.row || 0;
 var ci = state.col || 0;
 var row = p.pricing.rows[ri] || p.pricing.rows[0];
 if (!row) return;
 var price = row.prices[ci];
 if (typeof price !== 'number') return;
 totalEl.textContent = 'S$'+ (price * qty).toFixed(2);
}

function pp3UploadArtwork(input, slug) {
 var file = input.files[0];
 if (!file) return;
 var nameEl = document.getElementById('pp3file-name-'+ slug);
 if (nameEl) {
 nameEl.textContent = '&#10003; '+ file.name;
 nameEl.style.display = 'block';
 }
}



function ppFaq(el) {
 var ans = el.nextElementSibling;
 var arr = el.querySelector('.pp2-faq-arr');
 var open = ans.style.display === 'block';
 ans.style.display = open ? 'none': 'block';
 if (arr) arr.textContent = open ? '+': '-';
}


function ppHandleUpload(e, slug) {
 var file = e.target.files[0];
 if (!file) return;
 ppUploadFile = { name: file.name, size: file.size };
 document.getElementById('pp-fchip').innerHTML =
 '<div class="pp-fchip">&#128196; '+ file.name +
 '<button onclick="ppClearUpload(\''+ slug + '\')">&#215;<\/button><\/div>';
 document.getElementById('pp-uzone').style.display = 'none';
}

function ppClearUpload(slug) {
 ppUploadFile = null;
 document.getElementById('pp-file-input').value = '';
 document.getElementById('pp-fchip').innerHTML = '';
 document.getElementById('pp-uzone').style.display = 'block';
}

function ppAddToCart(slug) {
  var prod = PRODUCTS_DATA[slug];
  if (!prod) return;

  // Gift products: require accepted AI-transformed image
  var isGift = prod.type==='gift' || (GIFT_CATS && GIFT_CATS.has(prod.category)) || !!(PP_EXTRA[slug] && PP_EXTRA[slug].giftConfig && PP_EXTRA[slug].giftConfig.method);
  if (isGift) {
    var gfSt = _giftFlow[slug];
    if (!gfSt || (gfSt.phase !== 'accepted' && gfSt.phase !== 'ov-accepted')) {
      // Scroll to the gift form and show a nudge
      var wrap = document.getElementById('gf-wrap-' + slug);
      if (wrap) {
        wrap.scrollIntoView({ behavior: 'smooth', block: 'center' });
        wrap.style.outline = '2px solid #E91E8C';
        setTimeout(function(){ wrap.style.outline = ''; }, 1800);
      }
      showToast('&#128247; Please upload and approve your photo first');
      return;
    }
  }

  var pr = prod.pricing;
  var row = pr.rows[ppRowIdx] || pr.rows[0];
  var price = row.prices[ppColIdx];
  if (typeof price !== 'number') {
    alert('Please contact us for a custom quote on this option.');
    return;
  }

  // Collect text personalisation — from giftConfig.inputs or legacy GIFT_PERSONALISATION
  var persText = [];
  var _gc = PP_EXTRA[slug] && PP_EXTRA[slug].giftConfig;
  if (_gc && _gc.inputs) {
    // New giftConfig path: text values live in _giftFlow[slug].ovTexts
    var _gfSt2 = _giftFlow[slug] || {};
    (_gc.inputs || []).forEach(function(inp, fi) {
      if (inp.type === 'text') {
        var val = (_gfSt2.ovTexts && _gfSt2.ovTexts['t' + fi]) || '';
        // Also check DOM input in case it wasn't saved to state yet
        var el = document.getElementById('gf-ov-tinp-' + slug + '-' + fi);
        if (el && el.value.trim()) val = el.value.trim();
        if (val) persText.push(inp.label + ': ' + val);
      }
    });
    // Also collect text layer values (engraving text)
    (_gc.textLayers || []).forEach(function(layer, li) {
      var val = (_gfSt2.ovTexts && _gfSt2.ovTexts[li]) || '';
      var el = document.getElementById('gf-ov-inp-' + slug + '-' + li);
      if (el && el.value.trim()) val = el.value.trim();
      if (val) persText.push(layer.label + ': ' + val);
    });
  } else if (GIFT_PERSONALISATION && GIFT_PERSONALISATION[slug]) {
    // Legacy path
    GIFT_PERSONALISATION[slug].forEach(function(field, fi) {
      if (field.type !== 'image') {
        var inp = document.getElementById('pf3txt-' + slug + '-' + fi);
        if (inp && inp.value.trim()) persText.push(field.label + ': ' + inp.value.trim());
      }
    });
  }

  // Build gift file data — capture all sides if multi-side template
  var giftImageUrl = null;
  var giftSides = null;
  if (isGift && _giftFlow[slug]) {
    var gfSt3 = _giftFlow[slug];
    // Collect all completed sides
    if (gfSt3.sides && Object.keys(gfSt3.sides).length > 0) {
      var gc5 = (PP_EXTRA[slug]||{}).giftConfig || {};
      var allSides5 = gc5.sides || [{ mockupImage:'', templateFields:[] }];
      giftSides = allSides5.map(function(side, si) {
        var sideData = gfSt3.sides[si] || {};
        return {
          name:        side.name || ('Side '+(si+1)),
          image:       sideData.canvasDataUrl  || null,   // 300dpi print-ready for PDF
          previewImage:sideData.previewDataUrl || sideData.canvasDataUrl || null,  // 72dpi for display
          texts:       sideData.texts || {}
        };
      }).filter(function(s){ return s.image || Object.keys(s.texts).length; });
      // Primary preview image (72dpi) shown to customer
      giftImageUrl = giftSides[0] ? (giftSides[0].previewImage || giftSides[0].image) : null;
    } else {
      giftImageUrl = gfSt3.processedDataUrl || gfSt3.originalDataUrl;
    }
  }

  var cartItem = {
    id:        'ci_' + Date.now(),
    product:   prod.name,
    icon:      prod.icon,
    config:    pr.configs[ppColIdx],
    qty:       row.qty,
    unit:      'set',
    price:     price,
    giftImage: giftImageUrl,
    notes:     persText.join(' | ') || ''
  };
  if (giftSides && giftSides.length) cartItem.giftSides = giftSides;
  cart.push(cartItem);

  updateCartCount();
  showToast(prod.icon + ' ' + prod.name + ' added to cart');
  goSub('cart');
}

// ==============================================
// ROUTER
// ==============================================
function go(screen){
 var hideNavScreens=['order','cart','checkout','confirm','orders'];
 var showNav = hideNavScreens.indexOf(screen) === -1;
 document.getElementById('nav').style.display = showNav ? 'flex': 'none';
 document.querySelectorAll('.mega-menu').forEach(function(m){ m.classList.remove('open'); });
 // Don\'t touch mmenu display — its controlled by CSS transform via .open class

 var _ss=document.querySelectorAll('.screen');for(var _si=0;_si<_ss.length;_si++){_ss[_si].classList.remove('active');}

 if(screen==='shop'){
 document.getElementById('screen-shop').classList.add('active');
 buildShopGrid();
 } else if(screen==='membership'){
 document.getElementById('screen-membership').classList.add('active');
 } else if(screen==='bundles'){
 document.getElementById('screen-bundles').classList.add('active');
 renderBundlesScreen();
 } else if(screen==='bundle-detail'){
 document.getElementById('screen-bundle-detail').classList.add('active');
 } else if(screen==='points'){
 go('membership'); return;
 } else if(screen==='staff'){
 document.getElementById('screen-staff').classList.add('active');
 sfAuthed = true;
 document.getElementById('sf-login-view').style.display = 'none';
 document.getElementById('sf-dash-view').style.display = 'block';
 sfLoad();
 sfStartClock();
 } else if(screen==='admin'){
 document.getElementById('screen-admin').classList.add('active');
 var loginEl=document.getElementById('admin-login'); if(loginEl) loginEl.style.display='none';
 var dashEl=document.getElementById('admin-dash'); if(dashEl) dashEl.style.display='block';
 setTimeout(function(){ admBuildProdList(''); adminLoadOrders(); admLoadDashboard(); },50);
 } else if(screen==='cart'){
 document.getElementById('screen-cart').classList.add('active');
 renderCart(); updateCartCount();
 } else {
 document.getElementById('screen-'+screen).classList.add('active');
 }

 ['home','about','contact'].forEach(function(p){
 var _el=document.getElementById('nl-'+p);if(_el){_el.classList.toggle('active',p===screen);}
 });

 curScreen=screen;
 window.scrollTo({top:0,behavior:'smooth'});
}

function goSub(sub){
 curSub=sub;
 var _ss=document.querySelectorAll('.screen');for(var _si=0;_si<_ss.length;_si++){_ss[_si].classList.remove('active');}
 if(sub==='cart'){
 document.getElementById('screen-cart').classList.add('active');
 renderCart();
 } else if(sub==='checkout'){
 document.getElementById('screen-checkout').classList.add('active');
 prefillCheckout();renderCoSummary();
 } else if(sub==='orders'){
 document.getElementById('screen-orders').classList.add('active');
 renderOrders();
 } else {
 go(sub);
 return;
 }
 window.scrollTo({top:0,behavior:'smooth'});
}

