var mOpen=false;
function megaToggle(e, menuId){
 if(e){ e.preventDefault(); e.stopPropagation(); }
 var mm = document.getElementById(menuId);
 if(!mm) return;
 var isOpen = mm.classList.contains('open');
 var all = document.querySelectorAll('.mega-menu');
 for(var i=0;i<all.length;i++){ all[i].classList.remove('open'); }
 if(!isOpen){ mm.classList.add('open'); }
}
document.addEventListener('click', function(e){
 var inMenu = e.target.closest && (e.target.closest('#print-nav-btn') || e.target.closest('#gifts-nav-btn') || e.target.closest('.mega-menu'));
 if(!inMenu){
 var all = document.querySelectorAll('.mega-menu');
 for(var i=0;i<all.length;i++){ all[i].classList.remove('open'); }
 }
});
function navToggle(){
 var mm = document.getElementById('nav-mm');
 var isOpen = mm.className.indexOf('open') !== -1;
 if(isOpen){
 mm.className = '';
 } else {
 mm.className = 'open';
 }
 var h1=document.getElementById('hb1');
 var h2=document.getElementById('hb2');
 var h3=document.getElementById('hb3');
 if(!isOpen){
 if(h1){h1.style.transform='rotate(45deg) translate(5px,5px)';}
 if(h2){h2.style.opacity='0';}
 if(h3){h3.style.transform='rotate(-45deg) translate(5px,-5px)';}
 } else {
 if(h1){h1.style.transform='';}
 if(h2){h2.style.opacity='1';}
 if(h3){h3.style.transform='';}
 }
}
function navClose(){
 var mm = document.getElementById('nav-mm');
 if(mm){ mm.className = ''; }
 var h1=document.getElementById('hb1');
 var h2=document.getElementById('hb2');
 var h3=document.getElementById('hb3');
 if(h1){h1.style.transform='';}
 if(h2){h2.style.opacity='1';}
 if(h3){h3.style.transform='';}
}
function mmToggle(row){
 var items = row.querySelector('.mm-items');
 var arr = row.querySelector('.mm-arr');
 if(!items) return;
 var isOpen = items.className.indexOf('open') !== -1;
 if(isOpen){
 items.className = 'mm-items';
 if(arr) arr.textContent = '+';
 } else {
 items.className = 'mm-items open';
 if(arr) arr.textContent = '-';
 }
}
function toggleMenu(){ navToggle(); }
function closeMenu(){ navClose(); }

