function switchPTab(t){
 activePTab=t;
 document.getElementById('p-print').style.display=t==='print'?'grid':'none';
 document.getElementById('p-gifts').style.display=t==='gifts'?'block':'none';
 document.getElementById('ptab-print').classList.toggle('active',t==='print');
 document.getElementById('ptab-gifts').classList.toggle('active',t==='gifts');
}

function renderPSidebar(){
 var sb=document.getElementById('p-sidebar');
 var groups=[...new Set(PRINT.map(function(p){return p.group;}))];
 sb.innerHTML='';
 groups.forEach(function(g){
 sb.innerHTML+='<div class="p-sgrp">'+g+'<\/div>';
 PRINT.filter(function(p){return p.group===g;}).forEach(function(p){
 var d=document.createElement('div');
 d.className='p-sit'+(p.id===pActiveProd.id?'active':'');
 d.innerHTML='<span style="font-size:15px">'+p.icon+'<\/span>'+p.name;
 d.onclick=function(){pActiveProd=p;pActiveColIdx=0;pActiveRowIdx=2;renderPSidebar();renderPMain();};
 sb.appendChild(d);
 });
 });
}

function renderPMain(){
 var p=pActiveProd;
 var main=document.getElementById('p-main');
 var row=p.rows[Math.min(pActiveRowIdx,p.rows.length-1)];
 var price=row.prices[pActiveColIdx]||0;
 var qty=row.qty;
 var ppu=price/qty;
 var ppuStr=ppu<1?'$'+ppu.toFixed(3):'$'+ppu.toFixed(2);

 var noteHtml=p.note?'<div class="note-info">&#8505;&#65039; '+p.note+'<\/div>':'';
 var optHtml=p.configs.map(function(c,i){return '<option value="'+i+'"'+(i===pActiveColIdx?'selected':'')+'>'+c+'<\/option>';}).join('');
 var thHtml=p.cols.map(function(c,i){return '<th style="'+(i===pActiveColIdx?'color:var(--mag)':'')+'">'+c+'<\/th>';}).join('');
 var trHtml=p.rows.map(function(r,ri){
 var tds=r.prices.map(function(pr,ci){return '<td class="'+(ci===pActiveColIdx?'ca':'')+'">$'+pr+'<\/td>';}).join('');
 return '<tr class="'+(ri===pActiveRowIdx?'sel':'')+'" onclick="pActiveRowIdx='+ri+';renderPMain()"><td>'+(r.qty>=1000?(r.qty/1000)+'K':r.qty)+''+p.unit+'<\/td>'+tds+'<\/tr>';
 }).join('');

 main.innerHTML=
 '<h2>'+p.icon+''+p.name+'<\/h2><p class="pdesc">'+p.desc+'<\/p>'+
 noteHtml+
 '<div class="cfg-row"><div class="cg"><label>'+p.configLabel+'<\/label>'+
 '<select onchange="pActiveColIdx=this.selectedIndex;renderPMain()">'+optHtml+'<\/select><\/div>'+
 '<div class="cg"><label>Turnaround<\/label><select><option>Standard (3–5 days)<\/option><option>Express (1–2 days) +30%<\/option><\/select><\/div><\/div>'+
 '<div class="tbl-wrap"><table><thead><tr><th>Qty<\/th>'+thHtml+'<\/tr><\/thead><tbody>'+trHtml+'<\/tbody><\/table><\/div>'+
 '<div class="sum-bar"><div><div class="sb-l">Selected: '+qty+''+p.unit+'&bull; '+p.configs[pActiveColIdx]+'<\/div>'+
 '<div class="sb-p">S$'+price+'<\/div><div class="sb-u">'+ppuStr+'/pc &bull; '+qty+''+p.unit+'<\/div><\/div>'+
 '<button class="btn-ord" onclick="goSub(\'checkout\')">Order Now &#8594;<\/button><\/div>';
}

function renderPGifts(){
 var g=document.getElementById('p-gift-grid');
 g.innerHTML='';
 GIFTS.forEach(function(gf){
 var c=document.createElement('div');
 c.className='gc';
 var rows=gf.rows.map(function(r){
 return '<div class="gc-r"><span class="gc-q">'+r.qty+'pcs<\/span>'+
 '<span><span class="gc-pr">$'+r.ppu.toFixed(2)+'/pc<\/span>'+
 '<span class="gc-tt"> = $'+(r.ppu*r.qty).toFixed(2)+'<\/span><\/span><\/div>';
 }).join('');
 c.innerHTML='<div class="gc-h"><span style="font-size:20px">'+gf.icon+'<\/span>'+
 '<div><div class="gc-nm">'+gf.name+'<\/div><div class="gc-ds">'+gf.desc+'<\/div><\/div><\/div>'+
 '<div class="gc-b">'+rows+'<\/div>';
 g.appendChild(c);
 });
}

