function prefillCheckout(){document.getElementById('co-email').value=(session && session.email)||'';}
function toggleAddr(){document.getElementById('co-addr-row').style.display=document.getElementById('co-method').value.indexOf('Delivery') !== -1?'block':'none';renderCoSummary();}
function setDelivery(mode){
 var isDelivery = mode === 'delivery';
 document.getElementById('co-method').value = isDelivery ? 'Delivery (+$8 flat)' : 'Self-collect \u2013 Paya Lebar Square';
 document.getElementById('dtog-collect').classList.toggle('active', !isDelivery);
 document.getElementById('dtog-delivery').classList.toggle('active', isDelivery);
 var addrRow = document.getElementById('co-addr-row');
 if(addrRow) addrRow.style.display = isDelivery ? 'block' : 'none';
 var deliveryRow = document.getElementById('co-delivery-row');
 if(deliveryRow) deliveryRow.style.display = isDelivery ? 'flex' : 'none';
 renderCoSummary();
}
function renderCoSummary(){
  var isDelivery = document.getElementById('co-method') && document.getElementById('co-method').value.indexOf('Delivery') !== -1;
  var del = isDelivery ? 8 : 0;
  var sub = cart.reduce(function(s,i){return s+(Number(i.price)||0);},0);
  var summaryEl = document.getElementById('co-summary');
  if (!summaryEl) return;
  summaryEl.innerHTML = cart.map(function(i){
    return '<div class="co-sum-item">' +
      '<div class="co-sum-item-icon">' + (i.icon||'🖨️') + '</div>' +
      '<div class="co-sum-item-body">' +
        '<div class="co-sum-item-name">' + (i.product||'Product') + '</div>' +
        '<div class="co-sum-item-spec">Qty: ' + (i.qty||1) + (i.config && i.config !== '—' ? ' &bull; ' + i.config : '') + '</div>' +
      '</div>' +
      '<div class="co-sum-item-price">S$' + Number(i.price).toFixed(2) + '</div>' +
    '</div>';
  }).join('');
  var subEl = document.getElementById('co-subtotal-display');
  if (subEl) subEl.textContent = 'S$' + sub.toFixed(2);
  var delRow = document.getElementById('co-delivery-row');
  if (delRow) delRow.style.display = del ? 'flex' : 'none';
  var discount = ptsRedeemed / REDEEM_RATE;
  var totalEl = document.getElementById('co-total-final');
  if (totalEl) totalEl.textContent = 'S$' + Math.max(0, sub + del - discount).toFixed(2);
  ptsUpdateSummary();
}
function fmtC(el){var v=el.value.replace(/\D/g,'').slice(0,16);el.value=v.replace(/(.{4})/g,'$1 ').trim();}
function fmtE(el){var v=el.value.replace(/\D/g,'').slice(0,4);if(v.length>2)v=v.slice(0,2)+'/'+v.slice(2);el.value=v;}

function placeOrder(){
  var name = document.getElementById('co-name').value.trim();
  var email = document.getElementById('co-email').value.trim();
  var phone = document.getElementById('co-phone').value.trim();
  var company = (document.getElementById('co-company')||{value:''}).value.trim();
  var position = (document.getElementById('co-position')||{value:''}).value.trim();
  var notes = (document.getElementById('co-notes')||{value:''}).value.trim();
  if (!name) { showToast('Please enter your full name'); return; }
  if (!phone) { showToast('Please enter your mobile number'); return; }
  if (!email || email.indexOf('@') === -1) { showToast('Please enter a valid email'); return; }
  if (!cart.length) { showToast('Your cart is empty'); return; }
  var btn = document.getElementById('pay-btn');
  if (btn) { btn.textContent = 'Placing order...'; btn.disabled = true; }
  setTimeout(function(){
    var isDelivery = document.getElementById('co-method').value.indexOf('Delivery') !== -1;
    var del = isDelivery ? 8 : 0;
    var sub = cart.reduce(function(s,i){ return s + (Number(i.price)||0); }, 0);
    var ptsDiscount = ptsRedeemed / REDEEM_RATE;
    var ptsEarned = ptsRedeemed > 0 ? 0 : Math.floor(sub * EARN_RATE);
    var total = Math.max(0, sub + del - ptsDiscount);
    var order = {
      id: 'PV-' + String(Date.now()).slice(-6),
      userId: session ? session.id : 'guest',
      customer: name, email: email, phone: phone,
      company: company, position: position, notes: notes,
      method: document.getElementById('co-method').value,
      items: cart.slice(),
      subtotal: sub, delivery: del,
      ptsRedeemed: ptsRedeemed, ptsDiscount: ptsDiscount, ptsEarned: ptsEarned,
      total: total, status: 'Pending',
      createdAt: new Date().toLocaleString('en-SG')
    };
    var orders = DB.getOrders(); orders.unshift(order); DB.saveOrders(orders);
    var updatedMember = DB.upsertMember(email, name, ptsEarned - ptsRedeemed);
    // Populate confirm screen
    document.getElementById('conf-num').textContent = order.id;
    document.getElementById('conf-det').innerHTML =
      '<div style="padding:10px 20px;font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:1.5px;color:#aaa;background:#fafafa;border-bottom:1px solid #f0f0f0">Order Details<\/div>' +
      '<div class="cd-r"><span class="cd-l">Customer<\/span><span class="cd-v">' + order.customer + '<\/span><\/div>' +
      '<div class="cd-r"><span class="cd-l">Email<\/span><span class="cd-v">' + order.email + '<\/span><\/div>' +
      '<div class="cd-r"><span class="cd-l">Mobile<\/span><span class="cd-v">' + order.phone + '<\/span><\/div>' +
      (order.company ? '<div class="cd-r"><span class="cd-l">Company<\/span><span class="cd-v">' + order.company + (order.position ? ' &#183; ' + order.position : '') + '<\/span><\/div>' : '') +
      '<div class="cd-r"><span class="cd-l">Collection<\/span><span class="cd-v">' + order.method + '<\/span><\/div>' +
      (ptsRedeemed > 0 ? '<div class="cd-r"><span class="cd-l">Points Used<\/span><span class="cd-v" style="color:#E91E8C">&#8722;' + ptsRedeemed.toLocaleString() + '&#8201;pts (&#8722;S$' + ptsDiscount.toFixed(2) + ')<\/span><\/div>' : '') +
      '<div class="cd-r"><span class="cd-l">Items<\/span><span class="cd-v">' + order.items.length + ' item' + (order.items.length > 1 ? 's' : '') + '<\/span><\/div>' +
      (function(){
        var ghtml = '';
        (order.items||[]).forEach(function(it){
          var img = it.giftImage || (it.giftSides && it.giftSides[0] && (it.giftSides[0].previewImage || it.giftSides[0].image));
          if (img) ghtml += '<img src="'+img+'" style="width:52px;height:52px;object-fit:cover;border-radius:3px;border:1px solid #e0e0e0;margin:2px">';
        });
        return ghtml ? '<div class="cd-r" style="flex-wrap:wrap"><span class="cd-l">Designs<\/span><span class="cd-v">'+ghtml+'<\/span><\/div>' : '';
      })() +
      '<div class="cd-r" style="background:#f8f8f8"><span class="cd-l" style="font-weight:800;color:#0a0a0a">Total<\/span><span class="cd-v" style="color:#E91E8C;font-size:18px;font-weight:800">S$' + order.total.toFixed(2) + '<\/span><\/div>';
    var cpb = document.getElementById('conf-pts-block');
    if (ptsEarned > 0) {
      if (cpb) cpb.style.display = 'block';
      var cpe = document.getElementById('conf-pts-earned');
      var cpt = document.getElementById('conf-pts-total');
      if (cpe) cpe.textContent = '+' + ptsEarned + ' pts';
      if (cpt) cpt.textContent = (updatedMember.points || 0).toLocaleString() + ' pts';
    } else {
      if (cpb) cpb.style.display = 'none';
    }
    ptsRedeemed = 0;
    cart = []; updateCartCount();
    _giftFlow = {};
    if (btn) { btn.textContent = 'Place Order →'; btn.disabled = false; }
    // Navigate to confirm
    document.querySelectorAll('.screen').forEach(function(s){ s.classList.remove('active'); });
    document.getElementById('screen-confirm').classList.add('active');
    window.scrollTo({top:0,behavior:'smooth'});
  }, 1200);
}

