// -- SHOP OVERVIEW --
// Consolidated category mapping for shop filter
var CAT_GROUP = {
  'Advertising': 'Advertising',
  'Art & Signage': 'Advertising',
  'Business Stationery': 'Stationery',
  'Cards & Types': 'Cards',
  'Wearables': 'Wearables',
  'Embroidery': 'Wearables',
  'Packaging': 'Packaging',
  'Personalised Gifts': 'Personalised Gifts',
  'Lifestyle': 'Personalised Gifts',
'Jewellery': 'Jewellery',
  'Wedding': 'Wedding'
};

function buildShopGrid() {
 var grid = document.getElementById('shop-grid-v2');
 if (!grid) return;
 var keys = Object.keys(PRODUCTS_DATA);
 var html = '';
 for (var i = 0; i < keys.length; i++) {
 var slug = keys[i];
 var p = PRODUCTS_DATA[slug];
 var fromPrice = '';
 if (p.pricing && p.pricing.rows && p.pricing.rows[0]) {
 var fp = p.pricing.rows[0].prices[0];
 if (typeof fp === 'number' && fp > 0) fromPrice = 'From S$'+ fp;
 }
 var filterCat = CAT_GROUP[p.category] || p.category;
 html += '<div class="shop-card" data-cat="'+ filterCat + '" data-rawcat="'+ p.category + '" data-name="'+ p.name.toLowerCase() + '" data-slug="'+ slug + '">'+
 '<div class="sc-cat">'+ p.category + '<\/div>'+
 '<div class="sc-icon">'+ p.icon + '<\/div>'+
 '<div class="sc-name">'+ p.name + '<\/div>'+
 (fromPrice ? '<div class="sc-price">'+ fromPrice + '<\/div>': '') +
 '<\/div>';
 }
 grid.innerHTML = html;
 grid.querySelectorAll('.shop-card').forEach(function(el) {
 el.addEventListener('click', function(){ goProduct(this.dataset.slug); });
 });
 var countEl = document.getElementById('shop-count-display');
 if (countEl) countEl.textContent = keys.length;
 var label = document.getElementById('shop-results-label');
 if (label) label.textContent = keys.length + ' products';
}
function shopFilter(cat, btn) {
 var btns = document.querySelectorAll('.shop-filter-btn');
 btns.forEach(function(b){ b.classList.remove('active'); });
 if (btn) btn.classList.add('active');
 var items = document.querySelectorAll('#shop-grid-v2 .shop-card');
 if (!items.length) { buildShopGrid(); items = document.querySelectorAll('#shop-grid-v2 .shop-card'); }
 items.forEach(function(el) {
 el.style.display = (cat === 'all' || el.dataset.cat === cat) ? '' : 'none';
 });
 var empty = document.getElementById('shop-empty');
 var visible = document.querySelectorAll('#shop-grid-v2 .shop-card:not([style*="none"])').length;
 if (empty) empty.style.display = visible ? 'none' : 'block';
 var label = document.getElementById('shop-results-label');
 if (label) label.textContent = visible + ' product' + (visible !== 1 ? 's' : '') + (cat && cat !== 'all' ? ' in ' + cat : '');
}

function shopSearch(q) {
 var term = q.toLowerCase();
 var items = document.querySelectorAll('#shop-grid-v2 .shop-card');
 if (!items.length) { buildShopGrid(); items = document.querySelectorAll('#shop-grid-v2 .shop-card'); }
 items.forEach(function(el) {
 var name = (el.dataset.name || '').toLowerCase();
 var cat = (el.dataset.cat || '').toLowerCase();
 el.style.display = (!term || name.includes(term) || cat.includes(term)) ? '': 'none';
 });
 var empty = document.getElementById('shop-empty');
 var visible = document.querySelectorAll('#shop-grid-v2 .shop-card:not([style*="none"])').length;
 if (empty) empty.style.display = visible ? 'none': 'block';
 var label = document.getElementById('shop-results-label');
 if (label) label.textContent = term ? visible + 'result'+ (visible !== 1 ? 's': '') + 'for "'+ q + '"': visible + 'products';
}


