var admCurrentSlug = null;
var admSeoSlug = null;

// -- Tab switching --
function admTab(tab, el) {
 document.querySelectorAll('.adm-pane').forEach(function(p){ p.classList.remove('on'); });
 document.querySelectorAll('.adm-tab-btn').forEach(function(b){ b.classList.remove('on'); });
 if (tab === 'images') setTimeout(imglibInit, 30);
 var pane = document.getElementById('adm-pane-'+ tab);
 if (pane) pane.classList.add('on');
 if (el) el.classList.add('on');
 if (tab === 'products') admBuildProdList('');
 if (tab === 'seo') admBuildSeoList('');
 if (tab === 'orders') admLoadOrders();
 if (tab === 'dashboard') admLoadDashboard();
 if (tab === 'settings') admRenderSettings();
 if (tab === 'fonts') admRenderFontList();
 if (tab === 'pages') { admBuildFaqList(); renderNav();
  pgInitHomepage(); pgInitAbout(); }
}

// -- Also support old admShowSection calls --
function admShowSection(s, el) {
 var map = {dashboard:'dashboard',products:'products',orders:'orders',seo:'seo',bundles:'promos',pages:'pages'};
 var t = map[s] || s;
 var btn = document.getElementById('adm-tab-'+ t);
 admTab(t, btn || el);
}

// -- Image preview helper --
function admImgPreview(input, slotId, previewId) {
 var file = input.files[0];
 if (!file) return;
 var reader = new FileReader();
 reader.onload = function(e) {
 var el = document.getElementById(previewId);
 if (el) el.innerHTML = '<img class="adm-img-preview" src="'+ e.target.result + '"><div style="font-size:11px;color:#22c55e">&#10003; '+ file.name + '</div>';
 };
 reader.readAsDataURL(file);
}

