function admLiveUpdate(target, val) {
 // Future: update live DOM elements
}

// ── Navigation Admin ──────────────────────────────────────────────────────────

function admRenderNavList() {
  var el = document.getElementById('adm-nav-list');
  if (!el) return;
  var items = PG_DATA.nav || [];

  // Live preview bar
  var previewHtml = '<div style="background:#0a0a0a;padding:10px 20px;border-radius:2px;margin-bottom:16px;display:flex;gap:4px;align-items:center;flex-wrap:wrap">';
  previewHtml += '<span style="font-size:14px;font-weight:700;color:#fff;margin-right:12px">Print<span style="color:#E91E8C">volution</span></span>';
  items.forEach(function(item) {
    if (item.hidden) return;
    if (item.type === 'sep') { previewHtml += '<span style="width:1px;height:16px;background:#444;margin:0 4px;display:inline-block"></span>'; return; }
    previewHtml += '<span style="font-size:12px;color:#ccc;padding:4px 10px;cursor:default">' + (item.label||'') + (item.type==='dropdown'?' ▾':'') + '</span>';
  });
  previewHtml += '<span style="margin-left:auto;font-size:11px;color:#E91E8C;padding:4px 10px;border:1px solid #E91E8C">Cart</span>';
  previewHtml += '</div>';

  // Rows
  var rowsHtml = items.map(function(item, i) {
    var isSep = item.type === 'sep';
    var isHidden = !!item.hidden;
    return '<div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:'+(isHidden?'#fafafa':'#fff')+';border:1px solid #e0e0e0;margin-bottom:6px;opacity:'+(isHidden?.5:1)+'">'+
      // Up/down
      '<div style="display:flex;flex-direction:column;gap:2px;flex-shrink:0">'+
        '<button onclick="admNavMove('+i+',-1)" style="background:#f0f0f0;border:1px solid #ddd;width:22px;height:18px;cursor:pointer;font-size:10px;line-height:1;padding:0">▲</button>'+
        '<button onclick="admNavMove('+i+',1)" style="background:#f0f0f0;border:1px solid #ddd;width:22px;height:18px;cursor:pointer;font-size:10px;line-height:1;padding:0">▼</button>'+
      '</div>'+
      (isSep ?
        '<span style="flex:1;font-size:12px;color:#aaa;font-style:italic">— Separator —</span>' :
        // Type
        '<select onchange="admNavTypeChange('+i+',this.value)" style="border:1px solid #e0e0e0;padding:5px 6px;font-size:12px;font-family:var(--sans);background:#fff;flex-shrink:0">'+
          '<option value="link"'+(item.type==='link'?' selected':'')+'>Link</option>'+
          '<option value="dropdown"'+(item.type==='dropdown'?' selected':'')+'>Dropdown</option>'+
        '</select>'+
        // Label
        '<input class="adm-nav-label" data-i="'+i+'" value="'+(item.label||'').replace(/"/g,'&quot;')+'" placeholder="Label" '+
          'style="width:90px;border:1px solid #e0e0e0;padding:5px 8px;font-size:12px;font-family:var(--sans)">'+
        // Action or mega
        (item.type==='dropdown' ?
          '<select class="adm-nav-mega" data-i="'+i+'" style="border:1px solid #e0e0e0;padding:5px 6px;font-size:12px;font-family:var(--sans);background:#fff">'+
            '<option value="mega-print"'+(item.mega==='mega-print'?' selected':'')+'>Print dropdown</option>'+
            '<option value="mega-gifts"'+(item.mega==='mega-gifts'?' selected':'')+'>Gifts dropdown</option>'+
          '</select>' :
          admNavPageSelect(i, item.action||"go('shop')")
        )+
        // Hide toggle
        '<button onclick="admNavToggleHide('+i+')" title="'+(isHidden?'Show':'Hide')+'" '+
          'style="background:'+(isHidden?'#f0f0f0':'#fff')+';border:1px solid #ddd;padding:4px 8px;font-size:11px;cursor:pointer;flex-shrink:0">'+
          (isHidden ? '👁 Show' : '👁 Hide')+'</button>'
      )+
      // Delete
      '<button class="adm-row-del" style="margin:0;flex-shrink:0" onclick="admNavRemove('+i+')">&#215;</button>'+
    '</div>';
  }).join('');

  el.innerHTML = previewHtml + rowsHtml;
}

function admNavMove(i, dir) {
  var items = PG_DATA.nav;
  var j = i + dir;
  if (j < 0 || j >= items.length) return;
  var tmp = items[i]; items[i] = items[j]; items[j] = tmp;
  admRenderNavList();
}

function admNavToggleHide(i) {
  var item = PG_DATA.nav[i];
  if (item) item.hidden = !item.hidden;
  admRenderNavList();
}

var _navDragIdx = null;
var _admMenuWhich = 'print';
function admNavDragStart(e, i) { _navDragIdx = i; e.dataTransfer.effectAllowed='move'; }
function admNavDragOver(e) { e.preventDefault(); e.dataTransfer.dropEffect='move'; }
function admNavDrop(e, targetIdx) {
  e.preventDefault();
  if (_navDragIdx === null || _navDragIdx === targetIdx) return;
  var items = PG_DATA.nav;
  var moved = items.splice(_navDragIdx, 1)[0];
  items.splice(targetIdx, 0, moved);
  _navDragIdx = null;
  admRenderNavList();
}

function admNavTypeChange(i, type) {
  var item = PG_DATA.nav[i];
  if (!item) return;
  item.type = type;
  if (type === 'dropdown') { item.mega = item.mega || 'mega-print'; item.id = item.id || 'custom-nav-btn'; delete item.action; }
  if (type === 'link') { item.action = item.action || "go('shop')"; delete item.mega; delete item.id; }
  admRenderNavList();
}

function admNavRemove(i) {
  PG_DATA.nav.splice(i, 1);
  admRenderNavList();
}

function admNavAdd(type) {
  if (!PG_DATA.nav) PG_DATA.nav = [];
  if (type === 'sep') { PG_DATA.nav.push({type:'sep'}); }
  else { PG_DATA.nav.push({type:'link', label:'New Link', action:"go('home')"}); }
  admRenderNavList();
}

function admSaveNav() {
  var items = PG_DATA.nav;
  document.querySelectorAll('.adm-nav-row').forEach(function(row) {
    var i = parseInt(row.dataset.i);
    if (isNaN(i) || !items[i]) return;
    var item = items[i];
    if (item.type === 'sep') return;
    var labelInp = row.querySelector('.adm-nav-label');
    var actionInp = row.querySelector('.adm-nav-action');
    var megaSel = row.querySelector('.adm-nav-mega');
    if (labelInp) item.label = labelInp.value;
    if (actionInp) item.action = actionInp.value;
    if (megaSel) { item.mega = megaSel.value; item.id = megaSel.value.replace('mega-','') + '-nav-btn'; }
  });
  renderNav();
  var saved = document.getElementById('adm-nav-saved');
  if (saved) { saved.style.display='inline'; setTimeout(function(){ saved.style.display='none'; }, 2000); }
}

// ── Dropdown menu editor ──────────────────────────────────────────────────────
// All available internal pages for nav links
var NAV_PAGES = [
  {label:'Home',            action:"go('home')"},
  {label:'Shop — All Products', action:"go('shop')"},
  {label:'Bundles',         action:"go('bundles')"},
  {label:'About Us',        action:"go('about')"},
  {label:'Contact',         action:"go('contact')"},
  {label:'FAQ',             action:"go('faq')"},
  {label:'Membership',      action:"go('membership')"},
  {label:'My Orders',       action:"go('orders')"},
  {label:'Cart',            action:"go('checkout')"},
];

function admNavPageSelect(i, selectedAction) {
  var opts = NAV_PAGES.map(function(p) {
    var sel = p.action === selectedAction ? ' selected' : '';
    return '<option value="'+p.action.replace(/"/g,'&quot;')+'"'+sel+'>'+p.label+'</option>';
  }).join('');
  // Add custom option if current action doesn't match any preset
  var isCustom = !NAV_PAGES.find(function(p){ return p.action === selectedAction; });
  return '<select class="adm-nav-action" data-i="'+i+'" style="flex:1;border:1px solid #e0e0e0;padding:5px 8px;font-size:12px;font-family:var(--sans);background:#fff">'+
    opts +
    (isCustom ? '<option value="'+selectedAction.replace(/"/g,'&quot;')+'" selected>Custom: '+selectedAction+'</option>' : '')+
  '</select>';
}

function admMenuTab(which, btn) {
  _admMenuWhich = which;
  document.querySelectorAll('#adm-menu-tab-print, #adm-menu-tab-gifts').forEach(function(b){ b.classList.remove('on'); });
  if (btn) btn.classList.add('on');
  admRenderMenuEditor();
}

function admRenderMenuEditor() {
  var el = document.getElementById('adm-menu-editor');
  if (!el) return;
  var sections = (PG_DATA.menus && PG_DATA.menus[_admMenuWhich]) || [];
  el.innerHTML = sections.map(function(sec, si) {
    var isHidden = !!sec.hidden;
    return '<div style="border:1px solid #e0e0e0;margin-bottom:10px;background:'+(isHidden?'#fafafa':'#fff')+'">'+
      '<div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:#f5f5f5;border-bottom:1px solid #eee">'+
        '<div style="display:flex;flex-direction:column;gap:2px;flex-shrink:0">'+
          '<button onclick="admMenuMoveSection('+si+',-1)" style="background:#e8e8e8;border:1px solid #ddd;width:22px;height:16px;font-size:9px;cursor:pointer;padding:0">▲</button>'+
          '<button onclick="admMenuMoveSection('+si+',1)" style="background:#e8e8e8;border:1px solid #ddd;width:22px;height:16px;font-size:9px;cursor:pointer;padding:0">▼</button>'+
        '</div>'+
        '<input class="adm-menu-sec-hd" data-si="'+si+'" value="'+sec.heading.replace(/"/g,'&quot;')+'" '+
          'style="width:160px;border:1px solid #e0e0e0;padding:4px 8px;font-size:12px;font-weight:700;font-family:var(--sans)">'+
        '<span style="font-size:11px;color:#aaa;flex-shrink:0">Column:</span>'+
        '<select class="adm-menu-sec-col" data-si="'+si+'" style="border:1px solid #e0e0e0;padding:4px 6px;font-size:11px;font-family:var(--sans);background:#fff">'+
          '<option value="0"'+((!sec.col||sec.col===0)?' selected':'')+'>1</option>'+
          '<option value="1"'+(sec.col===1?' selected':'')+'>2</option>'+
          '<option value="2"'+(sec.col===2?' selected':'')+'>3</option>'+
        '</select>'+
        '<button onclick="admMenuToggleSec('+si+')" style="background:'+(isHidden?'#e8e8e8':'#fff')+';border:1px solid #ddd;padding:3px 8px;font-size:11px;cursor:pointer">'+(isHidden?'👁 Show':'👁 Hide')+'</button>'+
        '<button onclick="admMenuRemoveSec('+si+')" style="background:none;border:1px solid #fca5a5;color:#ef4444;padding:3px 8px;font-size:11px;cursor:pointer;margin-left:auto">✕ Remove</button>'+
      '</div>'+
      '<div style="padding:8px 10px">'+
        (sec.items||[]).map(function(item, ii) {
          var hid = !!item.hidden;
          var productOpts = Object.keys(PRODUCTS_DATA).map(function(slug){
            var p = PRODUCTS_DATA[slug];
            var sel = slug === item.slug ? ' selected' : '';
            return '<option value="'+slug+'"'+sel+'>'+p.name+'</option>';
          }).join('');
          return '<div style="display:flex;align-items:center;gap:6px;margin-bottom:5px;opacity:'+(hid?.5:1)+'">'+
            '<div style="display:flex;flex-direction:column;gap:1px;flex-shrink:0">'+
              '<button onclick="admMenuMoveItem('+si+','+ii+',-1)" style="background:#f0f0f0;border:1px solid #ddd;width:18px;height:14px;font-size:8px;cursor:pointer;padding:0">▲</button>'+
              '<button onclick="admMenuMoveItem('+si+','+ii+',1)" style="background:#f0f0f0;border:1px solid #ddd;width:18px;height:14px;font-size:8px;cursor:pointer;padding:0">▼</button>'+
            '</div>'+
            '<select class="adm-menu-item-slug" data-si="'+si+'" data-ii="'+ii+'" '+
              'onchange="admMenuItemPick('+si+','+ii+',this)" '+
              'style="flex:1;border:1px solid #e0e0e0;padding:4px 7px;font-size:12px;font-family:var(--sans);background:#fff">'+
              productOpts+
            '</select>'+
            '<input class="adm-menu-item-label" data-si="'+si+'" data-ii="'+ii+'" value="'+item.label.replace(/"/g,'&quot;')+'" '+
              'placeholder="Label override" style="width:120px;border:1px solid #e0e0e0;padding:4px 7px;font-size:12px;font-family:var(--sans)" title="Leave as product name or customise">'+
            '<button onclick="admMenuToggleItem('+si+','+ii+')" title="'+(hid?'Show':'Hide')+'" style="background:'+(hid?'#e8e8e8':'#fff')+';border:1px solid #ddd;padding:2px 6px;font-size:11px;cursor:pointer">'+(hid?'Show':'Hide')+'</button>'+
            '<button onclick="admMenuRemoveItem('+si+','+ii+')" style="background:none;border:1px solid #fca5a5;color:#ef4444;padding:2px 6px;font-size:11px;cursor:pointer">✕</button>'+
          '</div>';
        }).join('')+
        '<button onclick="admMenuAddItem('+si+')" style="background:none;border:1px dashed #ddd;color:#888;padding:4px 10px;font-size:11px;cursor:pointer;margin-top:6px;width:100%">+ Add item to this section</button>'+
      '</div>'+
    '</div>';
  }).join('');
}

function admMenuItemPick(si, ii, sel) {
  var slug = sel.value;
  var p = PRODUCTS_DATA[slug];
  if (!p) return;
  var item = PG_DATA.menus[_admMenuWhich][si].items[ii];
  if (item) {
    item.slug = slug;
    item.label = p.name; // auto-fill label with product name
  }
  // Update the label input next to this select
  var row = sel.parentNode;
  var labelInp = row.querySelector('.adm-menu-item-label');
  if (labelInp) labelInp.value = p.name;
}

function admMenuMoveSection(si,dir){var s=PG_DATA.menus[_admMenuWhich],j=si+dir;if(j<0||j>=s.length)return;var t=s[si];s[si]=s[j];s[j]=t;admRenderMenuEditor();}
function admMenuToggleSec(si){var s=PG_DATA.menus[_admMenuWhich][si];if(s)s.hidden=!s.hidden;admRenderMenuEditor();}
function admMenuRemoveSec(si){PG_DATA.menus[_admMenuWhich].splice(si,1);admRenderMenuEditor();}
function admMenuAddSection(){var s=PG_DATA.menus[_admMenuWhich]||(PG_DATA.menus[_admMenuWhich]=[]);s.push({heading:'New Section',col:0,items:[]});admRenderMenuEditor();}
function admMenuMoveItem(si,ii,dir){var items=PG_DATA.menus[_admMenuWhich][si].items,j=ii+dir;if(j<0||j>=items.length)return;var t=items[ii];items[ii]=items[j];items[j]=t;admRenderMenuEditor();}
function admMenuToggleItem(si,ii){var it=PG_DATA.menus[_admMenuWhich][si].items[ii];if(it)it.hidden=!it.hidden;admRenderMenuEditor();}
function admMenuRemoveItem(si,ii){PG_DATA.menus[_admMenuWhich][si].items.splice(ii,1);admRenderMenuEditor();}
function admMenuAddItem(si){
  var firstSlug = Object.keys(PRODUCTS_DATA)[0];
  var firstName = (PRODUCTS_DATA[firstSlug]||{}).name || 'Product';
  PG_DATA.menus[_admMenuWhich][si].items.push({slug:firstSlug, label:firstName});
  admRenderMenuEditor();
}

function admSaveMenus() {
  var secs = PG_DATA.menus[_admMenuWhich];
  document.querySelectorAll('#adm-menu-editor .adm-menu-sec-hd').forEach(function(inp){var si=parseInt(inp.dataset.si);if(secs[si])secs[si].heading=inp.value;});
  document.querySelectorAll('#adm-menu-editor .adm-menu-sec-col').forEach(function(sel){var si=parseInt(sel.dataset.si);if(secs[si])secs[si].col=parseInt(sel.value);});
  document.querySelectorAll('#adm-menu-editor .adm-menu-item-label').forEach(function(inp){var si=parseInt(inp.dataset.si),ii=parseInt(inp.dataset.ii);if(secs[si]&&secs[si].items[ii])secs[si].items[ii].label=inp.value;});
  document.querySelectorAll('#adm-menu-editor .adm-menu-item-slug').forEach(function(inp){var si=parseInt(inp.dataset.si),ii=parseInt(inp.dataset.ii);if(secs[si]&&secs[si].items[ii])secs[si].items[ii].slug=inp.value;});
  renderMegaMenus();
  var saved=document.getElementById('adm-menu-saved');
  if(saved){saved.style.display='inline';setTimeout(function(){saved.style.display='none';},2000);}
}

function pgSubTab(name, el) {
 document.querySelectorAll('.pg-sub-pane').forEach(function(p){ p.style.display = 'none'; });
 document.querySelectorAll('.pg-sub-btn').forEach(function(b){ b.classList.remove('on'); });
 var pane = document.getElementById('pg-pane-'+ name);
 if (pane) pane.style.display = 'block';
 if (el) el.classList.add('on');
 if (name === 'faq') admBuildFaqList();
 if (name === 'homepage') pgInitHomepage();
 if (name === 'about') pgInitAbout();
 if (name === 'nav') { admRenderNavList(); admRenderMenuEditor(); }
 if (name === 'contact') pgRenderContactMethods();
 if (name === 'chipdefaults') pgInitChipDefaults();
}

