var CAT_CHIP_DEFAULTS = {
  'Cards & Types':           ['Makes people remember you','Ready before your next meeting','Premium finishes nobody else offers'],
  'Advertising':             ['Put your brand where eyes go','Reusable across multiple events','Delivered to your door or collect at Paya Lebar'],
  'Art & Signage':           ['Exhibition-quality print','Mounted and ready to hang','Custom sizes available'],
  'Embroidery':              ['Wearable merch people actually keep','Your artwork stitched to last 100+ washes','Full size range XS to 3XL'],
  'Jewellery':               ['Comes gift-ready in a box','Engraved exactly how you want it','Gold, Silver & Rose Gold options'],
  'Wedding':['Personalised to your exact names & date','A keepsake they will keep forever','Makes the occasion feel truly one-of-a-kind'],
  'Personalised Gifts':      ['Meaningful gift that nobody else has','Built around your photo or story','Arrives gift-ready'],
'Business Stationery':     ['Makes your business look the part','Consistent branding across every touchpoint','Easy reorder anytime'],
  'Wearables':               ['Full colour or embroidery options','XS to 3XL in stock','Mockup before production'],
'Packaging':               ['Your logo on every pack','Custom size & finish','Bulk pricing available'],
  'Lifestyle':               ['Personalised to order','5–7 day turnaround','Island-wide delivery'],
'_default':                ['Pre-press check on every file','Express turnaround available','Island-wide delivery']
};

function pgInitChipDefaults() {
  var container = document.getElementById('pg-chipdef-rows');
  if (!container) return;
  // All known categories + _default fallback
  var cats = Object.keys(CAT_CHIP_DEFAULTS);
  container.innerHTML = cats.map(function(cat) {
    var chips = CAT_CHIP_DEFAULTS[cat] || ['','',''];
    var label = cat === '_default' ? '⚙ Fallback (all other categories)' : cat;
    var inputs = [0,1,2,3].map(function(i) {
      return '<input data-cat="'+cat.replace(/"/g,'&quot;')+'" data-i="'+i+'" value="'+(chips[i]||'').replace(/"/g,'&quot;')+'" placeholder="Chip '+(i+1)+' (leave blank to skip)" style="border:1px solid #e0e0e0;padding:7px 10px;font-size:12px;font-family:var(--sans);width:100%;box-sizing:border-box;margin-bottom:6px">';
    }).join('');
    return '<div style="border:1px solid #e5e5e5;padding:14px 16px;background:#fff">'+
      '<div style="font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:1px;color:#E91E8C;margin-bottom:10px">'+label+'</div>'+
      inputs+
    '</div>';
  }).join('');
}

function admSaveChipDefaults() {
  var inputs = document.querySelectorAll('#pg-chipdef-rows input[data-cat]');
  inputs.forEach(function(inp) {
    var cat = inp.dataset.cat;
    var i   = +inp.dataset.i;
    if (!CAT_CHIP_DEFAULTS[cat]) CAT_CHIP_DEFAULTS[cat] = ['','',''];
    // Ensure array is long enough
    while (CAT_CHIP_DEFAULTS[cat].length <= i) CAT_CHIP_DEFAULTS[cat].push('');
    CAT_CHIP_DEFAULTS[cat][i] = inp.value.trim();
  });
  // Remove trailing empty chips from each category
  Object.keys(CAT_CHIP_DEFAULTS).forEach(function(cat) {
    var arr = CAT_CHIP_DEFAULTS[cat];
    while (arr.length > 0 && !arr[arr.length-1]) arr.pop();
    if (!arr.length) CAT_CHIP_DEFAULTS[cat] = [''];
  });
  admShowSaved('saved-chipdefaults');
}

