// ── Mega menu renderer — reads PG_DATA.menus ─────────────────────────────────
function renderMegaMenus() {
  ['print','gifts'].forEach(function(which) {
    var el = document.getElementById('mega-'+which+'-inner');
    if (!el) return;
    var sections = (PG_DATA.menus && PG_DATA.menus[which]) || [];
    // Group sections by col (0,1,2) — col field or sequential
    var cols = [[],[],[]];
    var autoCol = 0;
    sections.forEach(function(sec) {
      if (sec.hidden) return;
      var c = (sec.col !== undefined) ? sec.col : autoCol;
      if (!cols[c]) cols[c] = [];
      cols[c].push(sec);
      // Advance autoCol when col not specified and a new natural col starts
    });
    // Auto-assign: sections without col get packed into cols sequentially
    // Re-do: simpler — use sec.col if set, else pack by count
    cols = [[],[],[]];
    sections.forEach(function(sec) {
      if (sec.hidden) return;
      var c = (typeof sec.col === 'number') ? sec.col : null;
      if (c === null) {
        // Assign to column with fewest items
        var lens = cols.map(function(col){ return col.reduce(function(s,s2){return s+(s2.items||[]).length;},0); });
        c = lens.indexOf(Math.min.apply(null,lens));
        // But keep sections together that were originally sequential — use first item's original col
        c = sec._col !== undefined ? sec._col : c;
      }
      if (c < 0 || c > 2) c = 0;
      cols[c].push(sec);
    });

    el.innerHTML = cols.filter(function(c){return c.length;}).map(function(col) {
      return '<div class="mega-col">'+
        col.map(function(sec, si) {
          var hdStyle = si > 0 ? ' style="margin-top:14px"' : '';
          return '<div class="mega-hd"'+hdStyle+'>'+sec.heading+'</div>'+
            (sec.items||[]).filter(function(it){return !it.hidden;}).map(function(item) {
              return '<div class="mega-item" onclick="goProduct(\''+item.slug+'\')">'+item.label+'</div>';
            }).join('');
        }).join('')+
      '</div>';
    }).join('');
  });
}

// ── Nav renderer — reads PG_DATA.nav ─────────────────────────────────────────
function renderNav() {
  var el = document.getElementById('nav-clinks-render');
  if (!el) return;
  var items = (PG_DATA.nav || []).filter(function(item){ return !item.hidden; });
  el.innerHTML = items.map(function(item) {
    if (item.type === 'sep') return '<span class="nav-sep"></span>';
    if (item.type === 'dropdown') {
      return '<span class="nav-lnk" id="'+ item.id +'" onmousedown="megaToggle(event,\''+item.mega+'\')">'+
        item.label + ' &#9662;</span>';
    }
    return '<span class="nav-lnk" onclick="'+ item.action +'">'+item.label+'</span>';
  }).join('');
}

