// ── Admin overlay preview canvas ─────────────────────────────────────────────
var _peOvPreviewImg = null;

function peOverlayPreview() {
  var canvas = document.getElementById('pe-overlay-preview');
  if (!canvas) return;
  var slug = admCurrentSlug;
  var ex = PP_EXTRA[slug] || {};
  var gc3 = ex.giftConfig || {};
  var imgSrc = gc3.mockupImage || ex.image || '';

  // Collect current layer values from form
  var layers = [];
  var orRows = document.querySelectorAll('#pe-overlay-rows > div[id^="pe-or-"]');
  orRows.forEach(function(row, li) {
    var g  = function(cls){ var e=row.querySelector('.'+cls+'[data-li="'+li+'"]'); return e?e.value:''; };
    var gN = function(cls){ return parseFloat(g(cls))||0; };
    layers.push({
      label:     g('pe-ov-label')||'Text',
      x:         Math.max(1,Math.min(99,gN('pe-ov-x')||50)),
      y:         Math.max(1,Math.min(99,gN('pe-ov-y')||60)),
      fontSize:  Math.max(8,gN('pe-ov-fs')||20),
      color:     g('pe-ov-color')||'#ffffff',
      fontStyle: g('pe-ov-font')||'Georgia, serif',
    });
  });

  function drawPreview() {
    var wrap = canvas.parentElement;
    // offsetWidth can be 0 if parent was recently made visible — walk up to find real width
    var maxW = 360;
    var el = wrap;
    while (el) { if (el.offsetWidth > 50) { maxW = Math.min(el.offsetWidth - 16, 600); break; } el = el.parentElement; }
    var img = _peOvPreviewImg;
    // Canvas ratio: print dimensions take priority over image natural ratio
    var _dw = parseFloat((document.getElementById('pe-mock-w')||{}).value) || 0;
    var _dh = parseFloat((document.getElementById('pe-mock-h')||{}).value) || 0;
    var ratio = (_dw > 0 && _dh > 0) ? (_dh / _dw)
              : (img && img.naturalWidth ? img.naturalHeight / img.naturalWidth : 1.2);
    canvas.width  = maxW;
    canvas.height = Math.round(maxW * ratio);
    canvas.style.width  = canvas.width  + 'px';
    canvas.style.height = canvas.height + 'px';

    var ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (img && img.complete && img.naturalWidth) {
      // Cover-fit: fill canvas preserving image ratio, centred — no stretching
      var _iw = img.naturalWidth, _ih = img.naturalHeight;
      var _sc = Math.max(canvas.width / _iw, canvas.height / _ih);
      var _dw2 = _iw * _sc, _dh2 = _ih * _sc;
      var _dx = (canvas.width - _dw2) / 2, _dy = (canvas.height - _dh2) / 2;
      ctx.drawImage(img, _dx, _dy, _dw2, _dh2);
    } else {
      // No image — placeholder shows dimension info
      ctx.fillStyle = '#f0f0f0';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#bbb';
      ctx.font = '13px sans-serif';
      ctx.textAlign = 'center';
      if (_dw > 0 && _dh > 0) {
        ctx.fillText('Upload mockup image (' + _dw + ' x ' + _dh + ')', canvas.width/2, canvas.height/2 - 10);
        ctx.fillStyle = '#E91E8C';
        ctx.font = 'bold 11px sans-serif';
        ctx.fillText('Canvas locked to this ratio', canvas.width/2, canvas.height/2 + 12);
      } else {
        ctx.fillText('Set dimensions above, then upload mockup image', canvas.width/2, canvas.height/2);
      }
    }

    // Draw text layers
    layers.forEach(function(layer) {
      var x = (layer.x / 100) * canvas.width;
      var y = (layer.y / 100) * canvas.height;
      var fSize = Math.max(10, (layer.fontSize / 100) * canvas.width * 1.8);
      ctx.save();
      ctx.font = 'bold ' + fSize + 'px ' + layer.fontStyle;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      // Drop shadow for readability
      ctx.shadowColor = 'rgba(0,0,0,0.5)';
      ctx.shadowBlur = 4;
      ctx.fillStyle = layer.color;
      ctx.fillText(layer.label + ' →', x, y);
      // Position marker
      ctx.shadowBlur = 0;
      ctx.strokeStyle = 'rgba(233,30,140,0.5)';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.arc(x, y, 4, 0, Math.PI*2);
      ctx.stroke();
      ctx.restore();
    });
  }

  // Load/reload image
  if (!imgSrc) { _peOvPreviewImg = null; drawPreview(); return; }
  if (_peOvPreviewImg && _peOvPreviewImg.src === imgSrc) { drawPreview(); return; }
  var img = new Image();
  img.crossOrigin = 'anonymous';
  img.onload = function() { _peOvPreviewImg = img; drawPreview(); };
  img.onerror = function() { _peOvPreviewImg = null; drawPreview(); };
  img.src = imgSrc;
}


// -- Admin overlay: ratio hint badge --
function peUpdateRatioHint() {
  // Also update mockup uploader cropbox ratio live
  var _mwE = document.getElementById('pe-mock-w');
  var _mhE = document.getElementById('pe-mock-h');
  var _mwV = parseFloat(_mwE && _mwE.value) || 0;
  var _mhV = parseFloat(_mhE && _mhE.value) || 0;
  if (_mwV > 0 && _mhV > 0) admIuSetRatio('pe-mockup-uploader', _mwV / _mhV);
  var wEl = document.getElementById('pe-mock-w');
  var hEl = document.getElementById('pe-mock-h');
  var hintEl = document.getElementById('pe-mock-ratio-hint');
  if (!hintEl) return;
  var w = parseFloat(wEl && wEl.value) || 0;
  var h = parseFloat(hEl && hEl.value) || 0;
  if (w > 0 && h > 0) {
    function gcd(a,b){a=Math.round(a);b=Math.round(b);return b===0?a:gcd(b,a%b);}
    var g=gcd(w,h), rw=Math.round(w/g), rh=Math.round(h/g);
    if(rw>20||rh>20){rw=Math.round(w);rh=Math.round(h);}
    var img = (typeof _peOvPreviewImg!=='undefined') ? _peOvPreviewImg : null;
    if (img && img.naturalWidth && img.naturalHeight) {
      var diff = Math.abs((img.naturalHeight/img.naturalWidth)-(h/w))/(h/w);
      if (diff > 0.02) {
        hintEl.textContent = '[!] '+rw+':'+rh+' -- image ratio mismatch!';
        hintEl.style.cssText='font-size:11px;font-weight:700;color:#856404;background:#fff3cd;border:1px solid #ffc107;padding:3px 8px;border-radius:4px;white-space:nowrap;display:inline-block';
        return;
      }
    }
    hintEl.textContent = rw+':'+rh+' ratio';
    hintEl.style.cssText='font-size:11px;font-weight:700;color:#E91E8C;background:#fff0f7;border:1px solid #fcd6ea;padding:3px 8px;border-radius:4px;white-space:nowrap;display:inline-block';
  } else {
    hintEl.style.display='none';
  }
}

// Wire canvas drag to reposition layers
function peOvPreviewWireDrag() {
  var canvas = document.getElementById('pe-overlay-preview');
  if (!canvas || canvas._pvDragWired) return;
  canvas._pvDragWired = true;

  var dragging = null;
  function getPos(e) {
    var r = canvas.getBoundingClientRect();
    var touch = e.touches ? e.touches[0] : e;
    return { x: touch.clientX - r.left, y: touch.clientY - r.top };
  }
  function getLayerAt(x, y) {
    var slug = admCurrentSlug;
    var orRows = document.querySelectorAll('#pe-overlay-rows > div[id^="pe-or-"]');
    for (var li = 0; li < orRows.length; li++) {
      var row = orRows[li];
      var g  = function(cls){ var e=row.querySelector('.'+cls+'[data-li="'+li+'"]'); return e?parseFloat(e.value)||0:0; };
      var lx = (g('pe-ov-x') / 100) * canvas.width;
      var ly = (g('pe-ov-y') / 100) * canvas.height;
      if (Math.abs(x-lx) < 40 && Math.abs(y-ly) < 30) return li;
    }
    return null;
  }
  function updateLayerPos(li, x, y) {
    var xPct = Math.max(1, Math.min(99, (x / canvas.width)  * 100));
    var yPct = Math.max(1, Math.min(99, (y / canvas.height) * 100));
    var row = document.getElementById('pe-or-'+li);
    if (!row) return;
    var xEl = row.querySelector('.pe-ov-x[data-li="'+li+'"]');
    var yEl = row.querySelector('.pe-ov-y[data-li="'+li+'"]');
    if (xEl) xEl.value = Math.round(xPct);
    if (yEl) yEl.value = Math.round(yPct);
    peOverlayPreview();
  }
  canvas.addEventListener('mousedown', function(e){ dragging = getLayerAt(getPos(e).x, getPos(e).y); });
  canvas.addEventListener('mousemove', function(e){ if(dragging===null) return; var p=getPos(e); updateLayerPos(dragging,p.x,p.y); });
  canvas.addEventListener('mouseup', function(){ dragging=null; });
  canvas.addEventListener('touchstart', function(e){ dragging = getLayerAt(getPos(e).x, getPos(e).y); });
  canvas.addEventListener('touchmove', function(e){ if(dragging===null) return; e.preventDefault(); var p=getPos(e); updateLayerPos(dragging,p.x,p.y); }, {passive:false});
  canvas.addEventListener('touchend', function(){ dragging=null; });
}

function admSaveProd() {
 var slug = admCurrentSlug;
 if (!slug) return;
 var p = PRODUCTS_DATA[slug];
 var ex = PP_EXTRA[slug] || (PP_EXTRA[slug] = {});

 // Core fields
 var newName = document.getElementById('pe-name').value.trim();
 if (newName) p.name = newName;
 var newTagline = document.getElementById('pe-tagline').value.trim();
 if (newTagline) p.tagline = newTagline;
 p.description = document.getElementById('pe-desc').value || p.description;
 ex.intro = document.getElementById('pe-intro').value;
 var showPricingCb = document.getElementById('pe-show-pricing');
 if (showPricingCb) ex.showPricingTable = showPricingCb.checked ? undefined : false;
 ex.heroColor = document.getElementById('pe-hcolor-txt').value || document.getElementById('pe-hcolor').value;
 ex.heroBig = document.getElementById('pe-herobig').value;
 ex.h1 = document.getElementById('pe-h1').value;
 ex.h1em = document.getElementById('pe-h1em').value;
 ex.whyHeadline = document.getElementById('pe-why-hl').value;
 var imgUrl = document.getElementById('pe-img-url');
 if (imgUrl) ex.image = imgUrl.value.trim();
 // Also check new uploader widget
 var uploaderVal = admIuGetValue('pe-img-uploader');
 if (uploaderVal !== undefined) ex.image = uploaderVal;

 // SEO fields
 var seoTitle = document.getElementById('pe-seo-title');
 var seoDesc = document.getElementById('pe-seo-desc');
 var seoBody = document.getElementById('pe-seo-body');
 if (seoTitle) ex.seoTitle = seoTitle.value;
 if (seoDesc) ex.seoDesc = seoDesc.value;
 if (seoBody) ex.seoBody = seoBody.value.trim() || undefined;
 // Update live meta tags
 document.title = ex.seoTitle || (p.name + 'Singapore');
 var metaDesc = document.querySelector('meta[name="description"]');
 if (metaDesc && ex.seoDesc) metaDesc.content = ex.seoDesc;

 // Pricing config labels
 document.querySelectorAll('#adm-prod-editor .adm-cfg-inp').forEach(function(inp) {
   p.pricing.configs[+inp.dataset.ci] = inp.value;
 });
 // Pricing rows - qty
 document.querySelectorAll('#adm-prod-editor .adm-qty-inp').forEach(function(inp) {
   if (p.pricing.rows[+inp.dataset.ri]) p.pricing.rows[+inp.dataset.ri].qty = inp.value;
 });
 // Pricing cells - read from contenteditable rich cells
 document.querySelectorAll('#adm-prod-editor .adm-price-rich').forEach(function(cell) {
   var ri = +cell.dataset.ri, ci = +cell.dataset.ci;
   if (p.pricing.rows[ri]) {
     var raw = cell.innerText.trim();
     var n = parseFloat(raw);
     p.pricing.rows[ri].prices[ci] = isNaN(n) ? raw : n;
   }
 });

 // Specs
 var specs = [];
 document.querySelectorAll('#adm-prod-editor .adm-spec-l').forEach(function(inp, i) {
 var vEl = document.querySelectorAll('#adm-prod-editor .adm-spec-v')[i];
 if (inp.value) specs.push({label: inp.value, value: vEl ? vEl.value : ''});
 });
 p.specs = specs;

 // Highlights
 var hl = [];
 document.querySelectorAll('#adm-prod-editor .adm-hl-inp').forEach(function(inp) { if(inp.value) hl.push(inp.value); });
 p.highlights = hl;

 // Why Us
 var why = [];
 document.querySelectorAll('#adm-prod-editor .adm-why-inp').forEach(function(inp) { if(inp.value) why.push(inp.value); });
 ex.whyUs = why;

 // Chips
 var chips = [];
 document.querySelectorAll('#adm-prod-editor .adm-chip-inp').forEach(function(inp) { if(inp.value) chips.push(inp.value); });
 ex.chips = chips.length ? chips : undefined;
 // Use Cases — read title + desc + img, store as objects
 var useCases = [];
 var ucRows = document.querySelectorAll('#adm-usecase-rows > div');
 ucRows.forEach(function(row, i) {
   var titleInp = row.querySelector('.adm-uc-title');
   var descInp  = row.querySelector('.adm-uc-desc');
   var imgWrap  = row.querySelector('.adm-uc-img-wrap');
   var t = titleInp ? titleInp.value.trim() : '';
   var d = descInp  ? descInp.value.trim()  : '';
   var img = imgWrap ? (admIuGetValue(imgWrap.id) || '') : '';
   if (t) useCases.push({title:t, desc:d, img:img});
 });
 ex.useCases = useCases.length ? useCases : undefined;

 // Configurator steps - options labels, formulas, notes
 var cfg = CONFIGURATOR[slug];
 if (cfg && cfg.steps) {
   cfg.steps.forEach(function(step, si) {
     if (step.type === 'qty') {
       var qmodeInp = document.querySelector('.adm-qmode[data-si="'+ si +'"]:checked');
       var minInp = document.querySelector('.adm-qty-min[data-si="'+ si +'"]');
       var stepInp = document.querySelector('.adm-qty-step[data-si="'+ si +'"]');
       var presetsInp = document.querySelector('.adm-qty-presets[data-si="'+ si +'"]');
       var maxInp = document.querySelector('.adm-qty-max[data-si="'+ si +'"]');
       var qmode = qmodeInp ? qmodeInp.value : 'freetext';
       step.qmode = qmode;
       if (qmode === 'fixed') {
         step.min = 1; step.step = 1; step.max = 1; step.presets = [1];
       } else if (qmode === 'presets') {
         if (minInp) step.min = parseInt(minInp.value) || 1;
         if (presetsInp && presetsInp.value) {
           step.presets = presetsInp.value.split(',').map(function(v){ return parseInt(v.trim()); }).filter(function(n){ return !isNaN(n) && n > 0; });
           // Auto-set min to smallest preset
           if (step.presets.length) step.min = Math.min.apply(null, step.presets);
         }
         delete step.max;
       } else if (qmode === 'multiples') {
         if (stepInp) step.step = parseInt(stepInp.value) || 100;
         if (minInp) step.min = parseInt(minInp.value) || step.step;
         step.min = Math.max(step.step, Math.ceil(step.min / step.step) * step.step);
         step.presets = [];
         delete step.max;
       } else { // freetext
         if (minInp) step.min = parseInt(minInp.value) || 1;
         if (stepInp) step.step = parseInt(stepInp.value) || 1;
         if (maxInp) step.max = parseInt(maxInp.value) || 9999;
         step.presets = [];
       }
     } else {
       // Save step name, type, required
       var stepLabelInp = document.querySelector('.adm-step-label[data-si="'+ si +'"]');
       var stepTypeInp  = document.querySelector('.adm-step-type[data-si="'+ si +'"]');
       var stepReqInp   = document.querySelector('.adm-step-req[data-si="'+ si +'"]');
       if (stepLabelInp) step.label = stepLabelInp.value;
       if (stepTypeInp)  step.type  = stepTypeInp.value;
       if (stepReqInp)   step.required = stepReqInp.checked;
       (step.options||[]).forEach(function(opt, oi) {
         var labelInp = document.querySelector('.adm-opt-label[data-si="'+ si +'"][data-oi="'+ oi +'"]');
         var formulaInp = document.querySelector('.adm-opt-formula[data-si="'+ si +'"][data-oi="'+ oi +'"]');
         var noteInp = document.querySelector('.adm-opt-note[data-si="'+ si +'"][data-oi="'+ oi +'"]');
         if (labelInp) opt.label = labelInp.value;
         if (formulaInp) opt.price_formula = formulaInp.value;
         if (noteInp) opt.note = noteInp.value;
       });
     }
   });
 }

 // FAQ
 var faqQs = document.querySelectorAll('#adm-prod-editor .adm-faq-q');
 var faqAs = document.querySelectorAll('#adm-prod-editor .adm-faq-a');
 var faq = [];
 faqQs.forEach(function(q, i) { if(q.value) faq.push([q.value, faqAs[i] ? faqAs[i].value : '']); });
 ex.faq = faq;

 // Product type + method
 var peType = document.getElementById('pe-type');
 if (peType) p.type = peType.value || 'service';
 var peMethod = document.getElementById('pe-method');
 if (peMethod && peMethod.value) { if (!ex.giftConfig) ex.giftConfig = {}; ex.giftConfig.method = peMethod.value; }

 // Gift flow type
 var peFlowType = document.getElementById('pe-flow-type');
 if (peFlowType) {
   if (!ex.giftConfig) ex.giftConfig = {};
   ex.giftConfig.flowType = (peFlowType.value && peFlowType.value !== 'none') ? peFlowType.value : undefined;
 }

 // Style rows (AI prompts)
 var srRows = document.querySelectorAll('#pe-style-rows > div[id^="pe-sr-"]');
 if (srRows.length || (ex.giftConfig && ex.giftConfig.styleOptions !== undefined)) {
   if (!ex.giftConfig) ex.giftConfig = {};
   var stls = [];
   srRows.forEach(function(row, si) {
     var lbl = (row.querySelector('.pe-style-label[data-si="'+si+'"]')||{}).value||'';
     var prm = (row.querySelector('.pe-style-prompt[data-si="'+si+'"]')||{}).value||'';
     if (lbl || prm) stls.push({label:lbl, prompt:prm});
   });
   ex.giftConfig.styleOptions = stls.length ? stls : undefined;
 }

 // Overlay rows (text layers)
 var orRows = document.querySelectorAll('#pe-overlay-rows > div[id^="pe-or-"]');
 if (orRows.length || (ex.giftConfig && ex.giftConfig.textLayers !== undefined)) {
   if (!ex.giftConfig) ex.giftConfig = {};
   var lyrs = [];
   orRows.forEach(function(row, li) {
     var g   = function(cls){ var e=row.querySelector('.'+cls+'[data-li="'+li+'"]'); return e?e.value:''; };
     var gN  = function(cls){ return parseFloat(g(cls))||0; };
     var gCk = function(cls){ var e=row.querySelector('.'+cls+'[data-li="'+li+'"]'); return e?e.checked:false; };
     var lbl = g('pe-ov-label') || 'Text';
     lyrs.push({label:lbl, placeholder:g('pe-ov-ph'),
       x:Math.max(1,Math.min(99,gN('pe-ov-x')||50)),
       y:Math.max(1,Math.min(99,gN('pe-ov-y')||60)),
       fontSize:Math.max(8,gN('pe-ov-fs')||20),
       color:g('pe-ov-color')||'#ffffff',
       fontStyle:g('pe-ov-font')||'Georgia, serif',
       align:'center', canMove:gCk('pe-ov-canmove'), required:gCk('pe-ov-req')});
   });
   ex.giftConfig.textLayers = lyrs.length ? lyrs : undefined;
 }

 // Mockup image (for overlay / template modes)
 // Only write if the uploader was initialised for THIS product (not a stale value from another)
 var _mockupSt = _aiuState && _aiuState['pe-mockup-uploader'];
 if (_mockupSt && _mockupSt._slug === slug) {
   if (_mockupSt.origImg) admIuConfirm('pe-mockup-uploader');
   var mockupUploaderVal = admIuGetValue ? admIuGetValue('pe-mockup-uploader') : undefined;
   if (mockupUploaderVal !== undefined) {
     if (!ex.giftConfig) ex.giftConfig = {};
     ex.giftConfig.mockupImage = mockupUploaderVal || undefined;
   }
 }

 // Overlay print dimensions
 var _mockW = document.getElementById('pe-mock-w');
 var _mockH = document.getElementById('pe-mock-h');
 var _mockUnit = document.getElementById('pe-mock-unit');
 var _mockBleed = document.getElementById('pe-mock-bleed');
 if (_mockW && parseFloat(_mockW.value)) {
   if (!ex.giftConfig) ex.giftConfig = {};
   ex.giftConfig.printConfig = {
     w: parseFloat(_mockW.value)||0, h: parseFloat(_mockH&&_mockH.value)||0,
     unit: _mockUnit?_mockUnit.value:'mm', bleed: parseInt(_mockBleed?_mockBleed.value:0)||0
   };
 }

 // Base AI prompt
 var peBasePrompt = document.getElementById('pe-base-prompt');
 if (peBasePrompt !== null) {
   if (!ex.giftConfig) ex.giftConfig = {};
   ex.giftConfig.basePrompt = peBasePrompt.value.trim() || undefined;
 }

 // Template fields
 var trRows = document.querySelectorAll('#pe-template-rows > div[id^="pe-tr-"]');
 if (trRows.length || (ex.giftConfig && ex.giftConfig.templateFields !== undefined)) {
   if (!ex.giftConfig) ex.giftConfig = {};
   var tFields = [];
   trRows.forEach(function(row, ti) {
     var g  = function(cls){ var e=row.querySelector('.'+cls+'[data-ti="'+ti+'"]'); return e?e.value:''; };
     var gN = function(cls){ return parseFloat(g(cls))||0; };
     var gCk= function(cls){ var e=row.querySelector('.'+cls+'[data-ti="'+ti+'"]'); return e?e.checked:false; };
     var lbl = g('pe-tr-label') || 'Field';
     tFields.push({label:lbl, placeholder:g('pe-tr-ph'),
       x:Math.max(1,Math.min(99,gN('pe-tr-x')||50)),
       y:Math.max(1,Math.min(99,gN('pe-tr-y')||50)),
       fontSize:Math.max(8,gN('pe-tr-fs')||24),
       color:g('pe-tr-color')||'#1a1a1a',
       align:'center', required:gCk('pe-tr-req')});
   });
   ex.giftConfig.templateFields = tFields.length ? tFields : undefined;
 }

 // Derive inputs from flowType if not set
 if (ex.giftConfig && ex.giftConfig.flowType && !ex.giftConfig.inputs) {
   if (ex.giftConfig.flowType === 'transform')
     ex.giftConfig.inputs = [{type:'photo', label:'Upload your photo', required:true}];
   else if (ex.giftConfig.flowType === 'overlay')
     ex.giftConfig.inputs = [{type:'text', label:'Your personalisation', required:true}];
   else if (ex.giftConfig.flowType === 'template')
     ex.giftConfig.inputs = (ex.giftConfig.templateFields||[]).map(function(tf){
       return {type:'text', label:tf.label, placeholder:tf.placeholder, required:tf.required};
     });
 }
 // Gift production config
 var gcMethodEl = document.getElementById('adm-gc-method');
 if (gcMethodEl) {
   if (!ex.giftConfig) ex.giftConfig = {};
   ex.giftConfig.method = gcMethodEl.value || undefined;

   // Style options
   var styleRows = document.querySelectorAll('#adm-gc-style-rows > div[id^="adm-gc-style-"]');
   var styles = [];
   styleRows.forEach(function(row, si) {
     var lbl  = (row.querySelector('.adm-gc-style-label')  || {}).value || '';
     var prm  = (row.querySelector('.adm-gc-style-prompt') || {}).value || '';
     var desc = (row.querySelector('.adm-gc-style-desc')   || {}).value || '';
     if (lbl || prm) styles.push({ label:lbl, prompt:prm, description:desc||undefined });
   });
   ex.giftConfig.styleOptions = styles.length ? styles : undefined;

   // Text layers
   var tlRows = document.querySelectorAll('#adm-gc-tl-rows > div[id^="adm-gc-tl-"]');
   var tls = [];
   tlRows.forEach(function(row, li) {
     var g   = function(cls){ var e=row.querySelector('.'+cls+'[data-li="'+li+'"]'); return e?e.value:''; };
     var gN  = function(cls){ return parseFloat(g(cls))||0; };
     var gCk = function(cls){ var e=row.querySelector('.'+cls+'[data-li="'+li+'"]'); return e?e.checked:false; };
     var lbl = g('adm-gc-tl-label') || 'Text';
     tls.push({ label:lbl, placeholder:g('adm-gc-tl-ph'),
       x:Math.max(1,Math.min(99,gN('adm-gc-tl-x')||50)), y:Math.max(1,Math.min(99,gN('adm-gc-tl-y')||50)),
       fontSize:Math.max(8,gN('adm-gc-tl-fs')||20), color:g('adm-gc-tl-color')||'#ffffff',
       fontStyle:g('adm-gc-tl-font')||'Georgia, serif', align:g('adm-gc-tl-align')||'center',
       canMove:gCk('adm-gc-tl-canmove'), required:gCk('adm-gc-tl-req') });
   });
   ex.giftConfig.textLayers = tls.length ? tls : undefined;

   // Customer inputs
   var inputRows = document.querySelectorAll('#adm-gc-input-rows > div');
   var inputs = [];
   inputRows.forEach(function(row, ii) {
     var type = (row.querySelector('.adm-gc-inp-type[data-ii="'+ii+'"]')||{}).value||'text';
     var lbl  = (row.querySelector('.adm-gc-inp-label[data-ii="'+ii+'"]')||{}).value||'';
     var ph   = (row.querySelector('.adm-gc-inp-ph[data-ii="'+ii+'"]')||{}).value||'';
     var req  = (row.querySelector('.adm-gc-inp-req[data-ii="'+ii+'"]')||{}).checked||false;
     if (lbl) inputs.push({ type:type, label:lbl, placeholder:ph||undefined, required:req });
   });
   ex.giftConfig.inputs = inputs.length ? inputs : undefined;

   // Clean up if method cleared
   if (!ex.giftConfig.method && !styles.length && !tls.length && !inputs.length) {
     ex.giftConfig = undefined;
   }
 }

 // Personalisation
 if (GIFT_PERSONALISATION && GIFT_PERSONALISATION[slug]) {
 var types = document.querySelectorAll('#adm-prod-editor .adm-pers-type');
 var lbls = document.querySelectorAll('#adm-prod-editor .adm-pers-lbl');
 var phs = document.querySelectorAll('#adm-prod-editor .adm-pers-ph');
 var reqs = document.querySelectorAll('#adm-prod-editor .adm-pers-req');
 var pers = [];
 types.forEach(function(t, i) {
 pers.push({type:t.value, label:lbls[i]?lbls[i].value:'', placeholder:phs[i]?phs[i].value:'', required:reqs[i]?reqs[i].value==='true':false});
 });
 GIFT_PERSONALISATION[slug] = pers;
 }

 // Re-render product page if currently open
 var ps = document.getElementById('screen-product');
 if (ps && ps.classList.contains('active')) renderProductPage(slug, p);

 // Persist to localStorage so edits survive page reload
 try {
   var _extra = {}; Object.keys(PP_EXTRA).forEach(function(s){ _extra[s]=PP_EXTRA[s]; });
   localStorage.setItem('pv_pp_extra', JSON.stringify(_extra));
 } catch(e) {}
 try {
   var _ovr = {}; Object.keys(PRODUCTS_DATA).forEach(function(s){
     var p=PRODUCTS_DATA[s];
     _ovr[s]={name:p.name,type:p.type,tagline:p.tagline,description:p.description,
       pricing:p.pricing?JSON.parse(JSON.stringify(p.pricing)):undefined};
   });
   localStorage.setItem('pv_prod_overrides', JSON.stringify(_ovr));
 } catch(e) {}
 ['prod-saved','prod-saved2'].forEach(function(id){ admShowSaved(id); });
}

// -- Row add/remove helpers --
function admRemPrRow(btn, ri) { PRODUCTS_DATA[admCurrentSlug].pricing.rows.splice(ri,1); admOpenProduct(admCurrentSlug); }
function admAddPrRow() { var p=PRODUCTS_DATA[admCurrentSlug]; p.pricing.rows.push({qty:'New qty',prices:p.pricing.configs.map(function(){return 0;})}); admOpenProduct(admCurrentSlug); }
function admAddPrCol() {
 var p = PRODUCTS_DATA[admCurrentSlug];
 p.pricing.configs.push('New Column');
 p.pricing.rows.forEach(function(row){ row.prices.push(0); });
 admOpenProduct(admCurrentSlug);
}
function admRemPrCol(ci) {
 var p = PRODUCTS_DATA[admCurrentSlug];
 if (p.pricing.configs.length <= 1) { alert('Need at least one column.'); return; }
 p.pricing.configs.splice(ci, 1);
 p.pricing.rows.forEach(function(row){ row.prices.splice(ci, 1); });
 admOpenProduct(admCurrentSlug);
}
function admRemSpec(btn,i) { PRODUCTS_DATA[admCurrentSlug].specs.splice(i,1); admOpenProduct(admCurrentSlug); }
function admAddSpec() { PRODUCTS_DATA[admCurrentSlug].specs.push({label:'Label',value:'Value'}); admOpenProduct(admCurrentSlug); }
function admRemHL(btn,i) { PRODUCTS_DATA[admCurrentSlug].highlights.splice(i,1); admOpenProduct(admCurrentSlug); }
function admAddHL() { PRODUCTS_DATA[admCurrentSlug].highlights.push('New benefit'); admOpenProduct(admCurrentSlug); }
function admRemChip(btn,i) { var ex=PP_EXTRA[admCurrentSlug]; if(ex&&ex.chips) ex.chips.splice(i,1); admOpenProduct(admCurrentSlug); }
function admAddChip() { var ex=PP_EXTRA[admCurrentSlug]||(PP_EXTRA[admCurrentSlug]={}); if(!ex.chips)ex.chips=[]; ex.chips.push('✨ New chip'); admOpenProduct(admCurrentSlug); }
function admRemUseCase(btn,i) { var ex=PP_EXTRA[admCurrentSlug]; if(ex&&ex.useCases) ex.useCases.splice(i,1); admOpenProduct(admCurrentSlug); }
function admAddUseCase() { var ex=PP_EXTRA[admCurrentSlug]||(PP_EXTRA[admCurrentSlug]={}); if(!ex.useCases)ex.useCases=[]; ex.useCases.push({title:'New Use Case',desc:'Describe who orders this and why',img:''}); admOpenProduct(admCurrentSlug); }
function admUcImgPreview(inp, i) {
  var url = inp.value.trim();
  // Convert Dropbox share links to direct
  url = url.replace('www.dropbox.com','dl.dropboxusercontent.com').replace('?dl=0','').replace('?dl=1','');
  var row = inp.closest('[style*="border:1px solid #e0e0e0;padding:10px"]');
  if (!row) return;
  var preview = row.querySelector('div[style*="width:64px;height:64px"]');
  if (preview) preview.innerHTML = url ? '<img src="'+url+'" style="width:64px;height:64px;object-fit:cover;border-radius:4px" onerror="this.parentNode.innerHTML=\'<span style=&quot;font-size:10px;color:#e44&quot;>Bad URL</span>\'">' : '<span style="font-size:10px;color:#aaa;text-align:center">No image</span>';
}
function admRemCfgOpt(si,oi) { var cfg=CONFIGURATOR[admCurrentSlug]; if(cfg&&cfg.steps[si]&&cfg.steps[si].options) cfg.steps[si].options.splice(oi,1); admOpenProduct(admCurrentSlug); }
function admAddCfgOpt(si) { var cfg=CONFIGURATOR[admCurrentSlug]; if(cfg&&cfg.steps[si]) { if(!cfg.steps[si].options)cfg.steps[si].options=[]; cfg.steps[si].options.push({slug:'new-option',label:'New Option',price_formula:'0'}); admOpenProduct(admCurrentSlug); } }
function admAddCfgStep() {
 var cfg=CONFIGURATOR[admCurrentSlug];
 if(!cfg){CONFIGURATOR[admCurrentSlug]={steps:[]};cfg=CONFIGURATOR[admCurrentSlug];}
 if(!cfg.steps) cfg.steps=[];
 var type=(document.getElementById('adm-new-step-type')||{}).value||'select';
 var label=(document.getElementById('adm-new-step-label')||{}).value||'New Step';
 var newStep={id:label.toLowerCase().replace(/\s+/g,'-'),label:label,type:type,required:true,options:[]};
 if(type==='qty') newStep={id:'qty',label:'Quantity',type:'qty',min:1,step:1,presets:[50,100,250,500]};
 if(type==='text') newStep.placeholder='Enter '+label;
 cfg.steps.push(newStep);
 admOpenProduct(admCurrentSlug);
}
function admMoveCfgStep(si, dir) {
  var cfg = CONFIGURATOR[admCurrentSlug];
  if (!cfg || !cfg.steps) return;
  var steps = cfg.steps;
  var newIdx = si + dir;
  if (newIdx < 0 || newIdx >= steps.length) return;
  // Don't move qty step — it's always conceptually "the qty"
  if (steps[si].type === 'qty' || steps[newIdx].type === 'qty') return;
  var tmp = steps[si];
  steps[si] = steps[newIdx];
  steps[newIdx] = tmp;
  admOpenProduct(admCurrentSlug);
}
function admRemCfgStep(si) {
 var cfg=CONFIGURATOR[admCurrentSlug];
 if(cfg&&cfg.steps) cfg.steps.splice(si,1);
 admOpenProduct(admCurrentSlug);
}
function admRemWhy(btn,i) { var ex=PP_EXTRA[admCurrentSlug]; if(ex&&ex.whyUs) ex.whyUs.splice(i,1); admOpenProduct(admCurrentSlug); }
function admAddWhy() { var ex=PP_EXTRA[admCurrentSlug]||(PP_EXTRA[admCurrentSlug]={}); if(!ex.whyUs)ex.whyUs=[]; ex.whyUs.push('New point'); admOpenProduct(admCurrentSlug); }
function admRemProdFaq(btn,i) { var ex=PP_EXTRA[admCurrentSlug]; if(ex&&ex.faq) ex.faq.splice(i,1); admOpenProduct(admCurrentSlug); }
function admAddProdFaq() { var ex=PP_EXTRA[admCurrentSlug]||(PP_EXTRA[admCurrentSlug]={}); if(!ex.faq)ex.faq=[]; ex.faq.push(['Question?','Answer.']); admOpenProduct(admCurrentSlug); }
function admRemPers(btn,i) { if(GIFT_PERSONALISATION&&GIFT_PERSONALISATION[admCurrentSlug]) GIFT_PERSONALISATION[admCurrentSlug].splice(i,1); admOpenProduct(admCurrentSlug); }
function admAddPers() { if(!GIFT_PERSONALISATION[admCurrentSlug])GIFT_PERSONALISATION[admCurrentSlug]=[]; GIFT_PERSONALISATION[admCurrentSlug].push({type:'text',label:'New Field',placeholder:'',required:false}); admOpenProduct(admCurrentSlug); }

