// ==== ORDERS ====

function admLoadOrders() {
 var allOrders = [];
 try { allOrders = JSON.parse(localStorage.getItem('pv_orders')) || []; } catch(e) {}

 // Apply filters
 var q = (document.getElementById('ord-search') || {}).value || '';
 var statusFilter = (document.getElementById('ord-status') || {}).value || '';
 var orders = allOrders.filter(function(o) {
  var matchQ = !q || (o.id||'').toLowerCase().includes(q.toLowerCase()) || (o.customer||'').toLowerCase().includes(q.toLowerCase()) || (o.email||'').toLowerCase().includes(q.toLowerCase());
  var matchS = !statusFilter || o.status === statusFilter;
  return matchQ && matchS;
 });

 var body = document.getElementById('adm-ord-body');
 if (!body) return;

 // Update dashboard stats from ALL orders
 var dsOrders = document.getElementById('ds-orders');
 var dsPending = document.getElementById('ds-pending');
 var dsRev = document.getElementById('ds-rev');
 if (dsOrders) dsOrders.textContent = allOrders.length;
 if (dsPending) dsPending.textContent = allOrders.filter(function(o){ return o.status === 'Pending'; }).length;
 var rev = allOrders.reduce(function(s,o){ return s + (parseFloat(o.total)||0); }, 0);
 if (dsRev) dsRev.textContent = 'S$'+ rev.toFixed(0);

 if (!orders.length) {
  body.innerHTML = '<div style="padding:48px;text-align:center;color:#aaa;font-size:13px">'+ (q||statusFilter ? 'No orders match your filter.' : 'No orders yet.') +'</div>';
  return;
 }

 var SC = {Pending:'#f59e0b',Processing:'#3b82f6',Ready:'#8b5cf6',Completed:'#22c55e'};
 var html = '';
 orders.forEach(function(o) {
  var badge = {Pending:'pending',Processing:'processing',Ready:'ready',Completed:'completed'}[o.status] || 'pending';
  var itemSummary = (o.items && o.items.length)
   ? o.items.slice(0,2).map(function(i){ return (i.product||i.name||'Item') + (i.qty>1?' ×'+i.qty:''); }).join(' · ') + (o.items.length > 2 ? ' +' + (o.items.length-2) : '')
   : '—';
  var isGiftOrder = o.orderType === 'gift' || (o.items||[]).some(function(it){ return it.productType==='gift'; });
  var typePill = isGiftOrder
   ? '<span style="font-size:9px;background:#fff0f7;color:#E91E8C;border:1px solid #fcd;padding:1px 6px;border-radius:10px;font-weight:700;margin-left:5px">Gift</span>'
   : '';
  html += '<div class="adm-order-row" onclick="admViewOrder(\''+ o.id +'\')">'+
   '<div class="adm-ord-left">'+
    '<div class="adm-ord-id">#'+ (o.id||'—') + typePill +'</div>'+
    '<div class="adm-ord-name">'+ (o.customer||'—') +'</div>'+
    '<div class="adm-ord-sub">'+ (o.email||'') + (o.phone ? ' · '+ o.phone : '') +'</div>'+
    '<div class="adm-ord-items">'+ itemSummary +'</div>'+
   '</div>'+
   '<div class="adm-ord-right">'+
    '<div class="adm-ord-total">S$'+ parseFloat(o.total||0).toFixed(2) +'</div>'+
    '<span class="adm-badge '+ badge +'">'+ (o.status||'Pending') +'</span>'+
    '<div class="adm-ord-actions" onclick="event.stopPropagation()">'+
     '<select onchange="admChangeStatus(\''+ o.id +'\',this.value)" style="font-size:11px;padding:4px 6px;border:1px solid #e0e0e0;background:#fff;font-family:var(--sans)">'+
      ['Pending','Processing','Ready','Completed'].map(function(s){ return '<option'+(o.status===s?' selected':'')+'>'+s+'</option>'; }).join('')+
     '</select>'+
    '</div>'+
   '</div>'+
  '</div>';
 });
 body.innerHTML = html;
}

function admOrdFilter() { admLoadOrders(); }

function admChangeStatus(id, newStatus) {
 var orders = [];
 try { orders = JSON.parse(localStorage.getItem('pv_orders')) || []; } catch(e) {}
 var o = orders.find(function(x){ return x.id === id; });
 if (o) { o.status = newStatus; localStorage.setItem('pv_orders', JSON.stringify(orders)); }
 admLoadOrders();
 showToast('Order '+ id +' → '+ newStatus);
}

function admViewOrder(id) {
 var orders = [];
 try { orders = JSON.parse(localStorage.getItem('pv_orders')) || []; } catch(e) {}
 var o = orders.find(function(x){ return x.id === id; });
 if (!o) return;
 var items = (o.items||[]).map(function(i){
  var giftThumb = i.giftImage
    ? '<img src="'+i.giftImage+'" style="width:40px;height:40px;object-fit:cover;border-radius:3px;border:1px solid #eee;margin-right:8px;vertical-align:middle;flex-shrink:0">'
    : '';
  var nameCell = giftThumb
    ? '<td style="padding:6px 10px;border-bottom:1px solid #f0f0f0"><div style="display:flex;align-items:center">'+ giftThumb +'<span>'+(i.icon||'')+' '+(i.product||i.name||'Item')+'</span></div>'+(i.notes?'<div style="font-size:11px;color:#888;margin-top:3px;padding-left:48px">'+i.notes+'</div>':'')+'</td>'
    : '<td style="padding:6px 10px;border-bottom:1px solid #f0f0f0">'+(i.icon||'')+' '+(i.product||i.name||'Item')+(i.notes?'<div style="font-size:11px;color:#888;margin-top:2px">'+i.notes+'</div>':'')+'</td>';
  return nameCell +
   '<td style="padding:6px 10px;border-bottom:1px solid #f0f0f0;color:#888;font-size:12px">'+ (i.config||'') +'</td>'+
   '<td style="padding:6px 10px;border-bottom:1px solid #f0f0f0;font-weight:700;text-align:right">S$'+ parseFloat(i.price||0).toFixed(2) +'</td></tr>';
 }).join('');
 var modal = document.getElementById('adm-order-modal');
 var content = document.getElementById('adm-order-modal-body');
 if (!modal || !content) {
  // Create modal if not exists
  var m = document.createElement('div');
  m.id = 'adm-order-modal';
  m.style.cssText = 'display:none;position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999;align-items:center;justify-content:center;padding:20px';
  m.innerHTML = '<div style="background:#fff;max-width:600px;width:100%;max-height:90vh;overflow-y:auto;padding:28px;position:relative">'+
   '<button onclick="document.getElementById(\'adm-order-modal\').style.display=\'none\'" style="position:absolute;top:16px;right:16px;background:none;border:none;font-size:20px;cursor:pointer;color:#888">&#215;</button>'+
   '<div id="adm-order-modal-body"></div>'+
  '</div>';
  document.body.appendChild(m);
  modal = m;
  content = m.querySelector('#adm-order-modal-body');
 }
 content.innerHTML =
  '<div style="font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:1.5px;color:#E91E8C;margin-bottom:6px">Order Details</div>'+
  '<div style="font-family:var(--serif);font-size:24px;font-weight:700;margin-bottom:16px">'+ o.id +'</div>'+
  '<div style="display:grid;grid-template-columns:minmax(0,1fr) minmax(0,1fr);gap:8px;margin-bottom:20px;font-size:13px">'+
   '<div><span style="color:#aaa;font-size:10px;text-transform:uppercase;letter-spacing:.5px;display:block">Customer</span><strong>'+ (o.customer||'—') +'</strong></div>'+
   '<div><span style="color:#aaa;font-size:10px;text-transform:uppercase;letter-spacing:.5px;display:block">Email</span>'+ (o.email||'—') +'</div>'+
   '<div><span style="color:#aaa;font-size:10px;text-transform:uppercase;letter-spacing:.5px;display:block">Phone</span>'+ (o.phone||'—') +'</div>'+
   '<div><span style="color:#aaa;font-size:10px;text-transform:uppercase;letter-spacing:.5px;display:block">Collection</span>'+ (o.method||'—') +'</div>'+
   (o.company ? '<div><span style="color:#aaa;font-size:10px;text-transform:uppercase;letter-spacing:.5px;display:block">Company</span>'+ o.company +'</div>' : '')+
   '<div><span style="color:#aaa;font-size:10px;text-transform:uppercase;letter-spacing:.5px;display:block">Date</span>'+ (o.createdAt||'—') +'</div>'+
   (o.notes ? '<div style="grid-column:1/-1"><span style="color:#aaa;font-size:10px;text-transform:uppercase;letter-spacing:.5px;display:block">Notes</span>'+ o.notes +'</div>' : '')+
  '</div>'+
  '<table style="width:100%;border-collapse:collapse;margin-bottom:16px">'+
   '<thead><tr style="background:#f5f5f5"><th style="padding:8px 10px;text-align:left;font-size:11px;text-transform:uppercase;letter-spacing:.5px">Product</th><th style="padding:8px 10px;text-align:left;font-size:11px;text-transform:uppercase;letter-spacing:.5px">Spec</th><th style="padding:8px 10px;text-align:right;font-size:11px;text-transform:uppercase;letter-spacing:.5px">Price</th></tr></thead>'+
   '<tbody>'+ items +'</tbody>'+
  '</table>'+
  // Gift images section
  (function(){
    var imgs = (o.items||[]).filter(function(it){ return it.giftImage || (it.giftSides && it.giftSides.length); });
    // PDF download buttons per gift item
    var pdfBtns = imgs.map(function(it){
      var iidx = (o.items||[]).indexOf(it);
      return '<button onclick="admDownloadGiftPdf(\'' + o.id + '\',' + iidx + ')" style="display:inline-flex;align-items:center;gap:5px;padding:7px 14px;font-size:12px;font-weight:700;background:#f0f4ff;border:1.5px solid #c7d7fd;color:#3b5bdb;cursor:pointer;font-family:var(--sans);border-radius:4px;margin:3px">&#128196; Download PDF — ' + (it.product||'Gift') + '</button>';
    }).join('');
    if (!imgs.length) return '';
    return '<div style="margin-bottom:16px"><div style="font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:.5px;color:#555;margin-bottom:8px">Approved Images</div>'+
      '<div style="display:flex;gap:8px;flex-wrap:wrap">' +
      imgs.map(function(it){
        if (it.giftSides && it.giftSides.length > 1) {
          return it.giftSides.map(function(s){
            return s.image ? '<div style="text-align:center"><img src="'+s.image+'" style="width:72px;height:72px;object-fit:cover;border-radius:3px;border:1px solid #eee;display:block"><div style="font-size:9px;color:#aaa;margin-top:2px">'+it.product+' · '+s.name+'</div></div>' : '';
          }).join('');
        }
        return it.giftImage ? '<div style="text-align:center"><img src="'+it.giftImage+'" style="width:80px;height:80px;object-fit:cover;border-radius:3px;border:1px solid #eee;display:block"><div style="font-size:10px;color:#aaa;margin-top:3px">'+it.product+'</div></div>' : '';
      }).join('') +
      (pdfBtns ? '<div style="margin-top:12px;border-top:1px solid #f0f0f0;padding-top:10px">' + pdfBtns + '</div>' : '') +
      '</div></div>';
  })()+
  '<div style="display:flex;justify-content:space-between;align-items:center;border-top:2px solid #0a0a0a;padding-top:12px">'+
   '<div style="font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.5px">Total</div>'+
   '<div style="font-size:24px;font-weight:800;color:#E91E8C">S$'+ parseFloat(o.total||0).toFixed(2) +'</div>'+
  '</div>'+
  '<div style="margin-top:16px;display:flex;gap:8px;flex-wrap:wrap">'+
   '<a href="https://wa.me/'+ (o.phone||'').replace(/[^0-9]/g,'') +'" target="_blank" style="background:#25D366;color:#fff;border:none;padding:10px 16px;font-size:13px;font-weight:700;cursor:pointer;font-family:var(--sans);text-decoration:none;display:inline-block">&#128172; WhatsApp Customer</a>'+
   '<select onchange="admChangeStatus(\''+ o.id +'\',this.value)" style="border:1px solid #e0e0e0;padding:10px 12px;font-size:13px;font-family:var(--sans);background:#fff;cursor:pointer">'+
    ['Pending','Processing','Ready','Completed'].map(function(s){ return '<option'+(o.status===s?' selected':'')+'>'+s+'</option>'; }).join('')+
   '</select>'+
  '</div>';
 modal.style.display = 'flex';
}

// ==== SEO ====

function admBuildSeoList(filter) {
 var list = document.getElementById('adm-seo-list');
 if (!list) return;
 var html = '';
 Object.keys(PRODUCTS_DATA).forEach(function(slug) {
 var p = PRODUCTS_DATA[slug];
 if (!filter || p.name.toLowerCase().includes(filter.toLowerCase())) {
 var on = slug === admSeoSlug ? 'on': '';
 html += '<div class="adm-prod-item '+ on + '" data-slug="'+ slug + '" onclick="admOpenSeo(this.dataset.slug)">'+
  '<div><div>'+ p.name + '</div></div>'+
 '</div>';
 }
 });
 list.innerHTML = html;
}

function admSeoSearch(q) { admBuildSeoList(q); }

function admOpenSeo(slug) {
 admSeoSlug = slug;
 admBuildSeoList(document.querySelector('#adm-pane-seo .adm-search-input') ? document.querySelector('#adm-pane-seo .adm-search-input').value : '');
 var p = PRODUCTS_DATA[slug];
 var ex = PP_EXTRA[slug] || {};
 var panel = document.getElementById('adm-seo-panel');
 if (!panel) return;

 panel.innerHTML = '<div class="adm-card">'+
 '<div style="font-weight:800;font-size:15px;margin-bottom:20px">'+ p.icon + ''+ p.name + '— SEO</div>'+
 '<div class="adm-fl"><label>Google Title <span style="font-weight:400;color:#aaa;font-size:10px">(aim for under 60 characters)</span></label>'+
 '<input id="seo-title" value="'+ (ex.seoTitle||'').replace(/"/g,'&quot;') + '" oninput="admSeoPreview()">'+
 '<div class="adm-char-count" id="seo-tc">0 / 60</div>'+
 '</div>'+
 '<div class="adm-fl"><label>Google Description <span style="font-weight:400;color:#aaa;font-size:10px">(aim for 150-160 characters)</span></label>'+
 '<textarea id="seo-desc" oninput="admSeoPreview()">'+ (ex.seoDesc||'') + '</textarea>'+
 '<div class="adm-char-count" id="seo-dc">0 / 160</div>'+
 '</div>'+
 '<div class="adm-fl"><label>Page Main Heading (H1)</label><input id="seo-h1" value="'+ (ex.h1||'').replace(/"/g,'&quot;') + '"></div>'+
 '<div class="adm-fl"><label>Intro Paragraph</label><textarea id="seo-intro" style="min-height:100px">'+ (ex.intro||'') + '</textarea></div>'+
 '<div class="adm-seo-preview">'+
 '<div style="font-size:11px;font-weight:700;color:#888;margin-bottom:8px;text-transform:uppercase;letter-spacing:.5px">Google Preview</div>'+
 '<div class="seo-title" id="seo-prev-title">'+ (ex.seoTitle||p.name) + '</div>'+
 '<div class="seo-url">printvolution.sg › '+ slug + '</div>'+
 '<div class="seo-desc" id="seo-prev-desc">'+ (ex.seoDesc||'') + '</div>'+
 '</div>'+
 '<div style="margin-top:16px;display:flex;gap:10px;align-items:center">'+
 '<button class="adm-save-btn pink" onclick="admSeoSave()">Save SEO</button>'+
 '<span class="adm-saved" id="seo-saved">&#10003; Saved</span>'+
 '</div>'+
 '</div>';

 admSeoPreview();
}

function admSeoPreview() {
 var t = document.getElementById('seo-title');
 var d = document.getElementById('seo-desc');
 var pt = document.getElementById('seo-prev-title');
 var pd = document.getElementById('seo-prev-desc');
 var tc = document.getElementById('seo-tc');
 var dc = document.getElementById('seo-dc');
 if (t && pt) pt.textContent = t.value || '—';
 if (d && pd) pd.textContent = d.value ? d.value.substring(0,160) : '—';
 if (t && tc) { tc.textContent = t.value.length + '/ 60'; tc.className = 'adm-char-count'+ (t.value.length > 60 ? 'over': ''); }
 if (d && dc) { dc.textContent = d.value.length + '/ 160'; dc.className = 'adm-char-count'+ (d.value.length > 160 ? 'over': ''); }
}

function admSeoSave() {
 if (!admSeoSlug) return;
 var ex = PP_EXTRA[admSeoSlug] || (PP_EXTRA[admSeoSlug] = {});
 var t = document.getElementById('seo-title');
 var d = document.getElementById('seo-desc');
 var h = document.getElementById('seo-h1');
 var i = document.getElementById('seo-intro');
 if (t) ex.seoTitle = t.value;
 if (d) ex.seoDesc = d.value;
 if (h) ex.h1 = h.value;
 if (i) ex.intro = i.value;
 admShowSaved('seo-saved');
}

