// ════ TEMPLATE PRINT SETUP ═══════════════════════════════════════════════════
var _tplPrintConfig = {
  unit: 'mm',
  w: 0, h: 0,        // finished size in chosen unit
  bleed: 0,          // bleed in mm
  safe: 3,           // safe zone in mm
  showGuides: true,
  allowedFonts: []   // array of font IDs; empty = all fonts allowed
};


function admTplRenderAllowedFonts() {
  var container = document.getElementById('tpl-allowed-fonts');
  if (!container) return;
  if (!_customFonts.length) {
    container.innerHTML = '<div style="font-size:11px;color:#aaa">No custom fonts uploaded yet — add them in <strong>Settings → Custom Fonts</strong>.</div>';
    return;
  }
  var allowed = (_tplPrintConfig && _tplPrintConfig.allowedFonts) || [];
  container.innerHTML = _customFonts.map(function(f) {
    var checked = allowed.length === 0 || allowed.indexOf(f.id) > -1;
    return '<label style="display:flex;align-items:center;gap:8px;margin-bottom:6px;cursor:pointer">' +
      '<input type="checkbox" value="'+f.id+'" '+(checked?'checked':'')+' onchange="admTplUpdateAllowedFonts()" style="width:13px;height:13px;accent-color:#E91E8C">' +
      '<span style="font-size:13px;font-family:\''+f.family+'\',sans-serif;color:#0a0a0a">'+f.family+'</span>' +
      '<span style="font-size:10px;color:#9ca3af">('+f.size+'KB)</span>' +
    '</label>';
  }).join('');
}

function admTplUpdateAllowedFonts() {
  var container = document.getElementById('tpl-allowed-fonts');
  if (!container) return;
  var checked = Array.prototype.slice.call(container.querySelectorAll('input[type=checkbox]:checked'));
  _tplPrintConfig.allowedFonts = checked.map(function(el){ return el.value; });
  // Rebuild the field font picker to show only allowed fonts
  admTplRebuildFontPicker(_tplPrintConfig.allowedFonts.length ? _tplPrintConfig.allowedFonts : null);
  var dot = document.getElementById('tpl-status-dot');
  if (dot) dot.style.background = '#f59e0b';
}

function admTplTogglePrintSetup() {
  var panel = document.getElementById('tpl-print-setup');
  var arr   = document.getElementById('tpl-print-arr');
  if (!panel) return;
  var isOpen = panel.style.display !== 'none';
  panel.style.display = isOpen ? 'none' : '';
  if (arr) arr.style.transform = isOpen ? '' : 'rotate(180deg)';
}

function admTplSetUnit(unit) {
  var prev = _tplPrintConfig.unit;
  _tplPrintConfig.unit = unit;
  // Convert existing values if they have content
  var wEl = document.getElementById('tpl-dim-w');
  var hEl = document.getElementById('tpl-dim-h');
  if (wEl && hEl && parseFloat(wEl.value) && parseFloat(hEl.value)) {
    var w = parseFloat(wEl.value), h = parseFloat(hEl.value);
    // Convert from prev to new unit via mm
    var toMm = prev === 'in' ? 25.4 : prev === 'px' ? 0.264583 : 1;
    var fromMm = unit === 'in' ? 1/25.4 : unit === 'px' ? 3.7795 : 1;
    wEl.value = Math.round(w * toMm * fromMm * 100) / 100;
    hEl.value = Math.round(h * toMm * fromMm * 100) / 100;
  }
  ['mm','in','px'].forEach(function(u) {
    var btn = document.getElementById('tpl-unit-'+u);
    if (!btn) return;
    btn.style.background = u === unit ? '#0a0a0a' : '#f0f0f0';
    btn.style.color      = u === unit ? '#fff'    : '#888';
  });
  var unitLabels = document.querySelectorAll('#tpl-dim-unit,#tpl-safe-unit');
  unitLabels.forEach(function(el) {
    if (el.id === 'tpl-safe-unit') el.textContent = unit + ' from trim';
    else el.textContent = unit;
  });
  admTplUpdatePrintSetup();
}

function admTplSetBleed(mm) {
  _tplPrintConfig.bleed = mm;
  [0,1,2,3,5].forEach(function(v) {
    var btn = document.getElementById('tpl-bleed-'+v);
    if (!btn) return;
    btn.style.background = v === mm ? '#E91E8C' : '#f0f0f0';
    btn.style.color      = v === mm ? '#fff'    : '#888';
  });
  var note = document.getElementById('tpl-bleed-note');
  if (note) {
    if (mm === 0) note.textContent = 'No bleed — artwork fills to the trim line exactly.';
    else note.textContent = mm+'mm bleed on all sides. Tell customers their artwork must extend '+mm+'mm beyond the trim line.';
  }
  admTplUpdatePrintSetup();
  admTplDraw();
}

function admTplUpdatePrintSetup() {
  var wEl = document.getElementById('tpl-dim-w');
  var hEl = document.getElementById('tpl-dim-h');
  var safeEl = document.getElementById('tpl-safe');
  if (!wEl || !hEl) return;
  _tplPrintConfig.w = parseFloat(wEl.value) || 0;
  _tplPrintConfig.h = parseFloat(hEl.value) || 0;
  _tplPrintConfig.safe = parseFloat((safeEl||{}).value) || 3;
  var guidesCk = document.getElementById('tpl-show-guides');
  _tplPrintConfig.showGuides = guidesCk ? guidesCk.checked : true;

  // Update summary in toggle button
  var summary = document.getElementById('tpl-print-summary');
  var info    = document.getElementById('tpl-size-info');
  var u = _tplPrintConfig.unit;
  if (_tplPrintConfig.w && _tplPrintConfig.h) {
    var bleedTotal = _tplPrintConfig.bleed;
    var toMm = u === 'in' ? 25.4 : u === 'px' ? 0.264583 : 1;
    var wMm = _tplPrintConfig.w * toMm, hMm = _tplPrintConfig.h * toMm;
    var docW = (wMm + bleedTotal*2).toFixed(1);
    var docH = (hMm + bleedTotal*2).toFixed(1);
    if (summary) summary.textContent = _tplPrintConfig.w+'\xd7'+_tplPrintConfig.h+u + (bleedTotal ? ' + '+bleedTotal+'mm bleed' : ' no bleed');
    if (info) {
      info.style.display = '';
      info.innerHTML =
        '<strong>Finished (trim):</strong> '+_tplPrintConfig.w+'\xd7'+_tplPrintConfig.h+u+'<br>'+
        (bleedTotal ? '<strong>With bleed (document):</strong> '+docW+'\xd7'+docH+'mm<br>' : '')+
        '<strong>Safe zone:</strong> '+_tplPrintConfig.safe+u+' from trim<br>'+
        '<span style="color:#E91E8C;font-weight:700">Template image should match the document size ('+
        (bleedTotal ? docW+'\xd7'+docH+'mm including bleed' : _tplPrintConfig.w+'\xd7'+_tplPrintConfig.h+u)+
        ').</span>';
    }
  } else {
    if (summary) summary.textContent = 'Tap to configure dimensions \u0026 bleed';
    if (info) info.style.display = 'none';
  }

  // Update canvas hint to show dimension info
  var hint = document.getElementById('tpl-canvas-hint');
  if (hint && _tplPrintConfig.w && _tplPrintConfig.h) {
    var bleedNote = _tplPrintConfig.bleed > 0 ? ' + ' + _tplPrintConfig.bleed + 'mm bleed' : '';
    hint.textContent = 'Canvas ratio matches ' + _tplPrintConfig.w + '×' + _tplPrintConfig.h + _tplPrintConfig.unit + bleedNote + ' — upload your template image, then click to place fields';
    hint.style.color = '#4ade80';
    hint.style.fontWeight = '600';
  }

  // Mark unsaved
  var dot = document.getElementById('tpl-status-dot');
  if (dot) dot.style.background = '#f59e0b';

  admTplDraw();
  // Deferred second draw: colW from offsetWidth may be stale on first call
  // (layout hasn't reflowed yet when oninput fires during typing)
  setTimeout(admTplDraw, 60);
}

function admTplLoadPrintConfig(cfg) {
  if (!cfg) return;
  _tplPrintConfig = Object.assign({unit:'mm',w:0,h:0,bleed:0,safe:3,showGuides:true,allowedFonts:[]}, cfg);
  // Render allowed fonts checkboxes
  admTplRenderAllowedFonts();
  // Populate UI
  var sv = function(id,v){ var e=document.getElementById(id); if(e) e.value=v; };
  sv('tpl-dim-w', _tplPrintConfig.w || '');
  sv('tpl-dim-h', _tplPrintConfig.h || '');
  sv('tpl-safe',  _tplPrintConfig.safe || 3);
  admTplSetUnit(_tplPrintConfig.unit || 'mm');
  admTplSetBleed(_tplPrintConfig.bleed || 0);
  var guidesCk = document.getElementById('tpl-show-guides');
  if (guidesCk) guidesCk.checked = _tplPrintConfig.showGuides !== false;
  admTplUpdatePrintSetup();
}

function admTplRenderSideTabs() {
  var bar = document.getElementById('tpl-side-tabs');
  if (!bar) return;
  bar.innerHTML = _tplSides.map(function(s, si) {
    var isActive = si === _tplCurrentSide;
    return '<button onclick="admTplSwitchSide('+si+')" style="'+
      'padding:8px 14px;font-size:12px;font-weight:700;font-family:var(--sans);cursor:pointer;white-space:nowrap;'+
      'border:none;border-bottom:2px solid '+(isActive?'#E91E8C':'transparent')+';'+
      'background:transparent;color:'+(isActive?'#fff':'#555')+';'+
      'transition:all .15s;flex-shrink:0">'+
      s.name+
      (s.templateFields.length ? ' <span style="font-size:9px;background:#333;color:#aaa;padding:1px 5px;border-radius:8px;margin-left:3px">'+s.templateFields.length+'</span>' : '')+
    '</button>';
  }).join('') +
  '<button onclick="admTplAddSide()" style="padding:8px 12px;font-size:12px;font-weight:700;font-family:var(--sans);cursor:pointer;border:none;background:transparent;color:#555;flex-shrink:0" title="Add side">+</button>';
}

function admTplSwitchSide(si) {
  // Save current side first
  _tplSides[_tplCurrentSide].templateFields = _tplFields.map(function(f){ return Object.assign({},f); });
  if (_tplBaseImg && _tplBaseImg.src) _tplSides[_tplCurrentSide].mockupImage = _tplBaseImg.src;

  // Switch
  _tplCurrentSide = si;
  _tplFields = _tplSides[si].templateFields;
  _tplSelectedIdx = -1;
  _tplPendingType = null;

  // Load new side's image
  _tplBaseImg = null;
  var imgSrc = _tplSides[si].mockupImage || '';
  if (imgSrc) {
    var img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = function(){ _tplBaseImg = img; admTplDraw(); };
    img.onerror = function(){ _tplBaseImg = null; admTplDraw(); };
    img.src = imgSrc;
  } else {
    admTplDraw();
  }

  document.getElementById('tpl-field-editor').style.display = 'none';
  admTplRenderList();
  admTplRenderSideTabs();
  document.getElementById('tpl-canvas-hint').textContent =
    _tplSides[si].mockupImage
      ? 'Side: '+_tplSides[si].name+' — tap a field type to add, click canvas to place'
      : 'Upload a template image for '+_tplSides[si].name+' side';
  // Update unsaved dot
  var dot = document.getElementById('tpl-status-dot');
  if (dot) dot.style.background = '#f59e0b';
}

function admTplAddSide() {
  // Save current first
  _tplSides[_tplCurrentSide].templateFields = _tplFields.map(function(f){ return Object.assign({},f); });
  if (_tplBaseImg && _tplBaseImg.src) _tplSides[_tplCurrentSide].mockupImage = _tplBaseImg.src;

  var names = ['Front','Back','Inside','Outside','Left','Right','Sleeve','Lid','Base','Side A','Side B'];
  var usedNames = _tplSides.map(function(s){ return s.name; });
  var newName = 'Side ' + (_tplSides.length + 1);
  for (var n = 0; n < names.length; n++) {
    if (usedNames.indexOf(names[n]) === -1) { newName = names[n]; break; }
  }

  _tplSides.push({ name: newName, mockupImage: '', templateFields: [] });
  admTplSwitchSide(_tplSides.length - 1);
}

function admTplRenameSide(si, newName) {
  if (_tplSides[si]) _tplSides[si].name = newName || ('Side '+(si+1));
  admTplRenderSideTabs();
}

function admTplAddField(type) {
  _tplPendingType = type;
  // Update button states
  ['text','name','date','photo'].forEach(function(t){
    var btn = document.getElementById('tpl-add-'+t);
    if (!btn) return;
    var isActive = t === type;
    btn.style.outline = isActive ? '2px solid '+TPL_TYPE_COLOR[t] : 'none';
    btn.style.outlineOffset = '2px';
  });
  var hint = document.getElementById('tpl-canvas-hint');
  if (hint) {
    hint.textContent = '&#9997; Click on the canvas to place the ' + TPL_TYPE_LABEL[type] + ' field';
    hint.style.color = TPL_TYPE_COLOR[type];
    hint.style.fontWeight = '700';
    hint.style.background = '#0f0f0f';
  }
}

function admTplPlaceField(xPct, yPct) {
  if (!_tplPendingType) return;
  var type = _tplPendingType;
  _tplPendingType = null;
  var defaults = {
    text:  {label:'Text',      placeholder:'Enter text',       fontSize:28, color:'#1a1a1a', font:'Georgia, serif',                   align:'center', maxLength:80, required:false, w:40, h:12},
    name:  {label:'Name',      placeholder:'e.g. Sarah',       fontSize:36, color:'#1a1a1a', font:'Brush Script MT, cursive',          align:'center', maxLength:40, required:true,  w:50, h:14},
    date:  {label:'Date',      placeholder:'e.g. 14 Feb 2025', fontSize:22, color:'#555555', font:'Georgia, serif',                   align:'center', maxLength:20, required:false, w:38, h:10},
    photo: {label:'Photo Zone',placeholder:'Upload photo',      fontSize:14, color:'#888888', font:'Helvetica Neue, Arial, sans-serif', align:'center', maxLength:0,  required:false, w:80, h:80, isPhoto:true, keepRatio:true},
  };
  var field = Object.assign({ type:type, x:xPct, y:yPct }, defaults[type]);
  // Photo zones: largest square that physically fits within the template
  // zoneW_px == zoneH_px => h% = w% * (cW/cH)
  // But if h% > 90 (zone taller than template), flip: fix h=80%, derive w = h%/AR
  if (field.isPhoto) {
    var _plCanvas = document.getElementById('tpl-canvas');
    if (_plCanvas && _plCanvas.width && _plCanvas.height) {
      var _plAR = _plCanvas.width / _plCanvas.height;
      var _ph = Math.round(field.w * _plAR * 10) / 10;
      if (_ph > 85) {
        // Landscape template: fix h=80%, derive w
        _ph = 80;
        field.w = Math.max(5, Math.min(95, Math.round(_ph / _plAR * 10) / 10));
      }
      field.h = Math.max(2, Math.min(90, _ph));
    }
  }
  _tplFields.push(field);
  _tplSelectedIdx = _tplFields.length - 1;
  admTplDraw();
  admTplRenderList();
  admTplShowFieldEditor(_tplSelectedIdx);
  document.getElementById('tpl-canvas-hint').textContent = 'Drag to reposition. Click another field or add a new one.';
}

function admTplDeleteSelected() {
  if (_tplSelectedIdx < 0 || _tplSelectedIdx >= _tplFields.length) return;
  _tplFields.splice(_tplSelectedIdx, 1);
  _tplSelectedIdx = -1;
  document.getElementById('tpl-field-editor').style.display = 'none';
  admTplDraw();
  admTplRenderList();
}

function admTplUpdateSelected() {
  if (_tplSelectedIdx < 0) return;
  var f = _tplFields[_tplSelectedIdx];
  var gv = function(id){ var e=document.getElementById(id); return e?e.value:''; };
  var gn = function(id){ return parseFloat(gv(id))||0; };
  var gc2 = function(id){ var e=document.getElementById(id); return e?e.checked:false; };
  f.label       = gv('tpl-fe-label')  || f.label;
  f.placeholder = gv('tpl-fe-ph');
  f.fontSize    = gn('tpl-fe-fs')     || f.fontSize;
  f.color       = gv('tpl-fe-color')  || f.color;
  f.font        = gv('tpl-fe-font')   || f.font;
  f.align       = gv('tpl-fe-align')  || 'center';
  f.maxLength   = parseInt(gv('tpl-fe-max'))||80;
  f.w           = gn('tpl-fe-w')      || 30;
  f.h           = gn('tpl-fe-h')      || 10;
  // keepRatio: if photo and checkbox is ticked, lock h to template aspect ratio on W change
  var krEl = document.getElementById('tpl-fe-keep-ratio');
  if (krEl) f.keepRatio = krEl.checked;
  if (f.isPhoto && f.keepRatio) {
    var _krc = document.getElementById('tpl-canvas');
    if (_krc && _krc.width && _krc.height) {
      var _krAR = _krc.width / _krc.height;
      var newH = Math.round(f.w * _krAR * 10) / 10;
      if (newH > 85) {
        // Landscape: fix h=80% and derive w instead
        newH = 80;
        f.w = Math.max(5, Math.min(95, Math.round(newH / _krAR * 10) / 10));
      }
      f.h = Math.max(2, Math.min(90, newH));
      // Sync sliders
      var _hslider = document.getElementById('tpl-fe-h'); if (_hslider) _hslider.value = f.h;
      var _hnum = document.getElementById('tpl-fe-h-num'); if (_hnum) _hnum.value = f.h;
      var _hval = document.getElementById('tpl-fe-h-val'); if (_hval) _hval.textContent = Math.round(f.h) + '%';
    }
  }
  f.required    = gc2('tpl-fe-req');
  f.bold        = gc2('tpl-fe-bold');
  f.italic      = gc2('tpl-fe-italic');
  var wv = document.getElementById('tpl-fe-w-val');
  if (wv) wv.textContent = f.w+'%';
  var wn = document.getElementById('tpl-fe-w-num');
  if (wn) wn.value = f.w;
  var hv2 = document.getElementById('tpl-fe-h-val');
  if (hv2) hv2.textContent = (f.h||10)+'%';
  var hn = document.getElementById('tpl-fe-h-num');
  if (hn) hn.value = f.h||10;
  admTplUpdateFontPreview(f);
  admTplDraw();
  admTplRenderList();
  // Sync number inputs with sliders
  var wn2 = document.getElementById('tpl-fe-w-num'); if(wn2) wn2.value = f.w;
  var hn2 = document.getElementById('tpl-fe-h-num'); if(hn2) hn2.value = f.h||10;
  // Unsaved indicator
  var dot = document.getElementById('tpl-status-dot');
  if (dot) dot.style.background = '#f59e0b';
}

// ── Draw ──────────────────────────────────────────────────────────────────────
function admTplDraw() {
  var canvas = document.getElementById('tpl-canvas');
  if (!canvas) return;
  var col = document.getElementById('tpl-canvas-col');
  // On mobile the col may be the full modal width minus panel
  var colW = col ? col.offsetWidth : window.innerWidth;
  var panelW = 280; // right panel fixed width
  if (!col || colW < 50) colW = Math.max(200, window.innerWidth - panelW);
  var maxW = Math.max(200, colW - 32);

  // Determine aspect ratio: print config dimensions take priority over image natural size
  var _ratio = 0.75; // default fallback
  if (_tplPrintConfig && _tplPrintConfig.w && _tplPrintConfig.h) {
    var toMm = _tplPrintConfig.unit==='in'?25.4:_tplPrintConfig.unit==='px'?0.264583:1;
    var docWmm = _tplPrintConfig.w * toMm + (_tplPrintConfig.bleed||0) * 2;
    var docHmm = _tplPrintConfig.h * toMm + (_tplPrintConfig.bleed||0) * 2;
    _ratio = docHmm / docWmm;
  } else if (_tplBaseImg) {
    _ratio = _tplBaseImg.naturalHeight / _tplBaseImg.naturalWidth;
  }

  canvas.width  = Math.min(maxW, 1200);
  canvas.height = Math.round(canvas.width * _ratio);
  // Cap very tall canvases — use 90vh so square/portrait templates aren't over-clipped
  var maxH = window.innerHeight ? window.innerHeight * 0.88 : 700;
  if (canvas.height > maxH) {
    canvas.height = Math.round(maxH);
    canvas.width  = Math.round(canvas.height / _ratio);
  }
  canvas.style.width  = canvas.width  + 'px';
  canvas.style.height = canvas.height + 'px';

  var ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, canvas.width, canvas.height);

  if (_tplBaseImg) {
    // Cover-fit: scale image to fill canvas while preserving its own aspect ratio
    // (same as CSS object-fit:cover) — image centred, excess cropped
    var iw = _tplBaseImg.naturalWidth, ih = _tplBaseImg.naturalHeight;
    var scale = Math.max(canvas.width / iw, canvas.height / ih);
    var dw = iw * scale, dh = ih * scale;
    var dx = (canvas.width  - dw) / 2;
    var dy = (canvas.height - dh) / 2;
    ctx.drawImage(_tplBaseImg, dx, dy, dw, dh);
  } else {
    ctx.fillStyle = '#1e1e1e';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.strokeStyle = '#333';
    ctx.lineWidth = 2;
    ctx.setLineDash([8,8]);
    ctx.strokeRect(4, 4, canvas.width-8, canvas.height-8);
    ctx.setLineDash([]);
    ctx.fillStyle = '#555';
    ctx.font = '14px sans-serif';
    ctx.textAlign = 'center';
    var _dimLabel = (_tplPrintConfig && _tplPrintConfig.w && _tplPrintConfig.h)
      ? _tplPrintConfig.w + '×' + _tplPrintConfig.h + _tplPrintConfig.unit
        + (_tplPrintConfig.bleed > 0 ? ' + ' + _tplPrintConfig.bleed + 'mm bleed' : '')
      : '';
    ctx.fillText('Upload a template image to begin', canvas.width/2, canvas.height/2 - (_dimLabel?12:0));
    if (_dimLabel) {
      ctx.fillStyle = '#4ade80';
      ctx.font = 'bold 13px sans-serif';
      ctx.fillText(_dimLabel, canvas.width/2, canvas.height/2 + 14);
    }
  }

  // Draw each field zone
  _tplFields.forEach(function(f, idx) {
    var cx = (f.x / 100) * canvas.width;
    var cy = (f.y / 100) * canvas.height;
    var zoneW = ((f.w||30) / 100) * canvas.width;
    var zoneH = ((f.h||10) / 100) * canvas.height;
    // Only enforce minimum for non-photo zones (photo zones must keep their ratio)
    if (!f.isPhoto) zoneH = Math.max(zoneH, 20);
    var fSize = Math.max(10, Math.min(80, f.fontSize * (canvas.width / 800)));
    var fWeight = f.bold ? 'bold ' : '';
    var fStyle  = f.italic ? 'italic ' : '';
    var col2 = TPL_TYPE_COLOR[f.type] || '#3b5bdb';
    var isSelected = idx === _tplSelectedIdx;

    // Zone box
    ctx.save();
    ctx.strokeStyle = isSelected ? col2 : col2 + '99';
    ctx.lineWidth = isSelected ? 2.5 : 1.5;
    ctx.setLineDash(f.isPhoto ? [] : [6,3]);
    ctx.fillStyle = col2 + (isSelected ? '22' : '11');
    ctx.fillRect(cx - zoneW/2, cy - zoneH/2, zoneW, zoneH);
    ctx.strokeRect(cx - zoneW/2, cy - zoneH/2, zoneW, zoneH);
    ctx.setLineDash([]);

    // Text label
    ctx.font = (f.bold?'bold ':'') + (f.italic?'italic ':'') + Math.max(10,Math.min(18, fSize*0.6)) + 'px ' + (f.font||'sans-serif');
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = isSelected ? col2 : col2 + 'cc';
    ctx.fillText(f.label + (f.required?' *':''), cx, cy);

    // Type badge above zone
    ctx.font = '9px sans-serif';
    ctx.fillStyle = isSelected ? col2 : col2+'aa';
    ctx.fillText(TPL_TYPE_LABEL[f.type].toUpperCase(), cx, cy - zoneH/2 - 5);

    // Corner resize handles (bottom-right = size, right-middle = width)
    ctx.fillStyle = col2;
    // Width handle (right middle)
    ctx.beginPath(); ctx.arc(cx + zoneW/2, cy, 5, 0, Math.PI*2); ctx.fill();
    // Height handle (bottom middle)
    ctx.beginPath(); ctx.arc(cx, cy + zoneH/2, 5, 0, Math.PI*2); ctx.fill();
    // Corner resize handle (bottom-right)
    if (isSelected) {
      ctx.fillStyle = '#fff';
      ctx.strokeStyle = col2;
      ctx.lineWidth = 1.5;
      ctx.setLineDash([]);
      ctx.beginPath(); ctx.arc(cx + zoneW/2, cy + zoneH/2, 6, 0, Math.PI*2);
      ctx.fill(); ctx.stroke();
    }

    ctx.restore();
  });

  // ── Print guides (bleed + safe zone) ─────────────────────────────────────
  if (_tplPrintConfig && _tplPrintConfig.showGuides && _tplPrintConfig.w && _tplPrintConfig.h && _tplBaseImg) {
    var u = _tplPrintConfig.unit;
    var toMm = u==='in'?25.4:u==='px'?0.264583:1;
    var wMm = _tplPrintConfig.w * toMm;
    var hMm = _tplPrintConfig.h * toMm;
    var bleedMm = _tplPrintConfig.bleed || 0;
    var safeMm  = _tplPrintConfig.safe  || 0;

    // Canvas is mapped to the template image — which should include bleed
    // docW = wMm + bleedMm*2, docH = hMm + bleedMm*2
    var docW = wMm + bleedMm * 2;
    var docH = hMm + bleedMm * 2;
    var pxPerMm = canvas.width / docW;

    var trimX = bleedMm * pxPerMm;
    var trimY = bleedMm * pxPerMm;
    var trimW = wMm * pxPerMm;
    var trimH = hMm * pxPerMm;
    var safeX = trimX + safeMm * pxPerMm;
    var safeY = trimY + safeMm * pxPerMm;
    var safeW = trimW - safeMm * 2 * pxPerMm;
    var safeH = trimH - safeMm * 2 * pxPerMm;

    ctx.save();

    // Bleed overlay — shade the 4 bleed strips WITHOUT touching the trim area
    // (do NOT use clearRect — it wipes image pixels and creates the grey box bug)
    if (bleedMm > 0) {
      ctx.fillStyle = 'rgba(233,30,140,0.13)';
      // Top strip
      ctx.fillRect(0, 0, canvas.width, trimY);
      // Bottom strip
      ctx.fillRect(0, trimY + trimH, canvas.width, trimY);
      // Left strip (between top/bottom strips)
      ctx.fillRect(0, trimY, trimX, trimH);
      // Right strip (between top/bottom strips)
      ctx.fillRect(trimX + trimW, trimY, trimX, trimH);
    }

    // Trim line — pink dashed
    ctx.strokeStyle = '#E91E8C';
    ctx.lineWidth = 1.5;
    ctx.setLineDash([6, 4]);
    ctx.strokeRect(trimX, trimY, trimW, trimH);
    ctx.setLineDash([]);

    // Safe zone — blue dotted
    if (safeMm > 0 && safeW > 0 && safeH > 0) {
      ctx.strokeStyle = 'rgba(59,91,219,0.7)';
      ctx.lineWidth = 1;
      ctx.setLineDash([3, 4]);
      ctx.strokeRect(safeX, safeY, safeW, safeH);
      ctx.setLineDash([]);
    }

    // Labels
    ctx.font = 'bold 10px sans-serif';
    ctx.textBaseline = 'top';
    ctx.textAlign = 'left';
    if (trimX > 8) {
      ctx.fillStyle = '#E91E8C';
      ctx.fillText('TRIM', trimX + 3, trimY + 3);
    }
    if (bleedMm > 0 && trimX > 4) {
      ctx.fillStyle = 'rgba(233,30,140,0.8)';
      ctx.fillText('BLEED ' + bleedMm + 'mm', 3, 3);
    }
    if (safeMm > 0 && safeW > 0) {
      ctx.fillStyle = 'rgba(59,91,219,0.7)';
      ctx.fillText('SAFE', safeX + 3, safeY + 3);
    }

    ctx.restore();
  }

  // Pending type cursor hint
  if (_tplPendingType) {
    ctx.save();
    ctx.fillStyle = TPL_TYPE_COLOR[_tplPendingType] + 'cc';
    ctx.font = 'bold 14px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('Click to place ' + TPL_TYPE_LABEL[_tplPendingType], canvas.width/2, 20);
    ctx.restore();
  }
}

// ── Canvas interaction ────────────────────────────────────────────────────────
function admTplWireCanvas() {
  var canvas = document.getElementById('tpl-canvas');
  if (!canvas || canvas._tplWired) return;
  canvas._tplWired = true;

  function getPos(e) {
    var r = canvas.getBoundingClientRect();
    var t = e.touches ? e.touches[0] : e;
    var scaleX = canvas.width / r.width;
    var scaleY = canvas.height / r.height;
    return { x: (t.clientX - r.left) * scaleX, y: (t.clientY - r.top) * scaleY };
  }

  function findFieldAt(x, y) {
    for (var i = _tplFields.length - 1; i >= 0; i--) {
      var f = _tplFields[i];
      var cx = (f.x/100)*canvas.width, cy = (f.y/100)*canvas.height;
      var zW = ((f.w||30)/100)*canvas.width;
      var zH = Math.max(20, ((f.h||10)/100)*canvas.height);
      if (x >= cx-zW/2 && x <= cx+zW/2 && y >= cy-zH/2 && y <= cy+zH/2) return i;
    }
    return -1;
  }

  function findResizeHandleAt(x, y) {
    for (var i = 0; i < _tplFields.length; i++) {
      var f = _tplFields[i];
      var cx = (f.x/100)*canvas.width, cy = (f.y/100)*canvas.height;
      var zW = ((f.w||30)/100)*canvas.width;
      var zH = ((f.h||10)/100)*canvas.height;
      // Corner (bottom-right) = resize both
      if (Math.abs(x-(cx+zW/2)) < 12 && Math.abs(y-(cy+zH/2)) < 12) return {i:i, mode:'both'};
      // Right middle = width
      if (Math.abs(x-(cx+zW/2)) < 10 && Math.abs(y-cy) < 10) return {i:i, mode:'w'};
      // Bottom middle = height
      if (Math.abs(x-cx) < 10 && Math.abs(y-(cy+zH/2)) < 10) return {i:i, mode:'h'};
    }
    return null;
  }

  var resizing = null, startX = 0, startY = 0, startW = 0, startH = 0;

  function onDown(e) {
    var p = getPos(e);
    // Check resize handle first
    var rh = findResizeHandleAt(p.x, p.y);
    if (rh) { resizing = rh; startX = p.x; startY = p.y; startW = _tplFields[rh.i].w||30; startH = _tplFields[rh.i].h||10; e.preventDefault(); return; }
    // Place pending field
    if (_tplPendingType) {
      admTplPlaceField((p.x/canvas.width)*100, (p.y/canvas.height)*100);
      return;
    }
    // Select / start drag
    var idx = findFieldAt(p.x, p.y);
    if (idx >= 0) {
      _tplSelectedIdx = idx;
      var f = _tplFields[idx];
      _tplDragging = { idx:idx, offX: p.x - (f.x/100)*canvas.width, offY: p.y - (f.y/100)*canvas.height };
      admTplDraw();
      admTplShowFieldEditor(idx);
    } else {
      _tplSelectedIdx = -1;
      _tplDragging = null;
      document.getElementById('tpl-field-editor').style.display = 'none';
      admTplDraw();
    }
    e.preventDefault();
  }

  function onMove(e) {
    var p = getPos(e);
    if (resizing !== null) {
      var dX = p.x - startX, dY = p.y - startY;
      var f = _tplFields[resizing.i];
      if (resizing.mode === 'w' || resizing.mode === 'both')
        f.w = Math.max(5, Math.min(95, startW + (dX/canvas.width)*100));
      if (resizing.mode === 'h' || resizing.mode === 'both')
        f.h = Math.max(2, Math.min(80, startH + (dY/canvas.height)*100));
      // Photo zones: if keepRatio, keep square — clamp both axes
      if (f.isPhoto && f.keepRatio && (resizing.mode === 'w' || resizing.mode === 'both')) {
        var _tplAR = canvas.width / canvas.height;
        var _rH = Math.round(f.w * _tplAR * 10) / 10;
        if (_rH > 85) { _rH = 85; f.w = Math.max(5, Math.min(95, Math.round(_rH / _tplAR * 10) / 10)); }
        f.h = Math.max(2, Math.min(90, _rH));
      }
      // Sync editor if this field is selected
      if (resizing.i === _tplSelectedIdx) admTplShowFieldEditor(resizing.i);
      admTplDraw(); e.preventDefault(); return;
    }
    if (!_tplDragging) return;
    var f = _tplFields[_tplDragging.idx];
    f.x = Math.max(0, Math.min(100, ((p.x - _tplDragging.offX)/canvas.width)*100));
    f.y = Math.max(0, Math.min(100, ((p.y - _tplDragging.offY)/canvas.height)*100));
    admTplDraw();
    e.preventDefault();
  }

  function onUp() { _tplDragging = null; resizing = null; }

  canvas.addEventListener('mousedown', onDown);
  canvas.addEventListener('mousemove', onMove);
  canvas.addEventListener('mouseup', onUp);
  canvas.addEventListener('touchstart', onDown, {passive:false});
  canvas.addEventListener('touchmove', onMove, {passive:false});
  canvas.addEventListener('touchend', onUp);

  // Redraw on resize
  window.addEventListener('resize', function(){ admTplDraw(); });
}

// ── Field list sidebar ────────────────────────────────────────────────────────
function admTplRenderList() {
  var list = document.getElementById('tpl-field-list');
  if (!list) return;
  if (!_tplFields.length) {
    list.innerHTML = '<div style="font-size:12px;color:#aaa;padding:20px;text-align:center">No fields yet.</div>';
    return;
  }
  list.innerHTML = _tplFields.map(function(f, idx) {
    var col = TPL_TYPE_COLOR[f.type] || '#888';
    var isSelected = idx === _tplSelectedIdx;
    var BADGE_BG = {text:'#e0e7ff',name:'#dcfce7',date:'#fef3c7',photo:'#f3e8ff'};
    var BADGE_C  = {text:'#3b5bdb',name:'#16a34a',date:'#d97706',photo:'#7c3aed'};
    return '<div onclick="admTplSelectField('+idx+')" style="display:flex;align-items:flex-start;gap:10px;padding:10px 12px;border-bottom:1px solid #f0f0f0;cursor:pointer;background:'+(isSelected?'#f8f9ff':'#fff')+';'+(isSelected?'border-left:3px solid '+col+';padding-left:9px':'')+'">' +
      '<div style="flex:1;min-width:0">' +
        '<div style="display:flex;align-items:center;gap:5px;margin-bottom:3px">' +
          '<span style="font-size:11px;font-weight:700;background:'+(BADGE_BG[f.type]||'#eee')+';color:'+(BADGE_C[f.type]||'#555')+';padding:1px 6px;border-radius:8px">'+TPL_TYPE_LABEL[f.type]+'</span>' +
          (f.required ? '<span style="font-size:10px;color:#E91E8C;font-weight:700">*</span>' : '') +
        '</div>' +
        '<div style="font-size:13px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:#1a1a1a">'+f.label+'</div>' +
        '<div style="font-size:10px;color:#bbb;margin-top:1px">'+Math.round(f.x)+'%, '+Math.round(f.y)+'% &bull; '+Math.round(f.w||30)+'&times;'+Math.round(f.h||10)+'%</div>' +
      '</div>' +
      '<button onclick="event.stopPropagation();admTplRemoveField('+idx+')" style="background:none;border:none;color:#ddd;font-size:18px;cursor:pointer;padding:0;line-height:1;flex-shrink:0;margin-top:2px">&#215;</button>' +
    '</div>';
  }).join('');
}

function admTplSelectField(idx) {
  _tplSelectedIdx = idx;
  admTplDraw();
  admTplRenderList();
  admTplShowFieldEditor(idx);
}

function admTplRemoveField(idx) {
  _tplFields.splice(idx, 1);
  if (_tplSelectedIdx >= _tplFields.length) _tplSelectedIdx = _tplFields.length - 1;
  admTplDraw();
  admTplRenderList();
  if (_tplSelectedIdx < 0) document.getElementById('tpl-field-editor').style.display = 'none';
  else admTplShowFieldEditor(_tplSelectedIdx);
}

function admTplShowFieldEditor(idx) {
  var editor = document.getElementById('tpl-field-editor');
  if (!editor || idx < 0 || idx >= _tplFields.length) return;
  var f = _tplFields[idx];
  editor.style.display = '';

  // Populate all fields
  var sv = function(id,v){ var e=document.getElementById(id); if(e) e.value=v; };
  var sc = function(id,v){ var e=document.getElementById(id); if(e) e.checked=!!v; };
  sv('tpl-fe-label',  f.label      || '');
  sv('tpl-fe-ph',     f.placeholder|| '');
  sv('tpl-fe-fs',     f.fontSize   || 28);
  sv('tpl-fe-color',  f.color      || '#1a1a1a');
  sv('tpl-fe-font',   f.font       || 'Georgia, serif');
  sv('tpl-fe-align',  f.align      || 'center');
  sv('tpl-fe-max',    f.maxLength  || 80);
  sv('tpl-fe-w',       f.w  || 30);
  sv('tpl-fe-w-num',   f.w  || 30);
  sv('tpl-fe-h',       f.h  || 10);
  sv('tpl-fe-h-num',   f.h  || 10);
  // Restore keepRatio checkbox + show/hide it for photo zones
  var _krEl2 = document.getElementById('tpl-fe-keep-ratio');
  var _krRow = document.getElementById('tpl-fe-keep-ratio-row');
  if (_krEl2) _krEl2.checked = f.keepRatio !== false && f.isPhoto;
  if (_krRow) _krRow.style.display = f.isPhoto ? 'flex' : 'none';
  // Show actual mm size if print config has dimensions
  var _mmHint = document.getElementById('tpl-fe-mm-hint');
  if (_mmHint) {
    if (_tplPrintConfig && _tplPrintConfig.w && _tplPrintConfig.h) {
      var _u = _tplPrintConfig.unit || 'mm';
      var _toMm = _u==='in'?25.4:_u==='px'?0.264583:1;
      var _wMm = _tplPrintConfig.w * _toMm, _hMm = _tplPrintConfig.h * _toMm;
      var _fwMm = ((f.w||30)/100) * _wMm, _fhMm = ((f.h||10)/100) * _hMm;
      _mmHint.textContent = Math.round(_fwMm) + ' × ' + Math.round(_fhMm) + 'mm';
      _mmHint.style.display = 'inline';
    } else {
      _mmHint.style.display = 'none';
    }
  }
  sc('tpl-fe-req',    f.required);
  sc('tpl-fe-bold',   f.bold);
  sc('tpl-fe-italic', f.italic);

  // Size displays
  var wv = document.getElementById('tpl-fe-w-val');
  if (wv) wv.textContent = (f.w||30)+'%';
  var hv = document.getElementById('tpl-fe-h-val');
  if (hv) hv.textContent = (f.h||10)+'%';

  // Type badge
  var badge = document.getElementById('tpl-fe-type-badge');
  var BADGE_STYLES = {
    text:  {bg:'#e0e7ff',color:'#3b5bdb',label:'Text'},
    name:  {bg:'#dcfce7',color:'#16a34a',label:'Name'},
    date:  {bg:'#fef3c7',color:'#d97706',label:'Date'},
    photo: {bg:'#f3e8ff',color:'#7c3aed',label:'Photo Zone'},
  };
  var bs = BADGE_STYLES[f.type]||BADGE_STYLES.text;
  if (badge) { badge.textContent=bs.label; badge.style.background=bs.bg; badge.style.color=bs.color; }

  // Live font preview
  admTplUpdateFontPreview(f);
}

function admTplUpdateFontPreview(f) {
  var prev = document.getElementById('tpl-fe-preview');
  if (!prev) return;
  var fontStr = (f.bold ? 'bold ' : '') + (f.italic ? 'italic ' : '') + (f.fontSize||28)+'px ' + (f.font||'Georgia, serif');
  prev.innerHTML = '<span style="font:'+fontStr+';color:'+(f.color||'#333')+'">'+
    (f.label||'Preview text')+'</span>';
}


// ════ GIFT ORDER PDF EXPORT ═══════════════════════════════════════════════════
// Generates a print-ready PDF for a gift item, placing text layers at exact
// positions matching the canvas preview. Resolves the canvas-to-PDF font
// positioning problem by using the same coordinate system throughout.

function admDownloadGiftPdf(orderId, itemIdx) {
  var orders = DB.getOrders();
  var order  = orders.filter(function(o){ return o.id === orderId; })[0];
  if (!order) { showToast('Order not found'); return; }
  var item = (order.items||[])[itemIdx];
  if (!item) { showToast('Item not found'); return; }

  // Determine sides
  var sides;
  if (item.giftSides && item.giftSides.length) {
    sides = item.giftSides;
  } else if (item.giftImage) {
    sides = [{ name: 'Design', image: item.giftImage, texts: {} }];
  } else {
    showToast('No design files for this item');
    return;
  }

  // Get print config from giftConfig if available
  var slug = null;
  Object.keys(PRODUCTS_DATA||{}).forEach(function(s){ if((PRODUCTS_DATA[s].name||'')===(item.product||'')) slug=s; });
  var gc = slug ? ((PP_EXTRA[slug]||{}).giftConfig||{}) : {};
  // printConfig can come from template editor or overlay config — same structure
  var printCfg = gc.printConfig || { unit:'mm', w:0, h:0, bleed:0, safe:3 };
  // If printConfig has dimensions, the canvas was rendered at native image res
  // so the PDF should embed at that physical size with correct DPI.
  var allSides = gc.sides || [];

  var jsPDF = (window.jspdf && window.jspdf.jsPDF) || (window.jsPDF);
  if (!jsPDF) { showToast('PDF library not loaded — check internet connection'); return; }

  showToast('&#128196; Generating PDF...');

  // Process each side sequentially (async because of image loading)
  var sideIdx = 0;
  var doc = null;

  function processSide(si) {
    if (si >= sides.length) {
      // All sides done — save
      var filename = (order.id + '_' + (item.product||'gift').replace(/[^a-zA-Z0-9]/g,'_') + '.pdf').toLowerCase();
      doc.save(filename);
      showToast('&#10003; PDF downloaded: ' + filename);
      return;
    }

    var side = sides[si];
    var sideConfig = allSides[si] || {};
    var layers = sideConfig.templateFields || sideConfig.textLayers || gc.textLayers || [];

    if (!side.image) {
      processSide(si + 1);
      return;
    }

    var img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = function() {
      var imgW = img.naturalWidth;
      var imgH = img.naturalHeight;

      // Determine PDF page size
      // If printConfig has dimensions, use those (in mm). Otherwise derive from image at 96dpi.
      var pageWmm, pageHmm, bleedMm, safeMm;
      if (printCfg.w && printCfg.h) {
        var toMm = printCfg.unit==='in'?25.4:printCfg.unit==='px'?0.264583:1;
        pageWmm  = printCfg.w * toMm;
        pageHmm  = printCfg.h * toMm;
        bleedMm  = printCfg.bleed || 0;
        safeMm   = printCfg.safe  || 0;
        // Document size includes bleed
        var docWmm = pageWmm + bleedMm * 2;
        var docHmm = pageHmm + bleedMm * 2;
      } else {
        // Assume 96dpi screen image — convert px to mm
        pageWmm  = imgW * 0.264583;
        pageHmm  = imgH * 0.264583;
        bleedMm  = 0;
        safeMm   = 0;
        var docWmm = pageWmm;
        var docHmm = pageHmm;
      }

      // Create doc on first side
      if (!doc) {
        doc = new jsPDF({
          orientation: docWmm > docHmm ? 'landscape' : 'portrait',
          unit: 'mm',
          format: [docWmm, docHmm]
        });
      } else {
        doc.addPage([docWmm, docHmm], docWmm > docHmm ? 'landscape' : 'portrait');
      }

      // ── Embed the base image full-page ────────────────────────────────────
      var imgFmt = side.image.indexOf('image/png') > -1 ? 'PNG' : 'JPEG';
      doc.addImage(side.image, imgFmt, 0, 0, docWmm, docHmm, undefined, 'FAST');

      // ── Place text layers with pixel-perfect positioning ──────────────────
      // Key insight: canvas positions are in % of canvas dimensions.
      // We map those same % to the PDF page dimensions.
      // Canvas textAlign='center': x is the centre of the text.
      // jsPDF: x,y is always the bottom-left of the text box by default.
      // We use doc.text() with align option to match canvas behaviour exactly.

      layers.forEach(function(layer, li) {
        var textVal = '';
        if (side.texts) {
          textVal = side.texts[li] !== undefined ? String(side.texts[li]) :
                    (side.texts[String(li)] !== undefined ? String(side.texts[String(li)]) : '');
        }
        if (!textVal && !layer.isPhoto) return;
        if (layer.isPhoto) return; // photo zones handled separately

        // Position: layer.x/y are % of document dimensions
        var xPct = (layer.x != null ? layer.x : 50) / 100;
        var yPct = (layer.y != null ? layer.y : 50) / 100;
        var xMm  = xPct * docWmm;
        var yMm  = yPct * docHmm;

        // Font size: layer.fontSize is in px relative to an 800px canvas width.
        // Scale to document width, then convert px→pt for PDF.
        // 1pt = 0.352778mm; 1px ≈ 0.264583mm at 96dpi
        var scaledPxSize = (layer.fontSize || 20) * (docWmm / (printCfg.w && printCfg.h ? (printCfg.w*(printCfg.unit==='in'?25.4:printCfg.unit==='px'?0.264583:1)+bleedMm*2) : docWmm));
        // Clamp to reasonable range
        scaledPxSize = Math.max(6, Math.min(200, layer.fontSize || 20));
        // Convert px to pt: 1px = 0.75pt
        var _imgWmm2 = imgW > 0 ? imgW * 0.264583 : 0;
        var ptSize = scaledPxSize * 0.75 * (docWmm / (_imgWmm2 > 0 ? _imgWmm2 : docWmm));
        ptSize = Math.max(4, ptSize);

        // Font style
        var fontStyle = 'normal';
        if (layer.bold && layer.italic) fontStyle = 'bolditalic';
        else if (layer.bold) fontStyle = 'bold';
        else if (layer.italic) fontStyle = 'italic';

        // Map font family to jsPDF built-in
        var fontFamily = 'helvetica'; // default
        var fontStr = (layer.font || '').toLowerCase();
        if (fontStr.indexOf('georgia') > -1 || fontStr.indexOf('palatino') > -1 || fontStr.indexOf('times') > -1) fontFamily = 'times';
        else if (fontStr.indexOf('courier') > -1 || fontStr.indexOf('monospace') > -1) fontFamily = 'courier';
        // (Script fonts fall back to helvetica — jsPDF only has helvetica/times/courier built-in)

        // Colour
        var hex = (layer.color || '#000000').replace('#','');
        var r = parseInt(hex.substr(0,2),16)||0, g = parseInt(hex.substr(2,2),16)||0, b = parseInt(hex.substr(4,2),16)||0;

        doc.setFont(fontFamily, fontStyle);
        doc.setFontSize(ptSize);
        doc.setTextColor(r, g, b);

        // Alignment — matches canvas textAlign
        var align = layer.align || 'center';
        // jsPDF text(text, x, y, options) — x/y is baseline position
        // We add a half-line-height offset to centre vertically (matches canvas textBaseline:'middle')
        var lineHeightMm = ptSize * 0.352778 * 1.2;
        var yBaseline = yMm + lineHeightMm * 0.35; // small downward adjust for visual centre

        doc.text(textVal, xMm, yBaseline, { align: align, baseline: 'middle' });
      });

      // ── Crop marks / bleed marks ──────────────────────────────────────────
      if (bleedMm > 0) {
        doc.setDrawColor(0, 0, 0);
        doc.setLineWidth(0.1);
        var markLen = 3; // 3mm crop marks
        var trim = bleedMm;
        var docW = docWmm, docH = docHmm;
        // Top-left
        doc.line(trim - markLen, trim, trim, trim);
        doc.line(trim, trim - markLen, trim, trim);
        // Top-right
        doc.line(docW - trim, trim, docW - trim + markLen, trim);
        doc.line(docW - trim, trim - markLen, docW - trim, trim);
        // Bottom-left
        doc.line(trim - markLen, docH - trim, trim, docH - trim);
        doc.line(trim, docH - trim, trim, docH - trim + markLen);
        // Bottom-right
        doc.line(docW - trim, docH - trim, docW - trim + markLen, docH - trim);
        doc.line(docW - trim, docH - trim, docW - trim, docH - trim + markLen);

        // Label bleed
        doc.setFontSize(5);
        doc.setTextColor(180, 0, 0);
        doc.text('BLEED: ' + bleedMm + 'mm | TRIM: ' + pageWmm.toFixed(1) + '\xd7' + pageHmm.toFixed(1) + 'mm', trim + 0.5, trim - 1);
      }

      // ── Side label in corner ──────────────────────────────────────────────
      if (sides.length > 1) {
        doc.setFontSize(6);
        doc.setTextColor(120, 120, 120);
        doc.text(side.name || ('Side '+(si+1)), 1, docHmm - 1);
      }

      processSide(si + 1);
    };

    img.onerror = function() {
      // Side has no loadable image — skip
      processSide(si + 1);
    };

    img.src = side.image;
  }

  processSide(0);
}


// ════ CUSTOM FONT SYSTEM ══════════════════════════════════════════════════════
var _customFonts = [];  // [{id, name, family, format, base64, size}]

function admLoadFonts() {
  try { _customFonts = JSON.parse(localStorage.getItem('pv_custom_fonts') || '[]'); } catch(e) { _customFonts = []; }
  // Register all stored fonts with the browser
  _customFonts.forEach(function(f) { admRegisterFont(f); });
  admRenderFontList();
}

function admSaveFonts() {
  // Save without base64 data being too large — fonts can be big
  try { localStorage.setItem('pv_custom_fonts', JSON.stringify(_customFonts)); }
  catch(e) {
    showToast('Font storage full — try removing unused fonts first');
    console.warn('Font save failed:', e);
  }
}

function admRegisterFont(f) {
  // Register via FontFace API so it's available to canvas + CSS
  try {
    var ff = new FontFace(f.family, 'url(data:font/' + f.format + ';base64,' + f.base64 + ')');
    ff.load().then(function(loaded) {
      document.fonts.add(loaded);
    }).catch(function(err) {
      console.warn('Font load failed:', f.name, err);
    });
  } catch(e) { console.warn('FontFace API error:', e); }
}

function admUploadFonts(input) {
  if (!input.files || !input.files.length) return;
  var files = Array.prototype.slice.call(input.files);
  var processed = 0;

  files.forEach(function(file) {
    var ext = file.name.split('.').pop().toLowerCase();
    var format = ext === 'woff2' ? 'woff2' : ext === 'woff' ? 'woff' : ext === 'otf' ? 'opentype' : 'truetype';

    // Derive clean family name from filename
    var family = file.name.replace(/\.[^.]+$/, '').replace(/[-_]/g, ' ').replace(/\b\w/g, function(l){ return l.toUpperCase(); });

    var reader = new FileReader();
    reader.onload = function(e) {
      var base64 = e.target.result.split(',')[1];
      var id = 'font_' + Date.now() + '_' + Math.random().toString(36).slice(2,6);

      // Check for duplicate
      var existing = _customFonts.filter(function(f){ return f.name === file.name; });
      if (existing.length) {
        showToast('Font "' + file.name + '" already uploaded');
        processed++;
        if (processed === files.length) { input.value = ''; admRenderFontList(); }
        return;
      }

      var fontObj = { id:id, name:file.name, family:family, format:format, base64:base64, size:Math.round(file.size/1024) };
      _customFonts.push(fontObj);
      admRegisterFont(fontObj);

      processed++;
      if (processed === files.length) {
        admSaveFonts();
        admRenderFontList();
        input.value = '';
        showToast('&#10003; ' + files.length + ' font' + (files.length > 1 ? 's' : '') + ' uploaded');
      }
    };
    reader.readAsDataURL(file);
  });
}

function admDeleteFont(id) {
  _customFonts = _customFonts.filter(function(f){ return f.id !== id; });
  admSaveFonts();
  admRenderFontList();
  showToast('Font removed');
}

function admRenderFontList() {
  var list = document.getElementById('adm-font-list');
  if (!list) return;
  if (!_customFonts.length) {
    list.innerHTML = '<div style="font-size:13px;color:#9ca3af;padding:24px 0;text-align:center">No custom fonts uploaded yet.<br><span style="font-size:11px">Upload a .ttf, .otf, or .woff file above.</span></div>';
    return;
  }
  list.innerHTML = _customFonts.map(function(f) {
    return '<div style="display:flex;align-items:flex-start;gap:14px;padding:16px 0;border-bottom:1px solid #f3f4f6">' +
      '<div style="flex:1;min-width:0">' +
        '<div style="display:flex;align-items:center;gap:8px;margin-bottom:5px">' +
          '<span style="font-size:16px;font-weight:800;color:#0a0a0a;font-family:\'' + f.family + '\',sans-serif">' + f.family + '</span>' +
          '<span style="font-size:10px;font-weight:700;background:#f3f4f6;color:#6b7280;padding:2px 7px;border-radius:10px;text-transform:uppercase">' + f.format + '</span>' +
          '<span style="font-size:10px;color:#9ca3af">' + f.size + 'KB</span>' +
        '</div>' +
        '<div style="font-size:10px;color:#9ca3af;margin-bottom:10px">' + f.name + '</div>' +
        '<div style="font-size:20px;color:#0a0a0a;font-family:\'' + f.family + '\',sans-serif;line-height:1.4;margin-bottom:3px">The quick brown fox</div>' +
        '<div style="font-size:13px;color:#374151;font-family:\'' + f.family + '\',sans-serif;letter-spacing:1px;margin-bottom:2px">ABCDEFGHIJKLMNOPQRSTUVWXYZ</div>' +
        '<div style="font-size:13px;color:#9ca3af;font-family:\'' + f.family + '\',sans-serif">0123456789 &amp; !?@#</div>' +
      '</div>' +
      '<button onclick="admDeleteFont(\'' + f.id + '\')" class="adm-font-del-btn">&#215; Remove</button>' +
    '</div>';
  }).join('');
}

// ── Get font options for template editor picker ───────────────────────────────
function admGetFontOptions(allowedFontIds) {
  // Returns array of {value, label} for all available fonts
  // allowedFontIds: null = all, array = only those IDs
  var builtIn = [
    {value:'Georgia, serif', label:'Georgia (Serif)'},
    {value:'\'Fraunces\', Georgia, serif', label:'Fraunces (Display)'},
    {value:'\'DM Sans\', sans-serif', label:'DM Sans (Sans)'},
    {value:'Helvetica Neue, Arial, sans-serif', label:'Helvetica Neue'},
    {value:'Brush Script MT, cursive', label:'Brush Script (Script)'},
    {value:'Courier New, monospace', label:'Courier New (Mono)'},
    {value:'Palatino Linotype, serif', label:'Palatino (Elegant)'},
    {value:'Arial Black, sans-serif', label:'Arial Black (Bold)'},
    {value:'Times New Roman, serif', label:'Times New Roman'},
    {value:'Trebuchet MS, sans-serif', label:'Trebuchet MS'},
  ];
  var custom = _customFonts
    .filter(function(f){ return !allowedFontIds || allowedFontIds.indexOf(f.id) > -1; })
    .map(function(f){ return {value:'\''+f.family+'\', sans-serif', label:f.family+' (Custom)', id:f.id, isCustom:true}; });
  return builtIn.concat(custom);
}

// ── Rebuild font picker in template editor field editor ───────────────────────
function admTplRebuildFontPicker(allowedFontIds) {
  var sel = document.getElementById('tpl-fe-font');
  if (!sel) return;
  var currentVal = sel.value;
  var opts = admGetFontOptions(allowedFontIds);
  sel.innerHTML = opts.map(function(o){
    return '<option value="'+o.value+'"'+(o.value===currentVal?' selected':'')+'>'+o.label+'</option>';
  }).join('');
}


// ════ CUSTOM FONT SYSTEM ══════════════════════════════════════════════════════
var _customFonts = [];  // [{id, name, family, base64, format, size}]

function loadCustomFonts() {
  try {
    _customFonts = JSON.parse(localStorage.getItem('pv_custom_fonts')||'[]');
  } catch(e) { _customFonts = []; }
  // Register all custom fonts with the browser FontFace API
  _customFonts.forEach(function(f){ registerFontFace(f); });
}

function saveCustomFonts() {
  try { localStorage.setItem('pv_custom_fonts', JSON.stringify(_customFonts)); } catch(e) {}
}

function registerFontFace(f) {
  if (!f || !f.base64 || !f.family) return;
  try {
    var fmt = f.format || 'truetype';
    var src = 'url(data:font/'+fmt+';base64,' + f.base64 + ') format("'+fmt+'")';
    var face = new FontFace(f.family, src);
    face.load().then(function(loaded){ document.fonts.add(loaded); }).catch(function(){});
  } catch(e) {}
}

function admUploadFont(input) {
  if (!input.files || !input.files[0]) return;
  var file = input.files[0];
  var name  = file.name.replace(/\.[^.]+$/, ''); // strip extension
  var ext   = (file.name.split('.').pop()||'').toLowerCase();
  var fmt   = ext === 'woff' ? 'woff' : ext === 'woff2' ? 'woff2' : ext === 'otf' ? 'opentype' : 'truetype';
  var family = name.replace(/[-_]/g,' ').replace(/\b\w/g,function(l){return l.toUpperCase();});
  var reader = new FileReader();
  reader.onload = function(e) {
    var b64 = e.target.result.split(',')[1];
    var id  = 'font_' + Date.now();
    var font = { id:id, name:name, family:family, base64:b64, format:fmt,
      size: Math.round(file.size/1024) + ' KB' };
    _customFonts.push(font);
    saveCustomFonts();
    registerFontFace(font);
    admRenderFonts();
    showToast('&#127312; Font uploaded: ' + family);
  };
  reader.readAsDataURL(file);
  input.value = '';
}

function admDeleteFont(id) {
  _customFonts = _customFonts.filter(function(f){ return f.id !== id; });
  saveCustomFonts();
  admRenderFonts();
}

function admRenderFonts() {
  var wrap = document.getElementById('adm-fonts-list');
  if (!wrap) return;
  if (!_customFonts.length) {
    wrap.innerHTML = '<div style="font-size:12px;color:#aaa;padding:12px 0">No custom fonts uploaded yet.</div>';
    return;
  }
  wrap.innerHTML = _customFonts.map(function(f){
    return '<div style="display:flex;align-items:center;gap:10px;padding:9px 0;border-bottom:1px solid #f5f5f5">'+
      '<div style="flex:1;min-width:0">'+
        '<div style="font-size:14px;font-weight:600;font-family:\''+f.family+'\',sans-serif">'+f.family+'</div>'+
        '<div style="font-size:10px;color:#aaa">'+f.name+' &bull; '+f.size+'</div>'+
      '</div>'+
      '<div style="font-size:12px;font-weight:600;padding:4px 10px;background:#f8f8f8;border-radius:3px;font-family:\''+f.family+'\',sans-serif;color:#555">Aa Bb Cc</div>'+
      '<button onclick="admDeleteFont(\''+f.id+'\')" style="background:none;border:none;color:#ddd;font-size:18px;cursor:pointer;padding:0 4px;line-height:1">&times;</button>'+
    '</div>';
  }).join('');
}

// ── Get allowed fonts for a product (system + uploaded subset) ────────────────
function gfGetAllowedFonts(slug) {
  var gc = gfConfig(slug);
  var allowed = gc.allowedFonts || [];  // array of font IDs or 'system'
  var systemFonts = [
    { id:'sys_georgia',  family:'Georgia, serif',                   label:'Classic Serif' },
    { id:'sys_helvetica',family:'Helvetica Neue, Arial, sans-serif', label:'Modern Sans'  },
    { id:'sys_brush',    family:'Brush Script MT, cursive',          label:'Script'       },
    { id:'sys_courier',  family:'Courier New, monospace',            label:'Monospace'    },
    { id:'sys_palatino', family:'Palatino Linotype, serif',          label:'Elegant Serif'},
    { id:'sys_arial_bl', family:'Arial Black, sans-serif',           label:'Bold Block'   },
  ];
  var customSubset = allowed.length
    ? _customFonts.filter(function(f){ return allowed.indexOf(f.id) > -1; })
    : _customFonts;
  // If allowedFonts = [], show all system fonts + all custom fonts
  // If allowedFonts set, show only those (system or custom)
  var sysAllowed = allowed.length
    ? systemFonts.filter(function(f){ return allowed.indexOf(f.id) > -1; })
    : systemFonts;
  return sysAllowed.concat(customSubset.map(function(f){
    return { id:f.id, family:'\''+f.family+'\'', label:f.family };
  }));
}

// ── Render font picker in overlay/template customer flow ──────────────────────
function gfFontPickerHtml(slug, layerIdx) {
  var fonts = gfGetAllowedFonts(slug);
  if (fonts.length <= 1) return ''; // only one option — no picker needed
  var st = _giftFlow[slug] || {};
  var currentFont = (st.ovFonts && st.ovFonts[layerIdx]) || fonts[0].family;
  return '<div class="gf-font-picker-row">'+
    '<label style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#888;display:block;margin-bottom:4px">Font</label>'+
    '<select class="gf-font-select" id="gf-font-'+slug+'-'+layerIdx+'" onchange="gfSetFont(\''+slug+'\','+layerIdx+',this.value)" style="width:100%;border:1.5px solid #e0e0e0;padding:7px 10px;font-size:13px;font-family:var(--sans);border-radius:4px;background:#fff">'+
      fonts.map(function(f){
        return '<option value="'+f.family+'"'+(f.family===currentFont?' selected':'')+'>'+ f.label+'</option>';
      }).join('')+
    '</select>'+
  '</div>';
}

function gfSetFont(slug, layerIdx, fontFamily) {
  var st = _giftFlow[slug]; if (!st) return;
  if (!st.ovFonts) st.ovFonts = {};
  st.ovFonts[layerIdx] = fontFamily;
  gfOvDraw(slug);
}

