// ==== MEMBERS & POINTS ADMIN ====

function admLoadMembers() {
 var members = DB.getMembers();
 var keys = Object.keys(members);
 var orders = DB.getOrders();
 var countEl = document.getElementById('adm-mem-count');
 var outEl = document.getElementById('adm-pts-outstanding');
 if (countEl) countEl.textContent = keys.length;
 var totalPts = keys.reduce(function(s,k){ return s + (members[k].points||0); }, 0);
 if (outEl) outEl.textContent = totalPts.toLocaleString();
 admRenderMembers(members, orders, '');
}

function admRenderMembers(members, orders, filter) {
 var body = document.getElementById('adm-members-body');
 if (!body) return;
 var keys = Object.keys(members);
 if (filter) keys = keys.filter(function(k){ return k.includes(filter.toLowerCase()) || (members[k].name||'').toLowerCase().includes(filter.toLowerCase()); });
 if (!keys.length) { body.innerHTML = '<div style="padding:32px;text-align:center;color:#aaa;font-size:13px">No members found.</div>'; return; }
 // Sort by points desc
 keys.sort(function(a,b){ return (members[b].points||0) - (members[a].points||0); });
 var rows = keys.map(function(k) {
 var m = members[k];
 var orderCount = orders.filter(function(o){ return o.email && o.email.toLowerCase() === k; }).length;
 var pts = m.points || 0;
 var earned = m.totalEarned || 0;
 var div = document.createElement('div');
 div.className = 'adm-member-row';
 div.innerHTML =
 '<div><div style="font-weight:600">'+ (m.name||'—') + '</div><div style="font-size:11px;color:#888">'+ m.email + '</div></div>'+
 '<div><span class="adm-pts-badge">'+ pts.toLocaleString() + 'pts</span><div style="font-size:10px;color:#aaa;margin-top:2px">S$'+ (pts/1000).toFixed(2) + 'off avail.</div></div>'+
 '<div style="font-size:12px;color:#888">'+ earned.toLocaleString() + 'total</div>'+
 '<div style="font-size:12px">'+ orderCount + '</div>'+
 '<div></div>';
 var btn = document.createElement('button');
 btn.style.cssText = 'font-size:11px;padding:5px 10px;border:1px solid #e0e0e0;background:#fff;cursor:pointer;font-family:var(--sans)';
 btn.textContent = 'Adjust';
 btn.onclick = (function(email){ return function(){ admOpenPtsModal(email); }; })(k);
 div.lastElementChild.appendChild(btn);
 return div;
 });
 body.innerHTML = '';
 rows.forEach(function(r){ body.appendChild(r); });
}

function admFilterMembers(q) {
 admRenderMembers(DB.getMembers(), DB.getOrders(), q);
}

var admPtsModalEmail = '';
function admOpenPtsModal(email) {
 admPtsModalEmail = email;
 var modal = document.getElementById('adm-pts-modal');
 var label = document.getElementById('adm-pts-modal-email');
 var member = DB.getMember(email);
 if (label) label.textContent = email + '— Current balance: '+ ((member && member.points)||0).toLocaleString() + 'pts';
 if (modal) modal.style.display = 'flex';
 var inp = document.getElementById('adm-pts-adj');
 if (inp) inp.value = '';
}

function admClosePtsModal() {
 var modal = document.getElementById('adm-pts-modal');
 if (modal) modal.style.display = 'none';
}

function admApplyPtsAdj() {
 var adj = parseInt(document.getElementById('adm-pts-adj').value) || 0;
 if (!adj) { alert('Enter a points value.'); return; }
 var member = DB.getMember(admPtsModalEmail);
 DB.upsertMember(admPtsModalEmail, member ? member.name : '', adj);
 admClosePtsModal();
 admLoadMembers();
 admShowSaved('adm-global-saved');
}


// ════════════════════════════════════════════════════════════════
// IMAGE LIBRARY — variant image matching system
// ════════════════════════════════════════════════════════════════
var IMG_LIBRARY = {}; // slug -> [{url, tags:{stepId:optSlug}, label}]
(function(){
  try {
    var saved = JSON.parse(localStorage.getItem('pv_img_library') || 'null');
    if (saved && typeof saved === 'object') IMG_LIBRARY = saved;
  } catch(e) {}
})();

function imglibSave() {
  try { localStorage.setItem('pv_img_library', JSON.stringify(IMG_LIBRARY)); } catch(e) {}
}

// ── Score an image entry against current CFG_STATE ──
function imglibScore(entry, state) {
  var tags = entry.tags || {};
  var tagKeys = Object.keys(tags);
  if (tagKeys.length === 0) return 0; // fallback: score 0 (used only if nothing else matches)
  var score = 0;
  for (var i = 0; i < tagKeys.length; i++) {
    var k = tagKeys[i];
    if (state[k] === tags[k]) score++;
    else return -1; // any mismatch disqualifies
  }
  return score;
}

// ── Pick best image for current selection state ──
function imglibPickBest(slug) {
  var entries = IMG_LIBRARY[slug];
  if (!entries || !entries.length) return null;
  var state = CFG_STATE[slug] || {};
  var best = null, bestScore = -1;
  var fallback = null;
  for (var i = 0; i < entries.length; i++) {
    var tags = entries[i].tags || {};
    if (Object.keys(tags).length === 0) { fallback = entries[i]; continue; }
    var s = imglibScore(entries[i], state);
    if (s > bestScore) { bestScore = s; best = entries[i]; }
  }
  return (bestScore >= 0 ? best : null) || fallback;
}

// ── Update product page hero image on selection change ──
function cfgUpdateVariantImage(slug) {
  var frame = document.getElementById('pp3-art-frame-' + slug);
  if (!frame) return;
  var entries = IMG_LIBRARY[slug];
  if (!entries || !entries.length) return; // no library entries → don't override static ex.image
  var picked = imglibPickBest(slug);
  if (!picked) return;
  var img = frame.querySelector('img.pp3-art-img');
  if (img) {
    if (img.src === picked.url) return; // no change
    img.style.opacity = '0';
    img.style.transition = 'opacity .25s';
    setTimeout(function() {
      img.src = picked.url;
      img.onload = function() { img.style.opacity = '1'; };
      img.onerror = function() { img.style.opacity = '1'; };
    }, 120);
  } else {
    frame.innerHTML = '<img class="pp3-art-img" src="' + picked.url + '" style="opacity:1;transition:opacity .25s" alt="">';
  }
}

// ── Admin UI ──────────────────────────────────────────────────────
var _imglibCurrentSlug = null;
var _imglibTagIdx = null;

function imglibInit() {
  var sel = document.getElementById('imglib-prod-sel');
  if (!sel || sel.options.length > 1) return;
  sel.innerHTML = '<option value="">-- Select a product --</option>';
  Object.keys(PRODUCTS_DATA).sort(function(a,b){
    return (PRODUCTS_DATA[a].name||'').localeCompare(PRODUCTS_DATA[b].name||'');
  }).forEach(function(slug) {
    var p = PRODUCTS_DATA[slug];
    var opt = document.createElement('option');
    opt.value = slug;
    opt.textContent = (p.icon||'') + ' ' + p.name;
    sel.appendChild(opt);
  });
}

function imglibLoadProd(slug) {
  _imglibCurrentSlug = slug || null;
  var uploadArea = document.getElementById('imglib-upload-area');
  var grid = document.getElementById('imglib-grid');
  if (!slug) {
    if (uploadArea) uploadArea.style.display = 'none';
    if (grid) grid.style.display = 'none';
    return;
  }
  if (uploadArea) uploadArea.style.display = '';
  if (grid) grid.style.display = '';
  imglibRender();
}

function imglibRender() {
  var slug = _imglibCurrentSlug;
  var cards = document.getElementById('imglib-cards');
  var empty = document.getElementById('imglib-empty');
  if (!cards || !slug) return;
  var entries = IMG_LIBRARY[slug] || [];
  if (!entries.length) {
    cards.innerHTML = '';
    if (empty) empty.style.display = 'block';
    return;
  }
  if (empty) empty.style.display = 'none';
  // Build step lookup for this product (for displaying tag labels)
  var cfg = CONFIGURATOR[slug];
  var stepMap = {}; // stepId -> {label, optMap}
  if (cfg && cfg.steps) {
    cfg.steps.forEach(function(step) {
      var optMap = {};
      if (step.options) step.options.forEach(function(o){ optMap[o.slug||o.label] = o.label; });
      stepMap[step.id] = { label: step.label, optMap: optMap };
    });
  }

  cards.innerHTML = entries.map(function(entry, idx) {
    var tags = entry.tags || {};
    var tagKeys = Object.keys(tags);
    var tagBadges = tagKeys.length
      ? tagKeys.map(function(k) {
          var stepInfo = stepMap[k] || { label: k, optMap: {} };
          var optLabel = stepInfo.optMap[tags[k]] || tags[k];
          return '<span style="font-size:10px;background:#f3f4f6;border:1px solid #e5e5e5;padding:2px 7px;border-radius:10px;color:#374151;white-space:nowrap">' + optLabel + '</span>';
        }).join('')
      : '<span style="font-size:10px;color:#9ca3af;font-style:italic">Default (no tags)</span>';
    return '<div class="adm-card" style="padding:0;overflow:hidden;cursor:pointer" onclick="imglibOpenTagModal(' + idx + ')">'
      + '<img src="' + entry.url + '" style="width:100%;height:140px;object-fit:cover;display:block;background:#f5f5f5">'
      + '<div style="padding:10px">'
      + '<div style="font-size:12px;font-weight:700;color:#0a0a0a;margin-bottom:6px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + (entry.label || 'Untitled') + '</div>'
      + '<div style="display:flex;flex-wrap:wrap;gap:4px">' + tagBadges + '</div>'
      + '</div>'
      + '</div>';
  }).join('');
}

function imglibUpload(input) {
  if (!input.files || !input.files[0] || !_imglibCurrentSlug) return;
  var file = input.files[0];
  var reader = new FileReader();
  reader.onload = function(e) {
    if (!IMG_LIBRARY[_imglibCurrentSlug]) IMG_LIBRARY[_imglibCurrentSlug] = [];
    var entry = { url: e.target.result, tags: {}, label: file.name.replace(/\.[^.]+$/, '') };
    IMG_LIBRARY[_imglibCurrentSlug].push(entry);
    imglibSave();
    imglibRender();
    // Auto-open tag modal for freshly uploaded image
    imglibOpenTagModal(IMG_LIBRARY[_imglibCurrentSlug].length - 1);
  };
  reader.readAsDataURL(file);
  input.value = '';
}

function imglibOpenTagModal(idx) {
  _imglibTagIdx = idx;
  var slug = _imglibCurrentSlug;
  var entry = (IMG_LIBRARY[slug] || [])[idx];
  if (!entry) return;
  var modal = document.getElementById('imglib-tag-modal');
  var preview = document.getElementById('imglib-tag-preview');
  var rowsEl = document.getElementById('imglib-tag-rows');
  if (!modal || !rowsEl) return;
  if (preview) preview.src = entry.url;
  var cfg = CONFIGURATOR[slug];
  if (!cfg || !cfg.steps) { rowsEl.innerHTML = '<div style="color:#9ca3af;font-size:13px">This product has no configurator steps to tag against.</div>'; modal.style.display = 'flex'; return; }

  var html = '';
  cfg.steps.forEach(function(step) {
    if (!step.options || !step.options.length) return;
    var currentVal = (entry.tags || {})[step.id] || '';
    html += '<div>'
      + '<label style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#6b7280;display:block;margin-bottom:5px">' + step.label + '</label>'
      + '<select data-step="' + step.id + '" style="width:100%;padding:9px 12px;border:1.5px solid #e5e5e5;border-radius:6px;font-size:13px;font-family:var(--sans);background:#fff;outline:none">'
      + '<option value="">-- Any / not set --</option>'
      + step.options.map(function(o) {
          var v = o.slug || o.label;
          return '<option value="' + v + '"' + (currentVal === v ? ' selected' : '') + '>' + o.label + '</option>';
        }).join('')
      + '</select></div>';
  });
  rowsEl.innerHTML = html;
  modal.style.display = 'flex';
}

function imglibSaveTags() {
  var slug = _imglibCurrentSlug;
  var entry = (IMG_LIBRARY[slug] || [])[_imglibTagIdx];
  if (!entry) return;
  var selects = document.querySelectorAll('#imglib-tag-rows select[data-step]');
  var tags = {};
  selects.forEach(function(sel) {
    if (sel.value) tags[sel.dataset.step] = sel.value;
  });
  entry.tags = tags;
  imglibSave();
  imglibRender();
  imglibCloseTagModal();
}

function imglibDeleteImg() {
  var slug = _imglibCurrentSlug;
  if (!IMG_LIBRARY[slug] || _imglibTagIdx === null) return;
  if (!confirm('Delete this image?')) return;
  IMG_LIBRARY[slug].splice(_imglibTagIdx, 1);
  imglibSave();
  imglibRender();
  imglibCloseTagModal();
}

function imglibCloseTagModal() {
  var modal = document.getElementById('imglib-tag-modal');
  if (modal) modal.style.display = 'none';
  _imglibTagIdx = null;
}

