function ptsLookup() {
 var email = (document.getElementById('pts-lookup-email').value || '').trim().toLowerCase();
 if (!email || !email.includes('@')) { showToast('Please enter a valid email'); return; }
 var member = DB.getMember(email);
 document.getElementById('pts-result-found').style.display = 'none';
 document.getElementById('pts-result-none').style.display = 'none';
 if (!member) {
 document.getElementById('pts-result-none').style.display = 'block';
 return;
 }
 var pts = member.points || 0;
 var earned = member.totalEarned || 0;
 var redeemable = Math.floor(pts / 1000);
 document.getElementById('pts-result-name').textContent = member.name || email;
 document.getElementById('pts-result-balance').textContent = pts.toLocaleString();
 document.getElementById('pts-result-value').textContent = 'S$'+ redeemable.toFixed(2);
 document.getElementById('pts-result-earned').textContent = earned.toLocaleString();
 // Progress bar
 var inBlock = pts % 1000;
 var pct = Math.round(inBlock / 10);
 document.getElementById('pts-progress-bar').style.width = pct + '%';
 document.getElementById('pts-progress-pct').textContent = pct + '%';
 if (pts >= 1000) {
 document.getElementById('pts-progress-label').textContent = redeemable + 'redemption'+ (redeemable > 1 ? 's': '') + 'available';
 document.getElementById('pts-progress-sub').textContent = inBlock > 0 ? (1000 - inBlock) + 'more pts to your next S$1 off': 'Full blocks ready to redeem';
 } else {
 document.getElementById('pts-progress-label').textContent = 'Progress to first S$1 off';
 document.getElementById('pts-progress-sub').textContent = (1000 - pts) + 'more pts needed';
 }
 document.getElementById('pts-result-found').style.display = 'block';
}

function ptsLookupReset() {
 document.getElementById('pts-lookup-email').value = '';
 document.getElementById('pts-result-found').style.display = 'none';
 document.getElementById('pts-result-none').style.display = 'none';
 document.getElementById('pts-lookup-email').focus();
}


