// -- Product page state --
var ppColIdx = 0;
var ppRowIdx = 0;
var ppUploadFile = null;

function closeMega() { document.querySelectorAll('.mega-menu').forEach(function(m){ m.classList.remove('open'); }); }
function goProduct(slug) {
 closeMega();
 try {
 var prod = PRODUCTS_DATA[slug];
 if (!prod) { go('shop'); return; }
 ppColIdx = 0; ppRowIdx = 0; ppUploadFile = null;
 document.getElementById('nav').style.display = 'flex';
 var screens = document.querySelectorAll('.screen');
 for (var i = 0; i < screens.length; i++) screens[i].classList.remove('active');
 document.getElementById('screen-product').classList.add('active');
 renderProductPage(slug, prod);
 try { window.history.replaceState(null, '', '#product-' + slug); } catch(e) {}
 window.scrollTo({ top: 0, behavior: 'smooth'});
 } catch(e) {
 var d = document.getElementById('errdiv');
 if (d) { d.style.display = 'block'; d.textContent = 'goProduct ERR: '+ e.message + '\n'+ e.stack; }
 }
}


// ==============================================
// CONFIGURATOR ENGINE
// ==============================================
var CFG_STATE = {}; // slug -> {stepId: selectedValue, ...}

// ── Price Ladder ─────────────────────────────────────────────────────────────

// Build the initial ladder table (qty tiers × base price only)
function cfgBuildLadder(slug, prod, cfg) {
  if (!cfg) return '';
  var qtyStep = null;
  for (var i = 0; i < cfg.steps.length; i++) {
    if (cfg.steps[i].type === 'qty') { qtyStep = cfg.steps[i]; break; }
  }
  var mult = (qtyStep && qtyStep.labelMultiplier) || 1;
  var currentQty = parseInt((CFG_STATE[slug] || {}).qty) ||
    (qtyStep && qtyStep.presets && qtyStep.presets[0]) ||
    (qtyStep && qtyStep.min) || 1;

  // Build tier list
  var tiers = [];
  if (qtyStep && qtyStep.presets && qtyStep.presets.length) {
    tiers = qtyStep.presets.slice();
  }
  if (!tiers.length && prod.pricing && prod.pricing.rows && prod.pricing.rows.length) {
    prod.pricing.rows.forEach(function(r) {
      var n = parseInt((r.qty || '').replace(/[^0-9]/g, ''));
      if (n > 0) tiers.push(n);
    });
  }
  if (!tiers.length) {
    var mn = (qtyStep && qtyStep.min) || 1;
    tiers = [mn, mn*2, mn*5, mn*10, mn*25].filter(function(v,ix,a){ return a.indexOf(v)===ix; });
  }
  if (tiers.length > 8) tiers = tiers.slice(0, 8);

  // Build price map from pricing table rows (always available)
  var priceMap = {};
  if (prod.pricing && prod.pricing.rows) {
    prod.pricing.rows.forEach(function(r) {
      var n = parseInt((r.qty || '').replace(/[^0-9]/g, ''));
      if (!n) return;
      var firstPrice = 0;
      for (var ci = 0; ci < (r.prices || []).length; ci++) {
        if (typeof r.prices[ci] === 'number' && r.prices[ci] > 0) {
          firstPrice = r.prices[ci]; break;
        }
      }
      if (firstPrice > 0) priceMap[n] = firstPrice;
    });
  }

  // Add-ons from currently selected options (non-base steps)
  function getAddon(qty) {
    var addon = 0;
    var state = CFG_STATE[slug] || {};
    for (var si = 0; si < cfg.steps.length; si++) {
      var step = cfg.steps[si];
      if (step.type === 'qty') continue;
      var sel = state[step.id];
      if (!sel) continue;
      for (var oi = 0; oi < (step.options || []).length; oi++) {
        if (step.options[oi].slug === sel) {
          var f = step.options[oi].price_formula || '0';
          // Skip base-price formulas (those are already in priceMap)
          if (f !== '0' && f.indexOf('qty*(') !== 0 && f.indexOf('(qty/') !== 0) {
            addon += cfgEval(f, qty);
          }
          break;
        }
      }
    }
    return addon;
  }

  // Get price for a tier — pricing table first, then interpolate
  function getPrice(qty) {
    // Exact match in pricing table
    if (priceMap[qty] !== undefined) return priceMap[qty] + getAddon(qty);
    // Configurator calc if options selected
    var res = cfgCalcTotal(slug, qty);
    if (res && res.total > 0) return res.total;
    // Interpolate between nearest rows
    var keys = Object.keys(priceMap).map(Number).sort(function(a,b){return a-b;});
    if (!keys.length) return 0;
    var lo = keys[0], hi = keys[keys.length-1];
    for (var ki = 0; ki < keys.length; ki++) {
      if (keys[ki] <= qty) lo = keys[ki];
      if (keys[ki] >= qty) { hi = keys[ki]; break; }
    }
    if (lo === hi) return priceMap[lo] * qty / lo + getAddon(qty);
    var ratio = (qty - lo) / (hi - lo);
    var base = priceMap[lo] + (priceMap[hi] - priceMap[lo]) * ratio;
    return Math.round(base * 100) / 100 + getAddon(qty);
  }

  // Render table
  var html = '<table><thead><tr>'+
    '<th>Qty</th><th>Total price</th><th>Per piece</th><th>You save</th>'+
    '</tr></thead><tbody id="pp3ladder-rows-'+ slug +'">';

  var minTotal = getPrice(tiers[0]);
  var minPc = (minTotal > 0 && tiers[0] > 0) ? minTotal / (tiers[0] * mult) : 0;

  for (var ti = 0; ti < tiers.length; ti++) {
    var qty = tiers[ti];
    var total = getPrice(qty);
    var perPc = (total > 0 && qty > 0) ? total / (qty * mult) : 0;
    var saving = (minPc > 0 && perPc > 0 && perPc < minPc - 0.001 && ti > 0)
      ? 'Save S$' + ((minPc - perPc) * qty * mult).toFixed(2) : '';
    var isActive = qty === currentQty;
    var qtyLabel = (qty * mult) + (qty * mult === 1 ? ' pc' : ' pcs');
    html += '<tr class="'+ (isActive ? 'ladder-active' : '') +'" data-qty="'+ qty +'"'+
      ' onclick="cfgSetQty(\''+  slug + '\','+ qty +');cfgUpdateLadder(\''+  slug + '\')">'+
      '<td class="ladder-qty">'+ qtyLabel +'</td>'+
      '<td class="ladder-total">'+ (total > 0 ? 'S$'+total.toFixed(2) : '—') +'</td>'+
      '<td class="ladder-unit">'+ (perPc > 0 ? 'S$'+perPc.toFixed(3)+'/pc' : '—') +'</td>'+
      '<td class="ladder-saving">'+ saving +'</td>'+
      '</tr>';
  }
  html += '</tbody></table>';
  return html;
}
function cfgUpdateLadder(slug) {
  var tableEl = document.getElementById('pp3ladder-table-' + slug);
  if (!tableEl) return;
  var cfg = CONFIGURATOR[slug];
  var prod = PRODUCTS_DATA[slug];
  if (!cfg || !prod) return;
  tableEl.innerHTML = cfgBuildLadder(slug, prod, cfg);
}

function cfgEval(formula, qty) {
 if (!formula || formula === '0') return 0;
 try {
 // Replace [qty] style and Math refs
 var f = formula.replace(/\[qty\]/g, qty).replace(/;/g, ',');
 return parseFloat(Function('qty', 'Math', '"use strict"; return ('+ f + ')')(qty, Math)) || 0;
 } catch(e) { return 0; }
}

function cfgCalcTotal(slug, qty) {
  var cfg = CONFIGURATOR[slug];
  if (!cfg) return null;
  var state = CFG_STATE[slug] || {};
  var total = 0;
  var hasBase = false;

  // Special: area-based pricing (PVC Canvas uses width+height number inputs)
  var widthStep  = cfg.steps.find ? cfg.steps.find(function(s){return s.id==='width';})  : null;
  var heightStep = cfg.steps.find ? cfg.steps.find(function(s){return s.id==='height';}) : null;
  if (widthStep && heightStep) {
    var w = parseFloat(state['width'])  || 0;
    var h = parseFloat(state['height']) || 0;
    if (w > 0 && h > 0) {
      // Formula from CSV: (H_mm * W_mm / 93025) * 3.5 per unit
      // Inputs are in cm, convert: w_mm = w*10, h_mm = h*10
      var areaSqM = (w * h) / 10000; // sq metres
      var basePrice = areaSqM * 35; // $35/sqm approx (3.5 * 10000/1000)
      total += Math.max(15, Math.round(basePrice * 100) / 100) * qty;
      hasBase = true;
    }
  }

  for (var si = 0; si < cfg.steps.length; si++) {
    var step = cfg.steps[si];
    if (step.type === 'qty' || step.type === 'text' || step.type === 'number') continue;
    var selected = state[step.id];
    if (!selected) continue;
    for (var oi = 0; oi < (step.options||[]).length; oi++) {
      if (step.options[oi].slug === selected) {
        var price = cfgEval(step.options[oi].price_formula, qty);
        total += price;
        if (si === 0 || (step.options[oi].price_formula && step.options[oi].price_formula !== '0')) hasBase = true;
        break;
      }
    }
  }
  return {total: total, hasBase: hasBase};
}

function cfgSelect(slug, stepId, optSlug) {
 if (!CFG_STATE[slug]) CFG_STATE[slug] = {};
 CFG_STATE[slug][stepId] = optSlug;
 // Handle show_if: clear dependent steps
 var cfg = CONFIGURATOR[slug];
 for (var si = 0; si < cfg.steps.length; si++) {
 var step = cfg.steps[si];
 if (step.show_if && step.show_if.step === stepId) {
 if (optSlug !== step.show_if.value) {
 delete CFG_STATE[slug][step.id];
 }
 }
 }
 renderConfigurator(slug);
 cfgUpdateLadder(slug);
 cfgUpdateVariantImage(slug);
}

function cfgSetQty(slug, qty) {
  if (!CFG_STATE[slug]) CFG_STATE[slug] = {};
  var qv = parseInt(qty) || 1;
  CFG_STATE[slug]['qty'] = qv;
  cfgUpdatePriceOnly(slug);
  // Update active row in ladder
  var tableEl = document.getElementById('pp3ladder-table-' + slug);
  if (tableEl) {
    tableEl.querySelectorAll('tr[data-qty]').forEach(function(row) {
      row.classList.toggle('ladder-active', parseInt(row.dataset.qty) === qv);
    });
  }
  var cfg = CONFIGURATOR[slug];
  if (cfg) {
    var qtyStep = cfg.steps.find ? cfg.steps.find(function(s){return s.type==='qty';}) : null;
    if (qtyStep && qtyStep.presets && qtyStep.presets.length > 0) {
      var el = document.getElementById('cfg-container-' + slug);
      if (el) {
        var btns = el.querySelectorAll('.cfg-qty-btn');
        var presets = qtyStep.presets;
        for (var bi = 0; bi < btns.length; bi++) {
          btns[bi].classList.toggle('cfg-qty-on', presets[bi] === qv);
        }
      }
    }
  }
}

function cfgSetText(slug, stepId, val) {
  if (!CFG_STATE[slug]) CFG_STATE[slug] = {};
  CFG_STATE[slug][stepId] = val;
  cfgUpdatePriceOnly(slug);
  cfgUpdateLadder(slug);
}

function cfgUpdatePriceOnly(slug) {
  var cfg = CONFIGURATOR[slug];
  var prod = PRODUCTS_DATA[slug];
  if (!cfg || !prod) return;
  var state = CFG_STATE[slug] || {};
  var qtyStep = cfg.steps.find ? cfg.steps.find(function(s){return s.type==='qty';}) : null;
  var mult = (qtyStep && qtyStep.labelMultiplier) || 1;
  var qty = parseInt(state.qty) || (qtyStep && qtyStep.presets && qtyStep.presets[0]) || (qtyStep && qtyStep.min) || 1;
  var result = cfgCalcTotal(slug, qty);
  var totalPrice = result ? result.total : 0;
  var priceDisplay = totalPrice > 0 ? 'S$' + totalPrice.toFixed(2) : 'Select options above';
  var perUnit = (totalPrice > 0 && qty > 0) ? 'S$' + (totalPrice/(qty*mult)).toFixed(2) + ' / pc' : '';

  // Savings: compare single-unit price x qty vs bulk price
  var savingsNote = '';
  var savingsAmt = 0;
  if (totalPrice > 0 && qty > 1) {
    var r1 = cfgCalcTotal(slug, 1);
    var p1 = r1 ? r1.total : 0;
    if (p1 > 0) {
      var fullP = p1 * qty;
      savingsAmt = Math.round((fullP - totalPrice) * 100) / 100;
      if (savingsAmt > 0.005) savingsNote = 'You\'re saving S$' + savingsAmt.toFixed(2) + ' on this order';
    }
  }

  var el = document.getElementById('cfg-container-' + slug);
  if (!el) return;
  var priceEl = el.querySelector('.cfg-price-live');
  if (priceEl) {
    priceEl.innerHTML =
      '<div class="cfg-price-total">' + priceDisplay + '</div>' +
      (perUnit ? '<div class="cfg-price-unit">' + perUnit + '</div>' : '') +
      (savingsNote ? '<div class="cfg-savings-note">&#127381; ' + savingsNote + '</div>' : '') +
      '<div class="cfg-price-note">Estimated price &#183; Final confirmed at checkout</div>';
  }
  // Sync right card — one row per step + optional savings row
  var rowsElU = document.getElementById('pp3oc-rows-' + slug);
  if (rowsElU) {
    var rowsHtmlU = '';
    for (var si = 0; si < cfg.steps.length; si++) {
      var s = cfg.steps[si];
      if (s.type === 'qty') continue;
      var sel = state[s.id];
      var valLabelU = '';
      if (s.type === 'number') {
        if (sel && parseFloat(sel) > 0) valLabelU = sel + 'cm';
      } else if (s.type === 'text') {
        valLabelU = sel || '';
      } else {
        for (var oi = 0; oi < (s.options||[]).length; oi++) {
          if (s.options[oi].slug === sel) { valLabelU = s.options[oi].label; break; }
        }
      }
      if (!valLabelU) continue;
      rowsHtmlU += '<div class="pp3-oc-row"><span>' + s.label + '</span><span>' + valLabelU + '</span></div>';
    }
    if (savingsAmt > 0.005) {
      rowsHtmlU += '<div class="pp3-oc-row pp3-oc-savings"><span>&#127881; You save</span><span>-S$' + savingsAmt.toFixed(2) + '</span></div>';
    }
    rowsElU.innerHTML = rowsHtmlU;
  }
  var actualQty = qty * mult;
  var qtyDisplay = actualQty + (actualQty === 1 ? ' pc' : ' pcs');
  var priceStr = totalPrice > 0 ? 'S$' + totalPrice.toFixed(2) : '—';
  var qtyEl = document.getElementById('pp3oc-qty-' + slug);
  var totEl = document.getElementById('pp3oc-total-' + slug);
  var barEl = document.getElementById('pp3bar-price-' + slug);
  if (qtyEl) qtyEl.textContent = qtyDisplay;
  if (totEl) totEl.textContent = priceStr;
  if (barEl) barEl.textContent = priceStr;
}

