function renderCart(){
  var wrap = document.getElementById('cart-items');
  var sidebar = document.getElementById('cart-sidebar');
  var label = document.getElementById('cart-count-label');
  if (!wrap) return;

  if (label) {
    if (cart.length > 0) { label.textContent = cart.length; label.style.display = 'inline-block'; }
    else label.style.display = 'none';
  }

  if (!cart.length) {
    wrap.innerHTML =
      '<div class="cart-empty">' +
        '<div class="cart-empty-icon">🛒</div>' +
        '<div class="cart-empty-msg">Your cart is empty</div>' +
        '<div class="cart-empty-sub">Browse our products and configure your order</div>' +
        '<button class="cart-browse-btn" onclick="go(\'shop\')">Browse Products</button>' +
      '</div>';
    if (sidebar) sidebar.innerHTML = '';
    return;
  }

  var subtotal = 0;
  for (var i = 0; i < cart.length; i++) subtotal += Number(cart[i].price) || 0;

  var itemsHtml = '';
  for (var i = 0; i < cart.length; i++) {
    var item = cart[i];
    var priceNum = Number(item.price) || 0;
    var name   = item.product || item.name || 'Product';
    var icon   = item.icon || '🖨️';
    var config = item.config || item.spec || '';
    var qty    = item.qty || 1;
    var unit   = item.unit || '';
    var priceFmt = priceNum > 0 ? 'S$' + priceNum.toFixed(2) : 'Quote';
    var fileLabel = item.file ? item.file : '';
    var hasFile = !!fileLabel;
    var configLines = '';
    if (config && config !== '—') {
      var parts = config.split(' · ');
      configLines = parts.map(function(p){ return '<div>' + p + '</div>'; }).join('');
    }

    // Icon cell: multi-side thumbnails, single gift image, or emoji
    var hasGiftImg = !!(item.giftImage || (item.giftSides && item.giftSides.length));
    var iconCell;
    if (item.giftSides && item.giftSides.length > 1) {
      iconCell = '<div style="display:flex;gap:3px;flex-wrap:wrap;width:80px">' +
        item.giftSides.slice(0,4).map(function(s){
          return s.image ? '<img src="'+s.image+'" style="width:36px;height:36px;object-fit:cover;border-radius:3px;border:1px solid #e0e0e0">' : '';
        }).join('') + '</div>';
    } else if (item.giftImage) {
      iconCell = '<img class="cart-gift-img" src="' + item.giftImage + '" alt="Your design">';
    } else {
      iconCell = '<div class="cart-item-icon">' + icon + '</div>';
    }

    itemsHtml +=
      '<div class="cart-item" id="cart-item-' + item.id + '">' +
        iconCell +
        '<div class="cart-item-body">' +
          '<div class="cart-item-name">' + name + '</div>' +
          (configLines ? '<div class="cart-item-config">' + configLines + '</div>' : '') +
          '<div class="cart-item-unit">Qty: ' + qty + (unit ? ' &bull; ' + unit : '') + '</div>' +
          (item.notes ? '<div class="cart-item-notes">' + item.notes + '</div>' : '') +
          (hasGiftImg
            ? '<div class="cart-upload-row" style="color:#22c55e;font-size:11px">&#10003; Photo saved &amp; ready to print</div>'
            : '<div class="cart-upload-row">' +
                (hasFile
                  ? '<span class="cart-upload-done">&#128206; ' + fileLabel + ' <button onclick="clearArtwork(\'' + item.id + '\')" style="background:none;border:none;color:#aaa;cursor:pointer;font-size:11px;margin-left:4px">✕</button></span>'
                  : '<label class="cart-upload-btn" for="cart-file-' + item.id + '">&#128196; Upload Artwork <input type="file" id="cart-file-' + item.id + '" style="display:none" accept=".ai,.pdf,.eps,.png,.jpg,.jpeg" onchange="cartUploadFile(this,\'' + item.id + '\')"></label>') +
              '</div>'
          ) +
        '</div>' +
        '<div class="cart-item-right">' +
          '<div class="cart-item-price">' + priceFmt + '</div>' +
          '<button class="cart-remove-btn" onclick="removeItem(\'' + item.id + '\')">&#128465; Remove</button>' +
        '</div>' +
      '</div>';
  }
  wrap.innerHTML = itemsHtml;

  if (sidebar) {
    var rowsHtml = cart.map(function(it){
      return '<div class="cart-summary-row"><span>' + (it.product||'Item') + ' &times;' + it.qty + '</span><span style="font-weight:700;color:#0a0a0a">S$' + Number(it.price).toFixed(2) + '</span></div>';
    }).join('');
    sidebar.innerHTML =
      '<div class="cart-summary">' +
        '<div class="cart-summary-title"><span>&#128722;</span> Order Summary</div>' +
        '<div class="cart-sum-items">' + rowsHtml + '</div>' +
        '<div class="cart-sum-totals">' +
          '<div class="cart-sum-line"><span>Subtotal</span><span>S$' + subtotal.toFixed(2) + '</span></div>' +
          '<hr class="cart-summary-divider">' +
          '<div class="cart-summary-total"><span class="cart-summary-total-label">Total</span><span class="cart-summary-total-price">S$' + subtotal.toFixed(2) + '</span></div>' +
          '<div class="cart-summary-gst">GST inclusive where applicable</div>' +
        '</div>' +
        '<button class="cart-checkout-btn" onclick="goSub(\'checkout\')">Proceed to Checkout &rarr;</button>' +
        '<div class="cart-guarantees">' +
          '<div class="cart-guarantee">Artwork proofing before we print</div>' +
          '<div class="cart-guarantee">Mockup approval on every order</div>' +
          '<div class="cart-guarantee">Island-wide delivery available</div>' +
          '<div class="cart-guarantee">Paya Lebar Square — self-collect welcome</div>' +
        '</div>' +
      '</div>';
  }
}

function cartUploadFile(input, itemId) {
  var file = input.files[0];
  if (!file) return;
  for (var i = 0; i < cart.length; i++) {
    if (cart[i].id === itemId) { cart[i].file = file.name; break; }
  }
  renderCart();
}

function clearArtwork(itemId) {
  for (var i = 0; i < cart.length; i++) {
    if (cart[i].id === itemId) { cart[i].file = ''; break; }
  }
  renderCart();
}
function removeItem(id){cart=cart.filter(function(i){return i.id!==id;});renderCart();updateCartCount();}

