function renderOrders(){
 var list=document.getElementById('orders-list');
 var orders=DB.getOrders().filter(function(o){return o.userId===session.id;});
 if(!orders.length){
  list.innerHTML='<div class="ords-empty"><div class="ords-empty-icon">&#128230;<\/div><div class="ords-empty-msg">No orders yet<\/div><div class="ords-empty-sub">Your orders will appear here once placed.<\/div><button class="ords-shop-btn" onclick="go(\'shop\')">Browse Products<\/button><\/div>';
  return;
 }
 var statusClass={'Pending':'b-pend','Processing':'b-proc','Ready':'b-ready','Completed':'b-done'};
 var out='';
 for(var i=0;i<orders.length;i++){
  var o=orders[i];
  var its='';
  for(var j=0;j<o.items.length;j++){
   var item=o.items[j];
   its+='<div class="oc-item-row"><div class="oc-item-icon">'+item.icon+'<\/div><div><div class="oc-item-name">'+item.product+'<span class="oc-item-spec">Qty: '+item.qty+(item.unit?' '+item.unit:'')+'<\/span><\/div><\/div><div style="margin-left:auto;font-size:13px;font-weight:700;color:#0a0a0a;flex-shrink:0">S$'+item.price.toFixed(2)+'<\/div><\/div>';
  }
  var sc=statusClass[o.status]||'b-pend';
  out+='<div class="oc">'+
   '<div class="oc-hd">'+
    '<div><div class="oc-num">'+o.id+'<\/div><div class="oc-dt">'+o.createdAt+'<\/div><\/div>'+
    '<span class="badge '+sc+'">'+o.status+'<\/span>'+
   '<\/div>'+
   '<div class="oc-its">'+its+'<\/div>'+
   '<div class="oc-ft">'+
    '<span class="oc-method">&#128230; '+o.method+'<\/span>'+
    '<span class="oc-tot">S$'+o.total.toFixed(2)+'<\/span>'+
   '<\/div>'+
  '<\/div>';
 }
 list.innerHTML=out;
}

