// -- Order management (delegates to admLoadOrders) --
function adminLoadOrders() { admLoadOrders(); admLoadDashboard(); }
function adminRenderOrders() { admLoadOrders(); }
function adminFilterOrders() { admLoadOrders(); }

function admLoadDashboard() {
  var orders = DB.getOrders();
  var rev=0, pending=0;
  var byMethod={}, byType={service:0,gift:0}, giftJobs=[];
  orders.forEach(function(o) {
    rev += parseFloat(o.total||0);
    if (o.status==='Pending'||o.status==='Processing') pending++;
    (o.items||[]).forEach(function(it) {
      var t=it.productType||(it.isGift?'gift':'service');
      byType[t]=(byType[t]||0)+1;
      var m=it.method||it.productionMethod||'';
      if(m) byMethod[m]=(byMethod[m]||0)+1;
      if((t==='gift'||it.giftImage||it.isGift)&&(o.status==='Pending'||o.status==='Processing'))
        giftJobs.push({o:o,it:it});
    });
    if(!(o.items||[]).length){var t=o.orderType||'service';byType[t]=(byType[t]||0)+1;}
  });
  var el=function(id,v){var e=document.getElementById(id);if(e)e.textContent=v;};
  el('ds-orders',orders.length); el('ds-rev','S$'+rev.toFixed(2));
  el('ds-pending',pending); el('ds-services',byType.service); el('ds-gifts',byType.gift);

  var mb=document.getElementById('ds-method-breakdown');
  if(mb){var mk=Object.keys(byMethod).sort();mb.innerHTML=!mk.length?'<div style="font-size:12px;color:#aaa;padding:6px 0">No production method data yet</div>':mk.map(function(m){return '<div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid #f5f5f5;font-size:13px"><span>'+m+'</span><span style="font-weight:700;color:#E91E8C">'+byMethod[m]+'</span></div>';}).join('');}

  var gq=document.getElementById('ds-gift-queue');
  if(gq){var SC={Pending:'#f59e0b',Processing:'#3b82f6'};gq.innerHTML=!giftJobs.length?'<div style="font-size:12px;color:#aaa;padding:6px 0">No pending gift jobs</div>':giftJobs.slice(0,8).map(function(g){var it=g.it,o=g.o;var th=it.giftImage?'<img src="'+it.giftImage+'" style="width:44px;height:44px;object-fit:cover;border-radius:3px;border:1px solid #eee;flex-shrink:0">':'<div style="width:44px;height:44px;background:#f5f5f5;border-radius:3px;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0">'+(it.icon||'&#127873;')+'</div>';var mt=(it.method||it.productionMethod)?'<span style="font-size:9px;background:#f0f4ff;color:#3b5bdb;border:1px solid #c7d7fd;padding:1px 5px;border-radius:10px;margin-left:4px">'+(it.method||it.productionMethod)+'</span>':'';return '<div style="display:flex;align-items:center;gap:10px;padding:7px 0;border-bottom:1px solid #f5f5f5">'+th+'<div style="flex:1;min-width:0"><div style="font-size:12px;font-weight:700">'+(it.product||it.name||'Gift')+mt+'</div><div style="font-size:11px;color:#888">'+(o.customer||'Guest')+' &bull; '+o.id+'</div>'+(it.notes?'<div style="font-size:10px;color:#555;margin-top:1px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+it.notes+'</div>':'')+('</div><span style="font-size:10px;font-weight:700;color:'+(SC[o.status]||'#aaa')+'">'+o.status+'</span></div>');}).join('');}

  var ro=document.getElementById('ds-order-list');
  if(ro){if(!orders.length){ro.innerHTML='<div style="font-size:12px;color:#aaa;padding:16px 0;text-align:center">No orders yet.</div>';}else{var SC2={Pending:'#f59e0b',Processing:'#3b82f6',Ready:'#8b5cf6',Completed:'#22c55e'};ro.innerHTML=orders.slice().reverse().slice(0,8).map(function(o){var tBg=o.orderType==='gift'?'#fff0f7':'#f0f4ff',tC=o.orderType==='gift'?'#E91E8C':'#3b5bdb',tTx=o.orderType==='gift'?'Gift':'Service';return '<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-bottom:1px solid #f5f5f5;gap:8px"><div style="min-width:0"><div style="font-size:13px;font-weight:700">'+(o.id||'—')+'<span style="font-size:9px;background:'+tBg+';color:'+tC+';padding:1px 5px;border-radius:10px;margin-left:5px">'+tTx+'</span></div><div style="font-size:11px;color:#888">'+(o.customer||'Guest')+' &bull; '+(o.createdAt||'')+'</div></div><div style="text-align:right;flex-shrink:0"><div style="font-size:13px;font-weight:700">S$'+parseFloat(o.total||0).toFixed(2)+'</div><span style="font-size:10px;font-weight:700;color:'+(SC2[o.status]||'#aaa')+'">'+o.status+'</span></div></div>';}).join('');}}
}
function adminUpdateStatus(orderId, newStatus) {
 var orders = DB.getOrders();
 for (var i = 0; i < orders.length; i++) {
  if (orders[i].id === orderId) { orders[i].status = newStatus; break; }
 }
 DB.saveOrders(orders);
 admLoadOrders();
 showToast('Order '+ orderId + ' → '+ newStatus);
}

function adminDeleteOrder(orderId) {
 if (!confirm('Delete order '+ orderId + '?')) return;
 var orders = DB.getOrders().filter(function(o){ return o.id !== orderId; });
 DB.saveOrders(orders);
 admLoadOrders();
 showToast('Order deleted');
}

function showToast(msg){
 var t=document.getElementById('toast');
 if(!t)return;
 t.textContent=msg;
 t.classList.add('show');
 clearTimeout(tTimer);
 tTimer=setTimeout(function(){t.classList.remove('show');},2500);
}

