// ==============================================
// ADMIN EXPORT FUNCTIONS
// ==============================================
function admCsvDownload(filename, rows) {
 var csv = rows.map(function(r) {
 return r.map(function(cell) {
 var s = (cell === null || cell === undefined) ? '': String(cell);
 if (s.indexOf(',') !== -1 || s.indexOf('"') !== -1 || s.indexOf('\n') !== -1) {
 s = '"'+ s.replace(/"/g, '""') + '"';
 }
 return s;
 }).join(',');
 }).join('\n');
 var blob = new Blob([csv], {type:'text/csv;charset=utf-8;'});
 var url = URL.createObjectURL(blob);
 var a = document.createElement('a');
 a.href = url;
 a.download = filename;
 a.click();
 URL.revokeObjectURL(url);
}

function admExportOrders() {
 var orders = DB.getOrders();
 if (!orders.length) { showToast('No orders to export'); return; }
 var rows = [['Order ID','Customer','Email','Phone','Company','Position','Collection Method','Items','Subtotal','Delivery','Points Discount','Total','Status','Date']];
 orders.forEach(function(o) {
 var itemNames = (o.items||[]).map(function(i){ return (i.name||i.product||'') + (i.qty > 1 ? 'x'+i.qty : ''); }).join('| ');
 rows.push([
 o.id||'',
 o.customer||'',
 o.email||'',
 o.phone||'',
 o.company||'',
 o.position||'',
 o.method||'',
 itemNames,
 (o.subtotal||0).toFixed(2),
 (o.delivery||0).toFixed(2),
 (o.ptsDiscount||0).toFixed(2),
 (o.total||0).toFixed(2),
 o.status||'',
 o.createdAt||'']);
 });
 var date = new Date().toISOString().slice(0,10);
 admCsvDownload('PV-Orders-'+ date + '.csv', rows);
 showToast('Exported '+ orders.length + 'orders');
}

function admExportCustomers() {
 var members = DB.getMembers();
 var keys = Object.keys(members);
 var orders = DB.getOrders();
 if (!keys.length) { showToast('No customers to export'); return; }
 // Build order count + last order per customer
 var orderMap = {};
 orders.forEach(function(o) {
 var e = (o.email||'').toLowerCase();
 if (!orderMap[e]) orderMap[e] = {count:0, total:0, last:''};
 orderMap[e].count++;
 orderMap[e].total += (o.total||0);
 if (!orderMap[e].last || o.createdAt > orderMap[e].last) orderMap[e].last = o.createdAt||'';
 });
 var rows = [['Name','Email','Points Balance','Total Points Earned','Orders','Total Spend (S$)','Last Order','Member Since']];
 keys.forEach(function(k) {
 var m = members[k];
 var om = orderMap[k] || {count:0, total:0, last:''};
 rows.push([
 m.name||'',
 m.email||k,
 m.points||0,
 m.totalEarned||0,
 om.count,
 om.total.toFixed(2),
 om.last,
 m.joinedAt||'']);
 });
 var date = new Date().toISOString().slice(0,10);
 admCsvDownload('PV-Customers-'+ date + '.csv', rows);
 showToast('Exported '+ keys.length + 'customers');
}

// ==============================================
// STAFF DASHBOARD
// ==============================================
var STAFF_PIN = '1234'; // change this
var sfAuthed = false;
var sfCurrentTab = 'all';
var sfPinBuffer = '';
var sfClockInterval = null;

function sfKey(k) {
 var err = document.getElementById('sf-pin-err');
 if (err) err.textContent = '';
 if (k === 'clear') { sfPinBuffer = ''; sfUpdateDots(); return; }
 if (k === 'del') { sfPinBuffer = sfPinBuffer.slice(0,-1); sfUpdateDots(); return; }
 if (sfPinBuffer.length >= 4) return;
 sfPinBuffer += k;
 sfUpdateDots();
 if (sfPinBuffer.length === 4) {
 setTimeout(sfCheckPin, 80);
 }
}

function sfUpdateDots() {
 for (var i = 0; i < 4; i++) {
 var d = document.getElementById('sfd'+ i);
 if (d) d.className = 'sf-pin-dot'+ (i < sfPinBuffer.length ? 'filled': '');
 }
}

function sfCheckPin() {
 if (sfPinBuffer === STAFF_PIN) {
 sfAuthed = true;
 document.getElementById('sf-login-view').style.display = 'none';
 document.getElementById('sf-dash-view').style.display = 'block';
 sfLoad();
 sfStartClock();
 } else {
 var err = document.getElementById('sf-pin-err');
 if (err) err.textContent = 'Incorrect PIN. Try again.';
 sfPinBuffer = '';
 sfUpdateDots();
 // shake the dots
 var dots = document.getElementById('sf-pin-dots');
 if (dots) {
 dots.style.animation = 'none';
 dots.style.transform = 'translateX(6px)';
 setTimeout(function(){ dots.style.transform = 'translateX(-6px)'; }, 80);
 setTimeout(function(){ dots.style.transform = ''; }, 160);
 }
 }
}

function sfLogout() {
 sfAuthed = false;
 sfPinBuffer = '';
 sfUpdateDots();
 document.getElementById('sf-login-view').style.display = 'flex';
 document.getElementById('sf-dash-view').style.display = 'none';
 if (sfClockInterval) clearInterval(sfClockInterval);
 go('home');
}

function sfStartClock() {
 function tick() {
 var el = document.getElementById('sf-clock');
 if (el) el.textContent = new Date().toLocaleTimeString('en-SG', {hour:'2-digit',minute:'2-digit',hour12:true});
 }
 tick();
 sfClockInterval = setInterval(tick, 15000);
}

function sfLoad() {
 var orders = DB.getOrders();
 // Stats
 var counts = {Pending:0, Processing:0, Ready:0, Completed:0};
 var todayStr = new Date().toLocaleDateString('en-SG');
 var todayCount = 0;
 for (var i = 0; i < orders.length; i++) {
 var o = orders[i];
 if (counts[o.status] !== undefined) counts[o.status]++;
 if (o.createdAt && o.createdAt.indexOf(todayStr) !== -1) todayCount++;
 }
 var sp = document.getElementById('sf-stat-pending'); if (sp) sp.textContent = counts.Pending;
 var spr = document.getElementById('sf-stat-processing'); if (spr) spr.textContent = counts.Processing;
 var sr = document.getElementById('sf-stat-ready'); if (sr) sr.textContent = counts.Ready;
 var st = document.getElementById('sf-stat-today'); if (st) st.textContent = todayCount;
 sfRender();
}

function sfSetTab(btn) {
 document.querySelectorAll('.sf-tab').forEach(function(b){ b.classList.remove('on'); });
 btn.classList.add('on');
 sfCurrentTab = btn.dataset.s;
 sfRender();
}

function sfRender() {
  var orders = DB.getOrders();
  var q = ((document.getElementById('sf-search')||{}).value || '').toLowerCase().trim();
  var filtered = orders.filter(function(o) {
    var matchTab = sfCurrentTab === 'all' || o.status === sfCurrentTab;
    var matchQ = !q ||
      (o.id||'').toLowerCase().indexOf(q) !== -1 ||
      (o.customer||'').toLowerCase().indexOf(q) !== -1 ||
      (o.email||'').toLowerCase().indexOf(q) !== -1 ||
      (o.phone||'').toLowerCase().indexOf(q) !== -1 ||
      (o.items||[]).some(function(it){ return (it.product||it.name||'').toLowerCase().indexOf(q) !== -1; });
    return matchTab && matchQ;
  });

  var list  = document.getElementById('sf-orders-list');
  var empty = document.getElementById('sf-empty');
  if (!list) return;

  if (!filtered.length) {
    list.innerHTML = '';
    if (empty) empty.style.display = 'block';
    return;
  }
  if (empty) empty.style.display = 'none';

  var STATUS_ORDER = {Pending:0, Processing:1, Ready:2, Completed:3};
  filtered.sort(function(a,b){
    return (STATUS_ORDER[a.status]||0) - (STATUS_ORDER[b.status]||0);
  });

  var SC = {
    Pending:   {bg:'#f59e0b', text:'#fff'},
    Processing:{bg:'#3b82f6', text:'#fff'},
    Ready:     {bg:'#10b981', text:'#fff'},
    Completed: {bg:'#9ca3af', text:'#fff'},
  };

  var html = '';
  for (var i = 0; i < filtered.length; i++) {
    var o = filtered[i];

    // ── Item rows ──────────────────────────────────────────────────────────────
    var itemsHtml = '';
    var hasGiftItems = false;
    if (o.items && o.items.length) {
      o.items.forEach(function(it) {
        var method = it.method || it.productionMethod || '';
        var isGift = it.productType === 'gift' || it.isGift || !!it.giftImage;
        if (isGift) hasGiftItems = true;

        var thumb;
        if (it.giftSides && it.giftSides.length > 1) {
          // Multi-side — show thumbnails row
          thumb = '<div style="display:flex;gap:4px;flex-shrink:0;align-items:flex-start">'+
            it.giftSides.slice(0,4).map(function(s){
              return s.image
                ? '<div style="text-align:center"><img src="'+s.image+'" style="width:48px;height:48px;object-fit:cover;border-radius:3px;border:1px solid #e0e0e0;display:block"><div style="font-size:8px;color:#aaa;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:48px">'+s.name+'</div></div>'
                : '';
            }).join('')+
          '</div>';
        } else if (it.giftImage) {
          thumb = '<img src="'+it.giftImage+'" style="width:56px;height:56px;object-fit:cover;border-radius:4px;border:1px solid #e0e0e0;flex-shrink:0">';
        } else {
          thumb = '<div class="sf-item-icon">'+(it.icon||'&#128230;')+'</div>';
        }

        var methodTag = method
          ? '<span style="font-size:9px;font-weight:700;background:#f0f4ff;color:#3b5bdb;border:1px solid #c7d7fd;padding:2px 6px;border-radius:8px;margin-left:5px">'+method+'</span>'
          : '';

        var notesHtml = it.notes
          ? '<div style="font-size:11px;color:#555;margin-top:5px;padding:6px 8px;background:#fafafa;border-left:2px solid #e0e0e0;border-radius:2px;line-height:1.5">'+it.notes+'</div>'
          : '';

        var qty = it.qty > 1 ? '<span style="font-size:11px;font-weight:700;background:#f0f0f0;color:#555;padding:1px 6px;border-radius:10px;margin-left:4px">&times;'+it.qty+'</span>' : '';

        itemsHtml +=
          '<div class="sf-item-row">'+
            thumb+
            '<div style="flex:1;min-width:0">'+
              '<div class="sf-item-name">'+(it.name||it.product||'Item')+qty+methodTag+'</div>'+
              '<div class="sf-item-spec">'+(it.config||it.spec||'')+'</div>'+
              notesHtml+
            '</div>'+
            '<div class="sf-item-price">S$'+((it.price||0)*(it.qty||1)).toFixed(2)+'</div>'+
          '</div>';
      });
    } else {
      itemsHtml = '<div style="font-size:12px;color:#aaa;padding:8px 0">No item details</div>';
    }

    // ── Status buttons ─────────────────────────────────────────────────────────
    var btnRow = ['Pending','Processing','Ready','Completed'].map(function(s){
      var isActive = o.status === s;
      return '<button class="sf-status-btn '+s+(isActive?' active':'')+'" data-oid="'+o.id+'" data-status="'+s+'" onclick="sfSetStatus(this)">'+
        (isActive ? '&#10003; ' : '') + s +
      '</button>';
    }).join('');

    // ── WA message ─────────────────────────────────────────────────────────────
    var waMsg = encodeURIComponent(
      'Hi '+(o.customer||'there')+', your order '+o.id+' is ready for collection at Paya Lebar Square #B1-35. '+
      'Opening hours: Mon–Sat 10am–7.30pm. Thank you! — Printvolution'
    );
    var waBtn = o.phone
      ? '<a class="sf-wa-btn" href="https://wa.me/65'+(o.phone||'').replace(/\D/g,'')+
        '?text='+waMsg+'" target="_blank">&#128172; WhatsApp</a>'
      : '';

    // ── Card header items summary (visible without opening) ────────────────────
    var itemSummary = '';
    if (o.items && o.items.length) {
      var names = o.items.slice(0,2).map(function(it){ return it.name||it.product||'Item'; });
      itemSummary = names.join(', ') + (o.items.length > 2 ? ' +' + (o.items.length-2) + ' more' : '');
    }

    // ── Gift badge on card ─────────────────────────────────────────────────────
    var giftBadge = hasGiftItems
      ? '<span style="font-size:9px;font-weight:700;background:#fff0f7;color:#E91E8C;border:1px solid #fcd6ea;padding:2px 7px;border-radius:8px;margin-right:4px">&#127873; Gift</span>'
      : '';

    var sc = SC[o.status] || {bg:'#888',text:'#fff'};
    var itemCount = o.items ? o.items.length : 0;

    html +=
      '<div class="sf-card" data-status="'+o.status+'" data-oid="'+o.id+'" id="sfc-'+o.id+'">'+

        // ── HEAD ──────────────────────────────────────────────────────────────
        '<div class="sf-card-head" onclick="sfToggleCard(\''+o.id+'\')">'+
          '<div style="min-width:0">'+
            '<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px">'+
              '<span class="sf-oid">'+o.id+'</span>'+
              giftBadge+
              '<span class="sf-status-badge '+o.status+'">'+o.status+'</span>'+
            '</div>'+
            '<div class="sf-cname">'+( o.customer||'Guest')+(o.company?' <span style="font-size:11px;font-weight:400;color:#aaa">· '+o.company+'</span>':'')+'</div>'+
            (itemSummary ? '<div style="font-size:11px;color:#aaa;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+itemSummary+'</div>' : '')+
          '</div>'+
          '<div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px;flex-shrink:0">'+
            '<div class="sf-ctotal">S$'+(o.total||0).toFixed(2)+'</div>'+
            '<div class="sf-ctime">'+(o.createdAt||'')+'</div>'+
            '<span class="sf-expand-arr">&#9660;</span>'+
          '</div>'+
        '</div>'+

        // ── BODY ──────────────────────────────────────────────────────────────
        '<div class="sf-card-body">'+

          // Items
          '<div class="sf-items-section">'+
            '<div class="sf-sec-title">Items ('+itemCount+')</div>'+
            itemsHtml+
          '</div>'+

          // Customer + Payment 2-col
          '<div class="sf-detail-grid">'+
            '<div class="sf-detail-section">'+
              '<div class="sf-ds-title">Customer</div>'+
              '<div class="sf-ds-row"><span class="sf-ds-label">Name</span><span class="sf-ds-val">'+(o.customer||'—')+'</span></div>'+
              (o.phone ? '<div class="sf-ds-row"><span class="sf-ds-label">Mobile</span><span class="sf-ds-val"><a href="tel:'+o.phone+'" style="color:#E91E8C;font-weight:700;text-decoration:none">'+o.phone+'</a></span></div>' : '')+
              (o.email ? '<div class="sf-ds-row"><span class="sf-ds-label">Email</span><span class="sf-ds-val" style="font-size:11px">'+o.email+'</span></div>' : '')+
              (o.company ? '<div class="sf-ds-row"><span class="sf-ds-label">Company</span><span class="sf-ds-val">'+o.company+'</span></div>' : '')+
              '<div class="sf-ds-row"><span class="sf-ds-label">Collection</span><span class="sf-ds-val">'+(o.method||'—')+'</span></div>'+
            '</div>'+
            '<div class="sf-detail-section">'+
              '<div class="sf-ds-title">Payment</div>'+
              '<div class="sf-ds-row"><span class="sf-ds-label">Subtotal</span><span class="sf-ds-val">S$'+(o.subtotal||0).toFixed(2)+'</span></div>'+
              (o.delivery ? '<div class="sf-ds-row"><span class="sf-ds-label">Delivery</span><span class="sf-ds-val">S$'+(o.delivery||0).toFixed(2)+'</span></div>' : '')+
              (o.ptsRedeemed > 0 ? '<div class="sf-ds-row"><span class="sf-ds-label">Points</span><span class="sf-ds-val" style="color:#E91E8C">−S$'+(o.ptsDiscount||0).toFixed(2)+'</span></div>' : '')+
              '<div class="sf-ds-row" style="padding-top:6px;margin-top:2px;border-top:1px solid #f0f0f0"><span class="sf-ds-label" style="font-size:13px;font-weight:800;color:#0a0a0a">Total</span><span class="sf-ds-val" style="font-size:15px;font-weight:800;color:#0a0a0a">S$'+(o.total||0).toFixed(2)+'</span></div>'+
              '<div class="sf-ds-row"><span class="sf-ds-label">Ordered</span><span class="sf-ds-val">'+(o.createdAt||'—')+'</span></div>'+
            '</div>'+
          '</div>'+

          // Action bar
          '<div class="sf-actions">'+
            '<span class="sf-action-label">Move to:</span>'+
            btnRow+
            waBtn+
            (hasGiftItems
              ? o.items.map(function(it,iidx){
                  return (it.giftImage||it.giftSides)
                    ? '<button onclick="admDownloadGiftPdf(\''+ o.id +'\','+iidx+')" style="padding:8px 12px;font-size:12px;font-weight:700;background:#f0f4ff;border:1.5px solid #c7d7fd;color:#3b5bdb;cursor:pointer;font-family:var(--sans);border-radius:3px;white-space:nowrap;transition:all .15s">&#128196; PDF'+(o.items.length>1?' ('+(iidx+1)+')':'')+'</button>'
                    : '';
                }).join('')
              : '')+
          '</div>'+

        '</div>'+
      '</div>';
  }
  list.innerHTML = html;
}

function sfToggleCard(oid) {
 var card = document.getElementById('sfc-'+ oid);
 if (card) card.classList.toggle('open');
}

function sfSetStatus(btn) {
 var oid = btn.dataset.oid;
 var newStatus = btn.dataset.status;
 var orders = DB.getOrders();
 for (var i = 0; i < orders.length; i++) {
   if (orders[i].id === oid) { orders[i].status = newStatus; break; }
 }
 DB.saveOrders(orders);
 showToast('Order '+ oid + ' → '+ newStatus);
 sfRender();
 // re-open the card
 setTimeout(function(){
 var card = document.getElementById('sfc-'+ oid);
 if (card) card.classList.add('open');
 }, 50);
}


