document.addEventListener('DOMContentLoaded',function(){
 try{ var _e=JSON.parse(localStorage.getItem('pv_pp_extra')||'null'); if(_e) Object.keys(_e).forEach(function(s){ PP_EXTRA[s]=Object.assign(PP_EXTRA[s]||{},_e[s]); }); }catch(e){}
 try{ var _o=JSON.parse(localStorage.getItem('pv_prod_overrides')||'null'); if(_o) Object.keys(_o).forEach(function(s){ if(PRODUCTS_DATA[s]) Object.assign(PRODUCTS_DATA[s],_o[s]); }); }catch(e){}
 admLoadFonts();
 seedSampleOrders();
 renderNav();
 renderMegaMenus();
 // Hash routing: #product-slug, #bundle-id, or default home
 var hash = window.location.hash;
 if (hash.indexOf('#product-') === 0) {
 var slug = hash.replace('#product-', '');
 if (PRODUCTS_DATA[slug]) { goProduct(slug); return; }
 } else if (hash.indexOf('#bundle-') === 0) {
 var bid = hash.replace('#bundle-', '');
 var found = BUNDLES && BUNDLES.find(function(b){ return b.id === bid; });
 if (found) { setTimeout(function(){ goBundlePage(bid); }, 100); return; }
 }
 go('home');
 setTimeout(renderHomeBundles, 100);
});

