         '<input class="adm-gc-style-desc" data-si="'+si+'" value="'+(s.description||'').replace(/"/g,'&quot;')+'" placeholder="Short description shown to customer (optional)" style="border:1px solid #e0e0e0;padding:5px 9px;font-size:11px;font-family:var(--sans);color:#888;width:100%;box-sizing:border-box">' +
       '</div>' +
       '<button class="adm-row-del" style="margin:0;flex-shrink:0" onclick="admGcStyleRemove('+si+')">&#215;</button>' +
     '</div>';
