// ── Admin Gift Flow helpers ───────────────────────────────────────────────────
var _GF_METHOD_FLOW = {};
(function(){
  DB.getMethods().forEach(function(m){
    if(m.flowType && m.flowType !== 'none') _GF_METHOD_FLOW[m.name] = m.flowType;
  });
})();

function peTypeChanged() {
  var t = (document.getElementById('pe-type')||{}).value || 'service';
  var w = document.getElementById('pe-gift-flow-wrap');
  if (w) w.style.display = t === 'gift' ? '' : 'none';
}

function peMethodChanged() {
  var method = (document.getElementById('pe-method')||{}).value || '';
  // Rebuild _GF_METHOD_FLOW from current DB in case methods were updated
  var methods = DB.getMethods();
  methods.forEach(function(m){ if(m.flowType && m.flowType!=='none') _GF_METHOD_FLOW[m.name]=m.flowType; });
  var suggested = _GF_METHOD_FLOW[method] || '';
  var fEl = document.getElementById('pe-flow-type');
  if (fEl && suggested && (!fEl.value || fEl.value === 'none')) {
    fEl.value = suggested;
    peFlowTypeChanged();
  }
  // Populate base prompt with method default if field is empty
  var bpEl = document.getElementById('pe-base-prompt');
  if (bpEl && !bpEl.value.trim()) {
    var mData = methods.filter(function(m){return m.name===method;})[0] || {};
    if (mData.basePrompt) bpEl.value = mData.basePrompt;
  }
}

function peFlowTypeChanged() {
  var v = (document.getElementById('pe-flow-type')||{}).value || 'none';
  var tEl  = document.getElementById('pe-transform-cfg');
  var oEl  = document.getElementById('pe-overlay-cfg');
  var tmEl = document.getElementById('pe-template-cfg');
  if (tEl)  tEl.style.display  = (v === 'transform') ? '' : 'none';
  if (oEl)  oEl.style.display  = (v === 'overlay')   ? '' : 'none';
  if (tmEl) tmEl.style.display = (v === 'template')  ? '' : 'none';

  // Refresh preview when flow type changes
  if (v === 'overlay' || v === 'template') {
    setTimeout(function(){ peOverlayPreview(); peOvPreviewWireDrag(); }, 50);
  }
}
// -- Admin overlay: ratio hint badge (second copy) --
function peUpdateRatioHint() {
  var _mwE = document.getElementById('pe-mock-w');
  var _mhE = document.getElementById('pe-mock-h');
  var hintEl = document.getElementById('pe-mock-ratio-hint');
  if (!hintEl) return;
  var w = parseFloat(_mwE && _mwE.value) || 0;
  var h = parseFloat(_mhE && _mhE.value) || 0;
  if (w > 0 && h > 0) {
    function gcd(a,b){a=Math.round(a);b=Math.round(b);return b===0?a:gcd(b,a%b);}
    var g=gcd(w,h), rw=Math.round(w/g), rh=Math.round(h/g);
    if(rw>20||rh>20){rw=Math.round(w);rh=Math.round(h);}
    admIuSetRatio('pe-mockup-uploader', w/h);
    hintEl.textContent = rw+':'+rh+' ratio';
    hintEl.style.cssText='font-size:11px;font-weight:700;color:#3b5bdb;background:#e8f0fe;border:1px solid #c7d7fd;padding:4px 10px;border-radius:4px;white-space:nowrap;display:inline-block';
  } else {
    hintEl.style.display='none';
  }
}



// ── Snapshot current form state into memory before any row add/remove ─────────
function peSnapshotForm() {
  var slug = admCurrentSlug;
  if (!slug) return;
  var p  = PRODUCTS_DATA[slug];
  var ex = PP_EXTRA[slug] || (PP_EXTRA[slug] = {});
  if (!p) return;

  // Basic fields
  var fv = function(id){ var e=document.getElementById(id); return e?e.value:''; };
  if (fv('pe-name'))    p.name    = fv('pe-name');
  if (fv('pe-tagline')) p.tagline = fv('pe-tagline');
  if (fv('pe-desc'))    p.description = fv('pe-desc');
  if (fv('pe-h1'))      ex.h1     = fv('pe-h1');
  if (fv('pe-h1em'))    ex.h1em   = fv('pe-h1em');
  if (fv('pe-herobig')) ex.heroBig = fv('pe-herobig');
  if (fv('pe-hcolor-txt')) ex.heroColor = fv('pe-hcolor-txt');

  // Type + method
  var peType = document.getElementById('pe-type');
  if (peType) p.type = peType.value || 'service';
  var peMethod = document.getElementById('pe-method');
  if (peMethod && peMethod.value) {
    if (!ex.giftConfig) ex.giftConfig = {};
    ex.giftConfig.method = peMethod.value;
  }

  // Flow type
  var peFlowType = document.getElementById('pe-flow-type');
  if (peFlowType && peFlowType.value) {
    if (!ex.giftConfig) ex.giftConfig = {};
    ex.giftConfig.flowType = peFlowType.value !== 'none' ? peFlowType.value : undefined;
  }

  // Base prompt
  var peBP = document.getElementById('pe-base-prompt');
  if (peBP !== null) {
    if (!ex.giftConfig) ex.giftConfig = {};
    ex.giftConfig.basePrompt = peBP.value.trim() || undefined;
  }

  // Style rows
  var srRows = document.querySelectorAll('#pe-style-rows > div[id^="pe-sr-"]');
  if (srRows.length) {
    if (!ex.giftConfig) ex.giftConfig = {};
    var stls = [];
    srRows.forEach(function(row, si) {
      var lbl = (row.querySelector('.pe-style-label[data-si="'+si+'"]')||{}).value||'';
      var prm = (row.querySelector('.pe-style-prompt[data-si="'+si+'"]')||{}).value||'';
      if (lbl || prm) stls.push({label:lbl, prompt:prm});
    });
    ex.giftConfig.styleOptions = stls.length ? stls : undefined;
  }

  // Overlay rows
  var orRows = document.querySelectorAll('#pe-overlay-rows > div[id^="pe-or-"]');
  if (orRows.length) {
    if (!ex.giftConfig) ex.giftConfig = {};
    var lyrs = [];
    orRows.forEach(function(row, li) {
      var g  = function(cls){ var e=row.querySelector('.'+cls+'[data-li="'+li+'"]'); return e?e.value:''; };
      var gN = function(cls){ return parseFloat(g(cls))||0; };
      var gCk= function(cls){ var e=row.querySelector('.'+cls+'[data-li="'+li+'"]'); return e?e.checked:false; };
      lyrs.push({
        label:    g('pe-ov-label')||'Text',
        placeholder: g('pe-ov-ph'),
        x:   Math.max(1,Math.min(99,gN('pe-ov-x')||50)),
        y:   Math.max(1,Math.min(99,gN('pe-ov-y')||60)),
        fontSize: Math.max(8,gN('pe-ov-fs')||20),
        color:    g('pe-ov-color')||'#ffffff',
        fontStyle:g('pe-ov-font')||'Georgia, serif',
        align:'center',
        canMove:  gCk('pe-ov-canmove'),
        required: gCk('pe-ov-req')
      });
    });
    ex.giftConfig.textLayers = lyrs.length ? lyrs : undefined;
  }

  // Template rows
  var trRows = document.querySelectorAll('#pe-template-rows > div[id^="pe-tr-"]');
  if (trRows.length) {
    if (!ex.giftConfig) ex.giftConfig = {};
    var tFields = [];
    trRows.forEach(function(row, ti) {
      var g  = function(cls){ var e=row.querySelector('.'+cls+'[data-ti="'+ti+'"]'); return e?e.value:''; };
      var gN = function(cls){ return parseFloat(g(cls))||0; };
      var gCk= function(cls){ var e=row.querySelector('.'+cls+'[data-ti="'+ti+'"]'); return e?e.checked:false; };
      tFields.push({
        label: g('pe-tr-label')||'Field',
        placeholder: g('pe-tr-ph'),
        x: Math.max(1,Math.min(99,gN('pe-tr-x')||50)),
        y: Math.max(1,Math.min(99,gN('pe-tr-y')||50)),
        fontSize: Math.max(8,gN('pe-tr-fs')||24),
        color: g('pe-tr-color')||'#1a1a1a',
        align:'center',
        required: gCk('pe-tr-req')
      });
    });
    ex.giftConfig.templateFields = tFields.length ? tFields : undefined;
  }
}

