function admUcImgPreview(inp, i) {
  var url = inp.value.trim();
  // Convert Dropbox share links to direct
  url = url.replace('www.dropbox.com','dl.dropboxusercontent.com').replace('?dl=0','').replace('?dl=1','');
  var row = inp.closest('[style*="border:1px solid #e0e0e0;padding:10px"]');
  if (!row) return;
  var preview = row.querySelector('div[style*="width:64px;height:64px"]');
  if (preview) preview.innerHTML = url ? '<img src="'+url+'" style="width:64px;height:64px;object-fit:cover;border-radius:4px" onerror="this.parentNode.innerHTML=\'<span style=&quot;font-size:10px;color:#e44&quot;>Bad URL</span>\'">' : '<span style="font-size:10px;color:#aaa;text-align:center">No image</span>';
}
function admRemCfgOpt(si,oi) { var cfg=CONFIGURATOR[admCurrentSlug]; if(cfg&&cfg.steps[si]&&cfg.steps[si].options) cfg.steps[si].options.splice(oi,1); admOpenProduct(admCurrentSlug); }
function admAddCfgOpt(si) { var cfg=CONFIGURATOR[admCurrentSlug]; if(cfg&&cfg.steps[si]) { if(!cfg.steps[si].options)cfg.steps[si].options=[]; cfg.steps[si].options.push({slug:'new-option',label:'New Option',price_formula:'0'}); admOpenProduct(admCurrentSlug); } }
function admAddCfgStep() {
 var cfg=CONFIGURATOR[admCurrentSlug];
 if(!cfg){CONFIGURATOR[admCurrentSlug]={steps:[]};cfg=CONFIGURATOR[admCurrentSlug];}
 if(!cfg.steps) cfg.steps=[];
 var type=(document.getElementById('adm-new-step-type')||{}).value||'select';
 var label=(document.getElementById('adm-new-step-label')||{}).value||'New Step';
 var newStep={id:label.toLowerCase().replace(/\s+/g,'-'),label:label,type:type,required:true,options:[]};
 if(type==='qty') newStep={id:'qty',label:'Quantity',type:'qty',min:1,step:1,presets:[50,100,250,500]};
 if(type==='text') newStep.placeholder='Enter '+label;
 cfg.steps.push(newStep);
 admOpenProduct(admCurrentSlug);
}
function admMoveCfgStep(si, dir) {
  var cfg = CONFIGURATOR[admCurrentSlug];
  if (!cfg || !cfg.steps) return;
  var steps = cfg.steps;
  var newIdx = si + dir;
  if (newIdx < 0 || newIdx >= steps.length) return;
  // Don't move qty step — it's always conceptually "the qty"
  if (steps[si].type === 'qty' || steps[newIdx].type === 'qty') return;
  var tmp = steps[si];
  steps[si] = steps[newIdx];
  steps[newIdx] = tmp;
  admOpenProduct(admCurrentSlug);
}
function admRemCfgStep(si) {
 var cfg=CONFIGURATOR[admCurrentSlug];
 if(cfg&&cfg.steps) cfg.steps.splice(si,1);
 admOpenProduct(admCurrentSlug);
}
function admRemWhy(btn,i) { var ex=PP_EXTRA[admCurrentSlug]; if(ex&&ex.whyUs) ex.whyUs.splice(i,1); admOpenProduct(admCurrentSlug); }
function admAddWhy() { var ex=PP_EXTRA[admCurrentSlug]||(PP_EXTRA[admCurrentSlug]={}); if(!ex.whyUs)ex.whyUs=[]; ex.whyUs.push('New point'); admOpenProduct(admCurrentSlug); }
function admRemProdFaq(btn,i) { var ex=PP_EXTRA[admCurrentSlug]; if(ex&&ex.faq) ex.faq.splice(i,1); admOpenProduct(admCurrentSlug); }
function admAddProdFaq() { var ex=PP_EXTRA[admCurrentSlug]||(PP_EXTRA[admCurrentSlug]={}); if(!ex.faq)ex.faq=[]; ex.faq.push(['Question?','Answer.']); admOpenProduct(admCurrentSlug); }
function admRemPers(btn,i) { if(GIFT_PERSONALISATION&&GIFT_PERSONALISATION[admCurrentSlug]) GIFT_PERSONALISATION[admCurrentSlug].splice(i,1); admOpenProduct(admCurrentSlug); }
function admAddPers() { if(!GIFT_PERSONALISATION[admCurrentSlug])GIFT_PERSONALISATION[admCurrentSlug]=[]; GIFT_PERSONALISATION[admCurrentSlug].push({type:'text',label:'New Field',placeholder:'',required:false}); admOpenProduct(admCurrentSlug); }

