// ==== MEMBERS & POINTS ADMIN ====

function admLoadMembers() {
 var members = DB.getMembers();
 var keys = Object.keys(members);
 var orders = DB.getOrders();
 var countEl = document.getElementById('adm-mem-count');
 var outEl = document.getElementById('adm-pts-outstanding');
 if (countEl) countEl.textContent = keys.length;
 var totalPts = keys.reduce(function(s,k){ return s + (members[k].points||0); }, 0);
 if (outEl) outEl.textContent = totalPts.toLocaleString();
 admRenderMembers(members, orders, '');
}

function admRenderMembers(members, orders, filter) {
 var body = document.getElementById('adm-members-body');
 if (!body) return;
 var keys = Object.keys(members);
 if (filter) keys = keys.filter(function(k){ return k.includes(filter.toLowerCase()) || (members[k].name||'').toLowerCase().includes(filter.toLowerCase()); });
 if (!keys.length) { body.innerHTML = '<div style="padding:32px;text-align:center;color:#aaa;font-size:13px">No members found.</div>'; return; }
 // Sort by points desc
 keys.sort(function(a,b){ return (members[b].points||0) - (members[a].points||0); });
 var rows = keys.map(function(k) {
 var m = members[k];
 var orderCount = orders.filter(function(o){ return o.email && o.email.toLowerCase() === k; }).length;
 var pts = m.points || 0;
 var earned = m.totalEarned || 0;
 var div = document.createElement('div');
 div.className = 'adm-member-row';
 div.innerHTML =
 '<div><div style="font-weight:600">'+ (m.name||'—') + '</div><div style="font-size:11px;color:#888">'+ m.email + '</div></div>'+
 '<div><span class="adm-pts-badge">'+ pts.toLocaleString() + 'pts</span><div style="font-size:10px;color:#aaa;margin-top:2px">S$'+ (pts/1000).toFixed(2) + 'off avail.</div></div>'+
 '<div style="font-size:12px;color:#888">'+ earned.toLocaleString() + 'total</div>'+
 '<div style="font-size:12px">'+ orderCount + '</div>'+
 '<div></div>';
 var btn = document.createElement('button');
 btn.style.cssText = 'font-size:11px;padding:5px 10px;border:1px solid #e0e0e0;background:#fff;cursor:pointer;font-family:var(--sans)';
 btn.textContent = 'Adjust';
 btn.onclick = (function(email){ return function(){ admOpenPtsModal(email); }; })(k);
 div.lastElementChild.appendChild(btn);
 return div;
 });
 body.innerHTML = '';
 rows.forEach(function(r){ body.appendChild(r); });
}

function admFilterMembers(q) {
 admRenderMembers(DB.getMembers(), DB.getOrders(), q);
}

var admPtsModalEmail = '';
function admOpenPtsModal(email) {
 admPtsModalEmail = email;
 var modal = document.getElementById('adm-pts-modal');
 var label = document.getElementById('adm-pts-modal-email');
 var member = DB.getMember(email);
 if (label) label.textContent = email + '— Current balance: '+ ((member && member.points)||0).toLocaleString() + 'pts';
 if (modal) modal.style.display = 'flex';
 var inp = document.getElementById('adm-pts-adj');
 if (inp) inp.value = '';
}

function admClosePtsModal() {
 var modal = document.getElementById('adm-pts-modal');
 if (modal) modal.style.display = 'none';
}

function admApplyPtsAdj() {
 var adj = parseInt(document.getElementById('adm-pts-adj').value) || 0;
 if (!adj) { alert('Enter a points value.'); return; }
 var member = DB.getMember(admPtsModalEmail);
 DB.upsertMember(admPtsModalEmail, member ? member.name : '', adj);
 admClosePtsModal();
 admLoadMembers();
 admShowSaved('adm-global-saved');
}

