// ==== BUNDLE FRONT-END RENDER ====

function buildBundleCard(b, opts) {
 opts = opts || {};
 var saving = b.original - b.price;
 var pct = b.original > 0 ? Math.round(saving / b.original * 100) : 0;
 var chips = b.products.map(function(slug) {
  var name = PRODUCTS_DATA[slug] ? PRODUCTS_DATA[slug].name : slug;
  return '<span class="bun-prod-chip">'+ name + '</span>';
 }).join('');
 var bid = b.id;
 var html =
  '<div class="bun-card" onclick="goBundlePage(\''+ bid + '\')">' +
  (b.image ? '<div class="bun-card-img" style="background-image:url('+b.image+')" ></div>' : '') +
  (saving > 0 ? '<div class="bun-badge">Save S$'+ saving + '</div>' : '') +
  '<div class="bun-name">'+ b.name + '</div>' +
  '<div class="bun-desc">'+ (b.tagline || b.desc) + '</div>' +
  '<div class="bun-products">'+ chips + '</div>' +
  '<div class="bun-pricing">' +
    '<div class="bun-price">S$'+ b.price + '</div>' +
    (b.original > b.price ? '<div class="bun-orig">S$'+ b.original + '</div>' : '') +
    (saving > 0 ? '<div class="bun-saving">'+ pct + '% off</div>' : '') +
  '</div>' +
  '<div class="bun-card-actions">' +
    '<button class="bun-cta" onclick="event.stopPropagation();goBundlePage(\''+ bid + '\')">View Bundle &rarr;</button>' +
    '<button class="bun-cta-sec" onclick="event.stopPropagation();addBundleToCart(\''+ bid + '\')">Add to Cart</button>' +
  '</div>' +
  '</div>';
 return html;
}

function renderBundlesScreen() {
 var active = BUNDLES.filter(function(b){ return b.status === 'active'; });
 var grid = document.getElementById('bundles-grid');
 var empty = document.getElementById('bundles-empty');
 if (!grid) return;
 if (!active.length) {
 grid.innerHTML = '';
 if (empty) empty.style.display = 'block';
 return;
 }
 if (empty) empty.style.display = 'none';
 grid.innerHTML = active.map(function(b){ return buildBundleCard(b); }).join('');
}

function renderHomeBundles() {
 var grid = document.getElementById('home-bundle-grid');
 var section = document.getElementById('home-bundles-section');
 if (!grid) return;
 var active = BUNDLES.filter(function(b){ return b.status === 'active'; });
 if (!active.length) {
 if (section) section.style.display = 'none';
 return;
 }
 if (section) section.style.display = 'block';
 // Show max 3 on homepage
 grid.innerHTML = active.slice(0,3).map(function(b){ return buildBundleCard(b); }).join('');
}

function renderBundleCrossSell(slug) {
 var matching = BUNDLES.filter(function(b){
   return b.status === 'active' && b.products.indexOf(slug) > -1;
 });
 if (!matching.length) return '';
 var b = matching[0];
 var saving = b.original - b.price;
 var pct = b.original > 0 ? Math.round(saving / b.original * 100) : 0;
 var others = b.products.filter(function(s){ return s !== slug; }).map(function(s){
   return PRODUCTS_DATA[s] ? PRODUCTS_DATA[s].name : s;
 });
 var includedNames = b.products.map(function(s){
   return PRODUCTS_DATA[s] ? PRODUCTS_DATA[s].name : s;
 });
 var imgHtml = b.image
   ? '<div class="bun-cs-img" style="background-image:url('+b.image+')"></div>'
   : '<div class="bun-cs-noimg"><div class="bun-cs-noimg-icons">'
     + b.products.slice(0,3).map(function(s){ return '<span>'+(PRODUCTS_DATA[s]||{}).icon||'\uD83D\uDDA8'+'</span>'; }).join('')
     + '</div></div>';
 return '<div class="bun-cs-wrap">'
   + imgHtml
   + '<div class="bun-cs-body">'
   + '<div class="bun-cs-eyebrow">Bundle &amp; Save</div>'
   + '<div class="bun-cs-name">'+ b.name + '</div>'
   + '<div class="bun-cs-includes">'+ includedNames.join(' &middot; ') + '</div>'
   + '<div class="bun-cs-price-row">'
   + '<span class="bun-cs-price">S$'+ b.price + '</span>'
   + (b.original > b.price ? '<span class="bun-cs-orig">S$'+ b.original + '</span>' : '')
   + (saving > 0 ? '<span class="bun-cs-pct">'+ pct + '% off</span>' : '')
   + '</div>'
   + '</div>'
   + '<button class="bun-cs-btn" onclick="event.stopPropagation();goBundlePage(\''+ b.id + '\')">View Bundle &rarr;</button>'
   + '</div>';
}

function goBundlePage(id) {
 var b = BUNDLES.find(function(x){ return x.id === id; });
 if (!b) { go('bundles'); return; }
 var saving = b.original - b.price;
 var pct = b.original > 0 ? Math.round(saving / b.original * 100) : 0;

 // Hero
 var hero = document.getElementById('bdp-hero');
 if (hero) {
  if (b.image) {
   hero.style.backgroundImage = 'url('+ b.image +')';
   hero.style.backgroundSize = 'cover';
   hero.style.backgroundPosition = 'center';
   hero.style.cssText += ';background-color:#0D0D0D';
  } else {
   // No image — build a product-icon mosaic background using CSS
   // Pick gradient based on bundle name/id
   var gradients = {
     'b1': 'linear-gradient(135deg,#0D0D0D 0%,#1a0a1a 40%,#0D0D0D 100%)',
     'b2': 'linear-gradient(135deg,#0a0d10 0%,#0d1a14 40%,#0a0a0d 100%)',
   };
   var grad = gradients[b.id] || 'linear-gradient(135deg,#0D0D0D,#1a1a2e)';
   hero.style.backgroundImage = grad;
   hero.style.backgroundSize = '';
   hero.style.backgroundPosition = '';

   // Inject floating product icons into the hero grid div
   var gridEl = hero.querySelector('.bdp-hero-grid');
   if (gridEl) {
    var icons = (b.products||[]).slice(0,6).map(function(slug){
     return (PRODUCTS_DATA[slug]||{}).icon || '🖨️';
    });
    // Pad to 6
    while(icons.length < 6) icons.push('✦');
    var positions = [
     {top:'8%',left:'72%',size:'72px',opacity:.18,rotate:'-12deg'},
     {top:'28%',left:'82%',size:'52px',opacity:.12,rotate:'8deg'},
     {top:'58%',left:'76%',size:'64px',opacity:.15,rotate:'-5deg'},
     {top:'12%',left:'60%',size:'44px',opacity:.1,rotate:'15deg'},
     {top:'72%',left:'65%',size:'48px',opacity:.12,rotate:'-8deg'},
     {top:'42%',left:'88%',size:'40px',opacity:.1,rotate:'20deg'},
    ];
    gridEl.innerHTML = icons.map(function(ic,i){
     var p = positions[i];
     return '<div style="position:absolute;top:'+p.top+';left:'+p.left+';font-size:'+p.size+';opacity:'+p.opacity+';transform:rotate('+p.rotate+');pointer-events:none;user-select:none;filter:grayscale(1) brightness(3)">'+ic+'</div>';
    }).join('');
   }
  }
 }
 document.getElementById('bdp-h1').textContent = b.name;
 document.getElementById('bdp-tagline').textContent = b.tagline || b.desc;
 document.getElementById('bdp-eyebrow').textContent = 'Bundle & Save — '+ pct + '% off';

 // What's included tiles
 var whatGrid = document.getElementById('bdp-what-grid');
 whatGrid.innerHTML = b.products.map(function(slug) {
  var p = PRODUCTS_DATA[slug];
  if (!p) return '';
  var inc = (b.includes && b.includes[slug]) || {};
  var qty = inc.qty || '';
  var spec = inc.spec || p.tagline || '';
  var val = inc.value || '';
  return '<div class="bdp-prod-tile">'+
   '<div class="bdp-prod-header">'+
    '<span class="bdp-prod-icon">'+ p.icon +'</span>'+
    '<div class="bdp-prod-name">'+ p.name +'</div>'+
    (val ? '<div class="bdp-prod-val">'+ val +'</div>' : '')+
   '</div>'+
   (qty ? '<div class="bdp-prod-qty">'+ qty +'</div>' : '')+
   (spec ? '<div class="bdp-prod-desc">'+ spec +'</div>' : '')+
  '</div>';
 }).join('');

 // Why this bundle
 var whyList = document.getElementById('bdp-why-list');
 whyList.innerHTML = (b.why || []).map(function(w){
 return '<div class="bdp-why-item">'+ w + '</div>';
 }).join('');

 // FAQ
 var faqList = document.getElementById('bdp-faq-list');
 var faqWrap = document.getElementById('bdp-faq-wrap');
 if (b.faq && b.faq.length) {
 faqWrap.style.display = '';
 faqList.innerHTML = b.faq.map(function(f, i){
 return '<div class="bdp-faq-item" id="bdpfaq'+i+'">'+
 '<div class="bdp-faq-q" onclick="bdpToggleFaq('+ i +')">'+ f[0] + '<span class="bdp-faq-arr">&#9660;</span></div>'+
 '<div class="bdp-faq-a">'+ f[1] + '</div>'+
 '</div>';
 }).join('');
 } else {
 faqWrap.style.display = 'none';
 }

 // Sidebar price card
 document.getElementById('bdp-price-main').textContent = 'S$'+ b.price;
 document.getElementById('bdp-price-orig').textContent = b.original > b.price ? 'Usually S$'+ b.original : '';
 document.getElementById('bdp-price-saving').textContent = saving > 0 ? 'You save S$'+ saving + '('+ pct + '% off)': '';
 document.getElementById('bdp-badge').textContent = saving > 0 ? 'Save S$'+ saving : 'Bundle Deal';
 var includesList = document.getElementById('bdp-includes-list');
 includesList.innerHTML = b.products.map(function(slug) {
 var p = PRODUCTS_DATA[slug];
 return '<div class="bdp-includes-item">'+ (p ? p.name : slug) + '</div>';
 }).join('');
 document.getElementById('bdp-add-btn').onclick = function(){ addBundleToCart(b.id); };

 go('bundle-detail');
 try { window.history.replaceState(null, '', '#bundle-' + id); } catch(e) {}
}

function bdpToggleFaq(i) {
 var el = document.getElementById('bdpfaq'+i);
 if (el) el.classList.toggle('open');
}

function addBundleToCart(bundleId) {
 var b = BUNDLES.find(function(x){ return x.id === bundleId; });
 if (!b) return;
 // Add each product to cart
 b.products.forEach(function(slug) {
 var p = PRODUCTS_DATA[slug];
 if (!p) return;
 var item = {
 slug: slug,
 name: p.name,
 icon: p.icon,
 qty: 1,
 spec: 'Bundle: '+ b.name,
 price: Math.round(b.price / b.products.length)
 };
 cart.push({
   id: slug + '_' + Date.now(),
   slug: item.slug,
   icon: item.icon || '🖨️',
   product: item.name,
   qty: item.qty,
   price: item.price,
   unit: 'S$' + item.price.toFixed(2) + '/pc',
   config: item.spec || 'Bundle item',
   notes: ''
 });
 });
 updateCartCount();
 goSub('cart');
}

