// Hook home bundles into DOMContentLoaded
// ==== POINTS LOOKUP ====
function ptsLookup() {
 var email = (document.getElementById('pts-lookup-email').value || '').trim().toLowerCase();
 if (!email || !email.includes('@')) { showToast('Please enter a valid email'); return; }
 var member = DB.getMember(email);
 document.getElementById('pts-result-found').style.display = 'none';
 document.getElementById('pts-result-none').style.display = 'none';
 if (!member) {
 document.getElementById('pts-result-none').style.display = 'block';
 return;
 }
 var pts = member.points || 0;
 var earned = member.totalEarned || 0;
 var redeemable = Math.floor(pts / 1000);
 document.getElementById('pts-result-name').textContent = member.name || email;
 document.getElementById('pts-result-balance').textContent = pts.toLocaleString();
 document.getElementById('pts-result-value').textContent = 'S$'+ redeemable.toFixed(2);
 document.getElementById('pts-result-earned').textContent = earned.toLocaleString();
 // Progress bar
 var inBlock = pts % 1000;
 var pct = Math.round(inBlock / 10);
 document.getElementById('pts-progress-bar').style.width = pct + '%';
 document.getElementById('pts-progress-pct').textContent = pct + '%';
 if (pts >= 1000) {
 document.getElementById('pts-progress-label').textContent = redeemable + 'redemption'+ (redeemable > 1 ? 's': '') + 'available';
 document.getElementById('pts-progress-sub').textContent = inBlock > 0 ? (1000 - inBlock) + 'more pts to your next S$1 off': 'Full blocks ready to redeem';
 } else {
 document.getElementById('pts-progress-label').textContent = 'Progress to first S$1 off';
 document.getElementById('pts-progress-sub').textContent = (1000 - pts) + 'more pts needed';
 }
 document.getElementById('pts-result-found').style.display = 'block';
}

function ptsLookupReset() {
 document.getElementById('pts-lookup-email').value = '';
 document.getElementById('pts-result-found').style.display = 'none';
 document.getElementById('pts-result-none').style.display = 'none';
 document.getElementById('pts-lookup-email').focus();
}


// ==== MEMBERSHIP PAGE ====
function memCalc() {
 var inp = document.getElementById('mem-calc-input');
 var val = parseFloat(inp.value) || 0;
 var result = document.getElementById('mem-calc-result');
 var ptsEl = document.getElementById('mem-calc-pts');
 var valEl = document.getElementById('mem-calc-val');
 var noteEl = document.getElementById('mem-calc-note');
 if (!val || val <= 0) { result.style.display = 'none'; return; }
 var pts = Math.floor(val * EARN_RATE);
 var redeemable = Math.floor(pts / REDEEM_RATE);
 result.style.display = 'block';
 ptsEl.textContent = pts.toLocaleString();
 valEl.textContent = 'S$'+ redeemable.toFixed(2);
 if (pts < REDEEM_RATE) {
 noteEl.textContent = 'You need '+ (REDEEM_RATE - pts) + 'more points to unlock your first S$1 off.';
 } else {
 noteEl.textContent = 'You can redeem S$'+ redeemable + 'off your next order right now.';
 }
}

function memLookup() {
 var email = (document.getElementById('mem-lookup-email').value || '').trim().toLowerCase();
 var result = document.getElementById('mem-result');
 if (!email || !email.includes('@')) { result.innerHTML = '<div style="color:#ef4444;font-size:13px">Please enter a valid email.</div>'; return; }
 var member = DB.getMember(email);
 if (!member) {
 result.innerHTML = '<div style="background:#1a1a1a;border:1px solid #333;padding:20px;text-align:center">'+
 '<div style="font-size:14px;color:#666;margin-bottom:12px">No account found for this email.</div>'+
 '<div style="font-size:13px;color:#555">Place your first order using this email and points will start tracking automatically.</div>'+
 '<button data-goto="shop" onclick="go(this.dataset.goto)" style="margin-top:16px;background:#E91E8C;color:#fff;border:none;padding:10px 24px;font-size:13px;font-weight:700;cursor:pointer;font-family:var(--sans)">Start Shopping &rarr;</button>'+
 '</div>';
 return;
 }
 var pts = member.points || 0;
 var redeemable = Math.floor(pts / REDEEM_RATE);
 var pct = Math.round((pts % REDEEM_RATE) / 10);
 result.innerHTML = '<div style="background:#1a1a1a;border:1px solid #222;padding:24px;text-align:center">'+
 '<div style="font-size:13px;color:#888;margin-bottom:4px">'+ (member.name || email) + '</div>'+
 '<div style="font-size:48px;font-weight:800;color:#fff;line-height:1">'+ pts.toLocaleString() + '</div>'+
 '<div style="font-size:14px;color:#E91E8C;font-weight:700;margin:4px 0">points</div>'+
 '<div style="font-size:13px;color:#666;margin-top:8px">S$'+ redeemable + '.00 redeemable &nbsp;·&nbsp; '+ (member.totalEarned||0).toLocaleString() + 'total earned</div>'+
 '<div style="background:#111;height:6px;border-radius:3px;margin:16px 0 6px;overflow:hidden"><div style="height:100%;background:#E91E8C;width:'+ pct + '%"></div></div>'+
 '<div style="font-size:11px;color:#555">'+ (pts >= REDEEM_RATE ? 'Redeem at checkout': (REDEEM_RATE - (pts % REDEEM_RATE)) + 'more pts to next S$1 off') + '</div>'+
 '<button data-goto="shop" onclick="go(this.dataset.goto)" style="margin-top:20px;background:#E91E8C;color:#fff;border:none;padding:10px 24px;font-size:13px;font-weight:700;cursor:pointer;font-family:var(--sans)">Shop &amp; Earn More &rarr;</button>'+
 '</div>';
}


function ftToggle(btn) {
 // Only fires on mobile (toggle-ic is hidden on desktop via CSS)
 var ic = btn.querySelector('.ft-toggle-ic');
 if (!ic || getComputedStyle(ic).display === 'none') return;
 var col = btn.closest('.ft-col');
 if (col) col.classList.toggle('open');
}



