(function moveBundleCrossSell(){
  function run(){
    document.querySelectorAll('.bun-cs-wrap').forEach(function(el){
      if(el.dataset.pvMovedV2) return;
      var prodScreen = el.closest('#screen-product, .pp3-body, .pp2-body');
      if(!prodScreen) return;
      var pricing = prodScreen.querySelector('.pp3-pricing-section');
      if(!pricing) return;
      var currentParent = el.parentElement;
      if(currentParent && currentParent.classList && currentParent.classList.contains('pv-prod-bundle-section')){
        if(currentParent.previousElementSibling === pricing){
          el.dataset.pvMovedV2 = '1';
          return;
        }
      }
      var wrap = document.createElement('div');
      wrap.className = 'pv-prod-bundle-section';
      wrap.innerHTML = '<div class="pv-prod-bundle-inner"><div class="pv-prod-bundle-tag">Bundle &amp; Save</div><h2 class="pv-prod-bundle-h">Order this together.<br><em>Save more.</em></h2></div>';
      var innerBox = document.createElement('div');
      innerBox.className = 'pv-prod-bundle-box';
      innerBox.appendChild(el);
      wrap.querySelector('.pv-prod-bundle-inner').appendChild(innerBox);
      pricing.parentNode.insertBefore(wrap, pricing.nextSibling);
      el.dataset.pvMovedV2 = '1';
    });

    /* Inject hero imagery onto bundle detail pages */
    document.querySelectorAll('.bdp-hero').forEach(function(el){
      if(el.dataset.pvHeroSet) return;
      el.dataset.pvHeroSet = '1';
      var name = (el.querySelector('.bdp-h1') && el.querySelector('.bdp-h1').textContent) || 'bundle';
      var tag = 'giftbox,corporate,print,bundle';
      if(/starter|business/i.test(name)) tag = 'businesscard,flyer,banner,stationery';
      else if(/event|launch/i.test(name)) tag = 'banner,flyer,rollup,tradeshow';
      else if(/wedding/i.test(name)) tag = 'weddingstationery,invitation,gift';
      else if(/gift|corporate/i.test(name)) tag = 'giftbox,corporate,hamper,tumbler';
      var url = 'https://picsum.photos/seed/' + encodeURIComponent(String(tag).split(',')[0]) + (Math.floor(Math.random()*900)+100) + '/1400/700';
      var img = document.createElement('div');
      img.className = 'pv-bdp-hero-img';
      img.style.backgroundImage = 'url('+url+')';
      el.insertBefore(img, el.firstChild);
      el.classList.add('pv-bdp-hero-styled');
    });
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', run);
  else run();
  setInterval(run, 1200);
})();

