/* ════════════════════════════════════════════════
   ADMIN — wire up navigation + confirm render
════════════════════════════════════════════════ */
(function(){
  function ensureAdminWorks(){
    /* Guarantee go('admin') renders the admin screen */
    if(typeof window.go !== 'function') return setTimeout(ensureAdminWorks, 300);
    if(window._pvAdminWired) return;
    window._pvAdminWired = true;
    var origGo = window.go;
    window.go = function(target){
      var r = origGo.apply(this, arguments);
      if(target === 'admin'){
        setTimeout(function(){
          var s = document.getElementById('screen-admin');
          if(s){
            document.querySelectorAll('.screen').forEach(function(el){el.classList.remove('active')});
            s.classList.add('active');
            try{window.scrollTo({top:0,behavior:'smooth'});}catch(e){window.scrollTo(0,0);}
            /* Trigger dashboard load if present */
            if(typeof window.admLoadDashboard === 'function') window.admLoadDashboard();
            if(typeof window.admLoadOrders === 'function') window.admLoadOrders();
            if(typeof window.admBuildProdList === 'function') window.admBuildProdList('');
          }
        }, 50);
      }
      if(target === 'staff' || target === 'sf'){
        setTimeout(function(){
          var s = document.getElementById('screen-staff') || document.getElementById('screen-sf');
          if(s){
            document.querySelectorAll('.screen').forEach(function(el){el.classList.remove('active')});
            s.classList.add('active');
            try{window.scrollTo({top:0,behavior:'smooth'});}catch(e){window.scrollTo(0,0);}
          }
        }, 50);
      }
      return r;
    };
  }
  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', ensureAdminWorks);
  }else{
    ensureAdminWorks();
  }
})();

/* ════════════════════════════════════════════════
   TOP-NAV UPGRADE — reworded labels, WhatsApp pill,
   and uploaded-logo swap
════════════════════════════════════════════════ */
(function navUpgrade(){
  var LABEL_MAP = {
    'Print': 'Print Services',
    'Gifts': 'Personalised Gifts',
    'Bundles': 'Bundle Deals',
    'About': 'About Us',
    'Contact': 'Get a Quote',
    'Shop': 'All Products',
    'Products': 'All Products',
    'Cart': 'My Cart'
  };
  function applyLabels(){
    document.querySelectorAll('#nav .nav-lnk').forEach(function(lnk){
      if(lnk.dataset.pvRelabeled) return;
      var raw = (lnk.textContent || '').replace(/[▾▼\u25BE\s]+$/,'').trim();
      if(!raw) return;
      if(LABEL_MAP[raw]){
        var dd = /dropdown|mega/.test(lnk.getAttribute('onmousedown')||'') ? ' ▾' : '';
        lnk.innerHTML = LABEL_MAP[raw] + dd;
        lnk.dataset.pvRelabeled = '1';
      }
    });
  }
  function addWa(){
    var right = document.querySelector('#nav .nav-right');
    if(!right) return;
    if(right.querySelector('.pv-nav-wa')) return;
    var wa = document.createElement('a');
    wa.className = 'pv-nav-wa';
    wa.href = 'https://wa.me/6585533497';
    wa.target = '_blank';
    wa.rel = 'noopener';
    wa.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347M12.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413A11.815 11.815 0 0012.05 0Z"/></svg><span>WhatsApp</span>';
    /* place BEFORE the cart button */
    var cart = right.querySelector('.nav-btn-p');
    if(cart) right.insertBefore(wa, cart);
    else right.appendChild(wa);
  }
  function applyLogo(){
    var stored = '';
    try{ stored = localStorage.getItem('pv_logo_dataurl') || ''; }catch(e){}
    var logos = document.querySelectorAll('.nav-logo, .ft-logo');
    logos.forEach(function(el){
      if(stored){
        if(el.dataset.pvLogoUrl === stored) return;
        el.dataset.pvLogoUrl = stored;
        el.classList.add('pv-has-upload');
        el.innerHTML = '<img src="'+stored+'" alt="Printvolution">';
      }else{
        if(el.dataset.pvLogoUrl === ''){ /* already reset */ }
        else if(el.dataset.pvLogoUrl){
          /* logo was removed → restore default */
          el.dataset.pvLogoUrl = '';
          el.classList.remove('pv-has-upload');
          el.innerHTML = 'Print<span style="color:#EC1C7D">volution</span>';
        }
      }
    });
  }
  function run(){ applyLabels(); addWa(); applyLogo(); }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', run);
  else run();
  setTimeout(run, 400); setTimeout(run, 1200); setTimeout(run, 2500);
  document.addEventListener('click', function(){ setTimeout(run, 200); });
})();

