(function adminExtras(){
  function addPerOrderDelete(){
    document.querySelectorAll('#screen-admin .adm-order-row').forEach(function(row){
      if(row.dataset.pvDelBtn) return;
      var actions = row.querySelector('.adm-ord-actions');
      if(!actions) return;
      /* Derive order id from the onclick, the #id text, or data attr */
      var idMatch = (row.getAttribute('onclick')||'').match(/admViewOrder\('([^']+)'/);
      var oid = idMatch ? idMatch[1] : '';
      if(!oid){
        var idTxt = row.querySelector('.adm-ord-id');
        if(idTxt) oid = (idTxt.textContent||'').replace('#','').trim().split(' ')[0];
      }
      if(!oid) return;
      var btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'pv-ord-del-btn';
      btn.textContent = '✕ Delete';
      btn.title = 'Delete this order';
      btn.onclick = function(e){
        e.preventDefault();e.stopPropagation();
        if(!confirm('Delete order '+oid+'? This cannot be undone.')) return;
        if(typeof window.adminDeleteOrder==='function'){
          window.adminDeleteOrder(oid);
        }else{
          try{
            var arr = JSON.parse(localStorage.getItem('pv_orders'))||[];
            arr = arr.filter(function(o){ return o.id !== oid; });
            localStorage.setItem('pv_orders', JSON.stringify(arr));
          }catch(err){}
        }
        if(typeof window.admLoadOrders==='function') window.admLoadOrders();
        if(typeof window.admLoadDashboard==='function') window.admLoadDashboard();
      };
      actions.appendChild(btn);
      row.dataset.pvDelBtn = '1';
    });
  }

  function mountLogoCard(){
    var pane = document.getElementById('pg-pane-homepage');
    if(!pane) return;
    if(pane.querySelector('.pv-logo-card')) return;
    var card = document.createElement('div');
    card.className = 'pv-logo-card';
    card.innerHTML =
      '<h3>Site Logo</h3>'+
      '<p>Upload a custom logo to replace the "Printvolution" wordmark in the top nav and footer. PNG, SVG or JPG. Transparent background recommended. Shown at 40px height in the nav.</p>'+
      '<div class="pv-logo-grid">'+
        '<div class="pv-logo-preview" id="pv-logo-preview"><span class="pv-logo-empty">● NO LOGO UPLOADED ●</span></div>'+
        '<div class="pv-logo-actions">'+
          '<input type="file" id="pv-logo-file" accept="image/png,image/jpeg,image/svg+xml,image/webp" style="display:none">'+
          '<button class="pv-logo-btn" id="pv-logo-upload-btn" type="button">📤 Upload Logo Image</button>'+
          '<button class="pv-logo-btn secondary" id="pv-logo-url-btn" type="button">🔗 Paste Image URL Instead</button>'+
          '<button class="pv-logo-btn danger" id="pv-logo-clear-btn" type="button">✕ Remove &amp; Restore Default</button>'+
          '<div class="pv-logo-hint">Your logo is stored locally in this browser. Max ~2 MB. Use SVG for sharpest results.</div>'+
        '</div>'+
      '</div>';
    /* Insert at the very top of homepage pane */
    pane.insertBefore(card, pane.firstChild);

    function refreshPreview(){
      var prev = document.getElementById('pv-logo-preview');
      if(!prev) return;
      var stored = '';
      try{ stored = localStorage.getItem('pv_logo_dataurl')||''; }catch(e){}
      if(stored){
        prev.innerHTML = '<img src="'+stored+'" alt="Logo preview">';
      }else{
        prev.innerHTML = '<span class="pv-logo-empty">● NO LOGO UPLOADED ●</span>';
      }
    }
    refreshPreview();

    var fileInput = document.getElementById('pv-logo-file');
    document.getElementById('pv-logo-upload-btn').onclick = function(){ fileInput.click(); };
    fileInput.onchange = function(){
      var f = fileInput.files && fileInput.files[0];
      if(!f) return;
      if(f.size > 2.5 * 1024 * 1024){
        alert('Logo file is too large. Max 2.5 MB.');
        return;
      }
      var r = new FileReader();
      r.onload = function(){
        try{
          localStorage.setItem('pv_logo_dataurl', r.result);
          refreshPreview();
          /* trigger swap on nav + footer */
          document.querySelectorAll('.nav-logo, .ft-logo').forEach(function(el){ delete el.dataset.pvLogoUrl; });
          if(typeof window.showToast==='function') window.showToast('✓ Logo updated — live on site');
        }catch(err){ alert('Could not save logo — storage quota exceeded. Try a smaller file.'); }
      };
      r.readAsDataURL(f);
    };
    document.getElementById('pv-logo-url-btn').onclick = function(){
      var url = prompt('Paste the image URL for your logo:\n\n(Must be a direct image link — PNG, SVG, JPG or WebP.)');
      if(!url) return;
      url = url.trim();
      if(!/^https?:\/\//i.test(url)){ alert('URL must start with http:// or https://'); return; }
      try{
        localStorage.setItem('pv_logo_dataurl', url);
        refreshPreview();
        document.querySelectorAll('.nav-logo, .ft-logo').forEach(function(el){ delete el.dataset.pvLogoUrl; });
        if(typeof window.showToast==='function') window.showToast('✓ Logo updated from URL');
      }catch(err){ alert('Could not save.'); }
    };
    document.getElementById('pv-logo-clear-btn').onclick = function(){
      if(!confirm('Remove your custom logo and restore the default "Printvolution" wordmark?')) return;
      try{ localStorage.removeItem('pv_logo_dataurl'); }catch(e){}
      refreshPreview();
      document.querySelectorAll('.nav-logo, .ft-logo').forEach(function(el){ delete el.dataset.pvLogoUrl; });
      if(typeof window.showToast==='function') window.showToast('Logo restored to default');
    };
  }

  /* ════════ Production Methods editor (admin dashboard) ════════
     Uses the existing DB.getMethods() / DB.saveMethods() API so it
     drives the real product-editor dropdown (#pe-method). Each method
     has { name, flowType, basePrompt } — we expose name + flowType here. */
  function getMethods(){
    if(window.DB && typeof DB.getMethods==='function') return DB.getMethods();
    return [];
  }
  function saveMethods(arr){
    if(!window.DB || typeof DB.saveMethods!=='function') return;
    DB.saveMethods(arr);
    /* 1. Rebuild the global flow-type lookup */
    try{
      if(window._GF_METHOD_FLOW){
        Object.keys(window._GF_METHOD_FLOW).forEach(function(k){delete window._GF_METHOD_FLOW[k];});
        arr.forEach(function(m){ if(m.flowType && m.flowType!=='none') window._GF_METHOD_FLOW[m.name]=m.flowType; });
      }
    }catch(e){}
    /* 2. Cascade flowType + basePrompt changes into every product whose
          giftConfig.method matches one of the updated methods — this is
          the real fix for "methods don't update on product pages". */
    var touched = 0;
    try{
      if(window.PP_EXTRA){
        var byName = {};
        arr.forEach(function(m){ if(m && m.name) byName[m.name] = m; });
        Object.keys(window.PP_EXTRA).forEach(function(slug){
          var ex = PP_EXTRA[slug]; if(!ex || !ex.giftConfig) return;
          var gc = ex.giftConfig; var m = byName[gc.method];
          if(!m) return;
          var changed = false;
          if(m.flowType && gc.flowType !== m.flowType){ gc.flowType = m.flowType; changed = true; }
          /* Only cascade basePrompt if product has none of its own */
          if(m.basePrompt && !gc.basePrompt){ gc.basePrompt = m.basePrompt; changed = true; }
          if(changed) touched++;
        });
        /* Persist PP_EXTRA if we touched anything */
        if(touched){
          try{ localStorage.setItem('pv_pp_extra', JSON.stringify(window.PP_EXTRA)); }catch(e){}
        }
      }
    }catch(e){}
    /* 3. If a public product page is currently visible, re-render it so
          changes appear immediately. */
    try{
      var activeProd = document.querySelector('#screen-product.active');
      if(activeProd && typeof window.renderProductPage==='function' && window._currentProductSlug){
        window.renderProductPage(window._currentProductSlug);
      }
    }catch(e){}
    /* 4. Toast */
    try{
      if(typeof window.showToast==='function'){
        window.showToast(touched ? ('✓ Methods saved — '+touched+' product'+(touched>1?'s':'')+' synced') : '✓ Methods saved');
      }
    }catch(e){}
  }
  var FLOW_LABELS = {
    'none':'— No AI / manual',
    'transform':'✨ AI photo transform',
    'overlay':'✎ Text on mockup',
    'template':'▤ Template fill'
  };
  window.pvGetProductionMethods = getMethods;

  function mountMethodsCard(){
    var dashPane = document.getElementById('adm-pane-dashboard');
    if(!dashPane || !dashPane.classList.contains('on')) return;
    if(dashPane.querySelector('.pv-methods-card')) { renderMethodsList(); return; }

    var card = document.createElement('div');
    card.className = 'adm-card pv-methods-card';
    card.style.cssText = 'margin-bottom:16px;border:2px solid #0A0A0A;box-shadow:4px 4px 0 #0A0A0A;padding:16px;background:#FFF';
    card.innerHTML =
      '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px;gap:12px;flex-wrap:wrap">'+
        '<div>'+
          '<div class="adm-section-title" style="margin:0">&#9881;&#65039; Modify Production Methods</div>'+
          '<div style="font-size:11px;color:#888;margin-top:2px">These are the methods shown in the product editor\'s <strong>Production Method</strong> dropdown. Add, rename, or remove — changes save instantly.</div>'+
        '</div>'+
      '</div>'+
      '<div id="pv-method-list" style="margin-top:14px;display:flex;flex-direction:column;gap:8px"></div>'+
      '<div style="display:flex;gap:8px;margin-top:12px">'+
        '<input id="pv-method-new" placeholder="New method name (e.g. Vinyl Cut)" style="flex:1;min-width:0;border:1.5px solid #0A0A0A;padding:9px 12px;font-size:13px;font-family:var(--sans);border-radius:4px">'+
        '<button id="pv-method-add" style="background:#EC1C7D;color:#fff;border:2px solid #0A0A0A;padding:9px 16px;font-size:12px;font-weight:800;cursor:pointer;font-family:var(--sans);border-radius:4px;box-shadow:2px 2px 0 #0A0A0A;white-space:nowrap">+ Add Method</button>'+
      '</div>';

    /* Insert before the grid that holds "Production Methods" breakdown */
    var firstGrid = dashPane.querySelector('.adm-grid-2');
    if(firstGrid) dashPane.insertBefore(card, firstGrid);
    else dashPane.appendChild(card);

    document.getElementById('pv-method-add').onclick = function(){
      var inp = document.getElementById('pv-method-new');
      var v = (inp.value||'').trim();
      if(!v) return;
      var list = getMethods();
      if(list.some(function(m){ return (m.name||'').toLowerCase()===v.toLowerCase(); })){ alert('That method already exists.'); return; }
      list.push({name:v, flowType:'none', basePrompt:''});
      saveMethods(list); inp.value=''; renderMethodsList(); syncSelect();
    };
    document.getElementById('pv-method-new').addEventListener('keydown', function(e){
      if(e.key==='Enter'){ e.preventDefault(); document.getElementById('pv-method-add').click(); }
    });
    renderMethodsList();
  }

  function renderMethodsList(){
    var host = document.getElementById('pv-method-list');
    if(!host) return;
    var list = getMethods();
    if(!list.length){
      host.innerHTML = '<div style="font-size:12px;color:#aaa;padding:6px 0">No methods yet — add one below.</div>';
      return;
    }
    host.innerHTML = list.map(function(m, i){
      var name = (m.name||'').replace(/"/g,'&quot;').replace(/</g,'&lt;');
      var flow = m.flowType || 'none';
      var dotCol = flow==='transform'?'#EC1C7D':flow==='overlay'?'#3b5bdb':flow==='template'?'#8b5cf6':'#ccc';
      var flowOpts = Object.keys(FLOW_LABELS).map(function(k){
        return '<option value="'+k+'"'+(flow===k?' selected':'')+'>'+FLOW_LABELS[k]+'</option>';
      }).join('');
      return '<div style="display:flex;gap:6px;align-items:center;background:#FAFAFA;border:1px solid #E5E5E5;padding:8px 10px;border-radius:4px;flex-wrap:wrap">'+
        '<div style="width:10px;height:10px;border-radius:50%;background:'+dotCol+';flex-shrink:0"></div>'+
        '<input class="pv-method-inp" data-i="'+i+'" value="'+name+'" style="flex:2 1 180px;min-width:140px;border:1px solid #DDD;padding:7px 10px;font-size:13px;font-weight:700;font-family:var(--sans);background:#FFF;border-radius:3px">'+
        '<select class="pv-method-flow" data-i="'+i+'" style="flex:1 1 150px;min-width:130px;border:1px solid #DDD;padding:7px 8px;font-size:12px;font-family:var(--sans);background:#FFF;border-radius:3px">'+flowOpts+'</select>'+
        '<button class="pv-method-up" data-i="'+i+'" title="Move up" style="background:#FFF;border:1px solid #0A0A0A;width:28px;height:30px;font-size:13px;cursor:pointer;border-radius:3px"'+(i===0?' disabled':'')+'>&#9650;</button>'+
        '<button class="pv-method-dn" data-i="'+i+'" title="Move down" style="background:#FFF;border:1px solid #0A0A0A;width:28px;height:30px;font-size:13px;cursor:pointer;border-radius:3px"'+(i===list.length-1?' disabled':'')+'>&#9660;</button>'+
        '<button class="pv-method-del" data-i="'+i+'" title="Remove" style="background:#FFF;border:1.5px solid #EC1C7D;color:#EC1C7D;padding:0 10px;height:30px;font-size:13px;font-weight:800;cursor:pointer;border-radius:3px">&#215;</button>'+
      '</div>';
    }).join('');
    host.querySelectorAll('.pv-method-inp').forEach(function(el){
      el.addEventListener('change', function(){
        var i = +this.dataset.i, v = (this.value||'').trim();
        var arr = getMethods();
        if(!v || !arr[i]){ this.value = arr[i] ? arr[i].name : ''; return; }
        arr[i].name = v; saveMethods(arr); syncSelect();
      });
    });
    host.querySelectorAll('.pv-method-flow').forEach(function(el){
      el.addEventListener('change', function(){
        var i = +this.dataset.i, arr = getMethods();
        if(arr[i]){ arr[i].flowType = this.value; saveMethods(arr); renderMethodsList(); syncSelect(); }
      });
    });
    host.querySelectorAll('.pv-method-del').forEach(function(el){
      el.onclick = function(){
        var i = +this.dataset.i; var arr = getMethods();
        if(!arr[i]) return;
        if(!confirm('Remove "'+arr[i].name+'" from the production methods list?')) return;
        arr.splice(i,1); saveMethods(arr); renderMethodsList(); syncSelect();
      };
    });
    host.querySelectorAll('.pv-method-up').forEach(function(el){
      el.onclick = function(){
        var i = +this.dataset.i; if(i===0) return;
        var arr = getMethods(); var t = arr[i-1]; arr[i-1]=arr[i]; arr[i]=t;
        saveMethods(arr); renderMethodsList(); syncSelect();
      };
    });
    host.querySelectorAll('.pv-method-dn').forEach(function(el){
      el.onclick = function(){
        var i = +this.dataset.i; var arr = getMethods(); if(i>=arr.length-1) return;
        var t = arr[i+1]; arr[i+1]=arr[i]; arr[i]=t;
        saveMethods(arr); renderMethodsList(); syncSelect();
      };
    });
  }

  /* Rewrite any on-screen production-method <select> so options always match
     the admin's custom list. Covers the Print/Service editor (#pe-method)
     and the gift flow editor (#adm-gc-method). */
  function syncSelect(){
    var methods = getMethods();
    var names = methods.map(function(m){ return m.name; });

    /* #pe-method — Print/Service editor (seen on screenshot) */
    document.querySelectorAll('#pe-method').forEach(function(sel){
      var current = sel.value;
      var html = '<option value="">-- Standard Print --</option>';
      methods.forEach(function(m){
        var esc = (m.name||'').replace(/"/g,'&quot;').replace(/</g,'&lt;');
        html += '<option value="'+esc+'"'+(current===m.name?' selected':'')+'>'+esc+'</option>';
      });
      if(current && names.indexOf(current)===-1){
        html += '<option value="'+current.replace(/"/g,'&quot;')+'" selected>'+current.replace(/</g,'&lt;')+' (legacy)</option>';
      }
      sel.innerHTML = html;
    });

    /* #adm-gc-method — Gift-flow editor */
    document.querySelectorAll('#adm-gc-method').forEach(function(sel){
      var current = sel.value;
      var html = '<option value="">— Not a gift / no special handling —</option>';
      methods.forEach(function(m){
        var esc = (m.name||'').replace(/"/g,'&quot;').replace(/</g,'&lt;');
        html += '<option value="'+esc+'"'+(current===m.name?' selected':'')+'>'+esc+'</option>';
      });
      if(current && names.indexOf(current)===-1){
        html += '<option value="'+current.replace(/"/g,'&quot;')+'" selected>'+current.replace(/</g,'&lt;')+' (legacy)</option>';
      }
      sel.innerHTML = html;
    });
  }

  /* ════════ Gift Flow Configuration UX enhancements ════════
     The existing gift flow config is functional but dense — this function
     injects a clearer explainer header, better labels, and contextual help
     whenever the product editor renders the gift flow section. */
  function enhanceGiftFlowUX(){
    var wrap = document.getElementById('pe-gift-flow-wrap');
    if(!wrap || wrap.dataset.pvGfEnhanced) return;
    wrap.dataset.pvGfEnhanced = '1';

    /* 1. Replace the tiny pink header with a clearer explainer card */
    var inner = wrap.firstElementChild; /* the fff8fc div */
    if(inner){
      var header = inner.querySelector('div[style*="Gift Flow Configuration"], div[style*="color:#E91E8C"]');
      if(header && !header.dataset.pvGfHdr){
        header.dataset.pvGfHdr = '1';
        header.outerHTML =
          '<div style="background:#fff;border:2px solid #EC1C7D;border-radius:6px;padding:14px 16px;margin-bottom:16px">'+
            '<div style="font-size:13px;font-weight:800;color:#EC1C7D;margin-bottom:6px">&#127873; Gift Flow Configuration</div>'+
            '<div style="font-size:12px;color:#374151;line-height:1.6;margin-bottom:8px">This decides what the customer <em>actually does</em> on the product page when they click "Personalise". Pick one of the three flows below — each one creates a different customer experience:</div>'+
            '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:8px;margin-top:10px">'+
              '<div style="background:#fef3c7;border:1px solid #f59e0b;padding:10px;border-radius:4px;font-size:11px;line-height:1.5"><strong style="color:#92400e">&#10024; AI Transform</strong><br><span style="color:#78350f">Customer uploads a photo → AI re-styles it (e.g. into oil painting, watercolour). Best for: UV print, sublimation, DTF.</span></div>'+
              '<div style="background:#dbeafe;border:1px solid #3b82f6;padding:10px;border-radius:4px;font-size:11px;line-height:1.5"><strong style="color:#1e40af">&#9998; Text on Mockup</strong><br><span style="color:#1e3a8a">Customer types text → appears live on a product mockup. Best for: engraving, embroidery, laser cut.</span></div>'+
              '<div style="background:#ede9fe;border:1px solid #8b5cf6;padding:10px;border-radius:4px;font-size:11px;line-height:1.5"><strong style="color:#5b21b6">&#128196; Template Fill</strong><br><span style="color:#4c1d95">Customer fills form fields → populates your design template (photos + text zones). Best for: invitations, cards, calendars.</span></div>'+
            '</div>'+
          '</div>';
      }
    }

    /* 2. Improve the Customer Experience label + help text */
    var fEl = document.getElementById('pe-flow-type');
    if(fEl && !fEl.dataset.pvGfLabel){
      fEl.dataset.pvGfLabel = '1';
      var wrapLbl = fEl.closest('.adm-fl');
      if(wrapLbl){
        var lbl = wrapLbl.querySelector('label');
        if(lbl) lbl.innerHTML = 'How does the customer create their gift? <span style="font-weight:400;color:#aaa;font-size:10px">(required)</span>';
        /* Improve the helper text below */
        var helper = wrapLbl.querySelector('div[style*="Auto-suggested"]');
        if(helper) helper.innerHTML = '&#128161; <strong>Tip:</strong> When you pick a Production Method above, we auto-suggest the best flow — but you can always override it here. Change this and the config below updates automatically.';
      }
    }

    /* 3. Clarify the "1 — Print Dimensions" numbered label since it only
          applies to the overlay flow */
    var ovCfg = document.getElementById('pe-overlay-cfg');
    if(ovCfg && !ovCfg.dataset.pvGfLbl){
      ovCfg.dataset.pvGfLbl = '1';
      var firstStep = ovCfg.querySelector('div[style*="1 \\u2014 Print Dimensions"], div[style*="1 — Print Dimensions"]');
      /* Fall back to finding the blue step-1 block by text content */
      if(!firstStep){
        Array.prototype.forEach.call(ovCfg.querySelectorAll('div'), function(d){
          if(!firstStep && /1\s*[—–-]\s*Print Dimensions/.test(d.textContent)) firstStep = d;
        });
      }
      /* Insert a banner at top of overlay config explaining the 3 steps */
      var banner = document.createElement('div');
      banner.style.cssText = 'background:#f0f9ff;border:1.5px solid #7dd3fc;padding:10px 12px;border-radius:4px;margin-bottom:12px;font-size:11px;color:#0c4a6e;line-height:1.5';
      banner.innerHTML = '<strong>&#9998; Text-on-Mockup setup</strong> — 3 steps: <strong>1.</strong> Enter the real print size → <strong>2.</strong> Upload the product mockup image → <strong>3.</strong> Add text fields the customer will fill in. The admin preview shows exactly what the customer sees.';
      ovCfg.insertBefore(banner, ovCfg.firstChild);
    }

    /* 4. Add a banner to the transform config */
    var tfCfg = document.getElementById('pe-transform-cfg');
    if(tfCfg && !tfCfg.dataset.pvGfLbl){
      tfCfg.dataset.pvGfLbl = '1';
      var banner2 = document.createElement('div');
      banner2.style.cssText = 'background:#fef3c7;border:1.5px solid #fbbf24;padding:10px 12px;border-radius:4px;margin-bottom:12px;font-size:11px;color:#78350f;line-height:1.5';
      banner2.innerHTML = '<strong>&#10024; AI Transform setup</strong> — The <em>Base Prompt</em> is always applied. <em>Style Options</em> are optional — add them only if you want the customer to pick between multiple looks (e.g. "Oil Painting", "Watercolour", "Pop Art"). Leave styles empty to use just the base prompt.';
      tfCfg.insertBefore(banner2, tfCfg.firstChild);
    }

    /* 5. Add a banner to the template config */
    var tplCfg = document.getElementById('pe-template-cfg');
    if(tplCfg && !tplCfg.dataset.pvGfLbl){
      tplCfg.dataset.pvGfLbl = '1';
      var banner3 = document.createElement('div');
      banner3.style.cssText = 'background:#ede9fe;border:1.5px solid #a78bfa;padding:10px 12px;border-radius:4px;margin-bottom:12px;font-size:11px;color:#4c1d95;line-height:1.5';
      banner3.innerHTML = '<strong>&#128196; Template Fill setup</strong> — Best for multi-field designs like invitations, greeting cards and calendars. Click <em>Open Template Editor</em> to upload your base design and drag text/photo zones onto it. You can set up multiple sides (front, back, inside) and allowed fonts per zone.';
      tplCfg.insertBefore(banner3, tplCfg.firstChild);
    }
  }

  function run(){ addPerOrderDelete(); mountLogoCard(); mountMethodsCard(); syncSelect(); enhanceGiftFlowUX(); }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', run);
  else run();
  setInterval(run, 1500);
  document.addEventListener('click', function(){ setTimeout(run, 250); });
})();

/* ══════════════════════════════════════════════════════════════════
   BUNDLE MANAGER — dedicated admin tab with persistence
   Wires up a new "Bundles" tab in the admin, persists to localStorage,
   adds a comprehensive inline editor (products, image, pricing, why, FAQ),
   and re-renders the public bundle pages whenever changes are saved.
══════════════════════════════════════════════════════════════════ */
(function bundleManager(){
  var LS_KEY = 'pv_bundles';

  /* 1. Hydrate BUNDLES from localStorage on startup */
  function hydrate(){
    if(!window.BUNDLES) return;
    try{
      var raw = localStorage.getItem(LS_KEY);
      if(raw){
        var saved = JSON.parse(raw);
        if(Array.isArray(saved)){
          /* Replace in place so references still work */
          window.BUNDLES.length = 0;
          saved.forEach(function(b){ window.BUNDLES.push(b); });
        }
      }
    }catch(e){}
  }
  function persist(){
    try{ localStorage.setItem(LS_KEY, JSON.stringify(window.BUNDLES||[])); }catch(e){}
  }
  function refreshPublicBundles(){
    try{ if(typeof window.renderBundlesScreen==='function') window.renderBundlesScreen(); }catch(e){}
    try{
      var active = document.querySelector('#screen-bundle-detail.active');
      if(active && typeof window.goBundlePage==='function' && window._currentBundleId){
        window.goBundlePage(window._currentBundleId);
      }
    }catch(e){}
  }

  /* 2. Inject the new tab button + pane */
  function mountTab(){
    var tabBar = document.querySelector('#screen-admin .adm-tabs, #screen-admin div:has(> #adm-tab-dashboard)');
    var existingTab = document.getElementById('adm-tab-bundles');
    if(!existingTab){
      var dashBtn = document.getElementById('adm-tab-dashboard');
      if(!dashBtn) return;
      var btn = document.createElement('button');
      btn.className = 'adm-tab-btn';
      btn.id = 'adm-tab-bundles';
      btn.textContent = '📦 Bundles';
      btn.onclick = function(){ window.admTab && window.admTab('bundles', btn); renderBundlesPane(); };
      /* Insert after Products tab */
      var prodBtn = document.getElementById('adm-tab-products');
      if(prodBtn && prodBtn.parentNode){
        prodBtn.parentNode.insertBefore(btn, prodBtn.nextSibling);
      }else{
        dashBtn.parentNode.appendChild(btn);
      }
    }
    /* Insert the pane */
    if(!document.getElementById('adm-pane-bundles')){
      var body = document.querySelector('#screen-admin .adm-body');
      if(!body) return;
      var pane = document.createElement('div');
      pane.className = 'adm-pane';
      pane.id = 'adm-pane-bundles';
      pane.innerHTML =
        '<div class="adm-page-title">&#128230; Bundle Manager</div>'+
        '<div class="adm-page-sub">Create bundles by checking products, set hero image + pricing, and edit every section shown on the bundle page.</div>'+
        '<div class="adm-card" style="margin-bottom:16px;border:2px solid #0A0A0A;box-shadow:4px 4px 0 #0A0A0A">'+
          '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;gap:10px;flex-wrap:wrap">'+
            '<div class="adm-section-title" style="margin:0">Your Bundles</div>'+
            '<button id="pv-bun-new" style="background:#EC1C7D;color:#fff;border:2px solid #0A0A0A;padding:9px 18px;font-size:12px;font-weight:800;cursor:pointer;font-family:var(--sans);border-radius:4px;box-shadow:2px 2px 0 #0A0A0A">+ New Bundle</button>'+
          '</div>'+
          '<div id="pv-bun-list" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px"></div>'+
        '</div>'+
        '<div id="pv-bun-editor-wrap" style="display:none"></div>';
      body.appendChild(pane);
      document.getElementById('pv-bun-new').onclick = function(){ openEditor(null); };
    }
    /* Make sure admTab knows about the new pane — patch if needed */
    patchAdmTab();
    /* If bundles tab is currently active, render it */
    if(document.getElementById('adm-pane-bundles').classList.contains('on')){
      renderBundlesPane();
    }
  }

  function patchAdmTab(){
    if(window._pvBundleAdmTabPatched) return;
    if(typeof window.admTab !== 'function') return;
    window._pvBundleAdmTabPatched = true;
    var orig = window.admTab;
    window.admTab = function(tab, btnEl){
      /* Switch active tab + pane manually for 'bundles' since the original
         admTab only knows the hardcoded tabs */
      if(tab === 'bundles'){
        document.querySelectorAll('#screen-admin .adm-tab-btn').forEach(function(b){ b.classList.remove('on'); });
        document.querySelectorAll('#screen-admin .adm-pane').forEach(function(p){ p.classList.remove('on'); });
        var btn = document.getElementById('adm-tab-bundles'); if(btn) btn.classList.add('on');
        var pane = document.getElementById('adm-pane-bundles'); if(pane) pane.classList.add('on');
        renderBundlesPane();
        return;
      }
      return orig.apply(this, arguments);
    };
  }

  /* 3. Render the bundle list */
  function renderBundlesPane(){
    var list = document.getElementById('pv-bun-list'); if(!list) return;
    var bundles = window.BUNDLES || [];
    if(!bundles.length){
      list.innerHTML = '<div style="grid-column:1/-1;padding:30px;text-align:center;color:#aaa;font-size:13px">No bundles yet. Click <strong>+ New Bundle</strong> to create one.</div>';
      return;
    }
    list.innerHTML = bundles.map(function(b){
      var names = (b.products||[]).map(function(s){ return window.PRODUCTS_DATA && PRODUCTS_DATA[s] ? PRODUCTS_DATA[s].name : s; }).join(' + ');
      var imgHtml = b.image ? '<img src="'+b.image+'" style="width:100%;height:120px;object-fit:cover;border:1.5px solid #0A0A0A;margin-bottom:8px" onerror="this.style.display=\'none\'">' : '<div style="height:120px;background:#F3EEE2;border:1.5px dashed #0A0A0A;display:flex;align-items:center;justify-content:center;color:#888;font-size:11px;margin-bottom:8px">No image</div>';
      var draft = b.status === 'draft';
      return '<div style="border:1.5px solid #0A0A0A;padding:12px;background:#fff;'+(draft?'opacity:.55':'')+'">'+
        imgHtml+
        '<div style="display:flex;justify-content:space-between;align-items:center;gap:6px;margin-bottom:4px"><strong style="font-size:13px;font-family:var(--sans)">'+(b.name||'Untitled')+'</strong><span style="font-size:9px;font-weight:800;padding:2px 6px;border-radius:3px;background:'+(draft?'#f3f4f6':'#dcfce7')+';color:'+(draft?'#6b7280':'#065f46')+';text-transform:uppercase;letter-spacing:.5px">'+(draft?'Draft':'Live')+'</span></div>'+
        '<div style="font-size:11px;color:#666;margin-bottom:6px;line-height:1.4">'+names+'</div>'+
        '<div style="font-size:12px;margin-bottom:10px"><strong style="color:#EC1C7D">S$'+(b.price||0)+'</strong> <span style="color:#aaa;text-decoration:line-through;font-size:10px">S$'+(b.original||0)+'</span></div>'+
        '<div style="display:flex;gap:6px">'+
          '<button data-bid="'+b.id+'" class="pv-bun-edit" style="flex:1;background:#FFD100;border:1.5px solid #0A0A0A;padding:7px;font-size:11px;font-weight:800;cursor:pointer;font-family:var(--sans);box-shadow:2px 2px 0 #0A0A0A">&#9998; Edit</button>'+
          '<button data-bid="'+b.id+'" class="pv-bun-del" style="background:#fff;border:1.5px solid #EF4444;color:#EF4444;padding:7px 10px;font-size:13px;font-weight:800;cursor:pointer">&#215;</button>'+
        '</div>'+
      '</div>';
    }).join('');
    list.querySelectorAll('.pv-bun-edit').forEach(function(b){ b.onclick = function(){ openEditor(this.dataset.bid); }; });
    list.querySelectorAll('.pv-bun-del').forEach(function(b){
      b.onclick = function(){
        var id = this.dataset.bid;
        var bun = (window.BUNDLES||[]).find(function(x){return x.id===id;});
        if(!bun) return;
        if(!confirm('Delete bundle "'+bun.name+'"?')) return;
        window.BUNDLES = window.BUNDLES.filter(function(x){return x.id!==id;});
        persist(); renderBundlesPane(); refreshPublicBundles();
      };
    });
  }

  /* 4. Open the inline editor */
  function openEditor(id){
    var wrap = document.getElementById('pv-bun-editor-wrap'); if(!wrap) return;
    var b = id ? (window.BUNDLES||[]).find(function(x){return x.id===id;}) : null;
    var isNew = !b;
    if(isNew){
      b = { id:'b'+Date.now(), name:'', tagline:'', desc:'', image:'', products:[], includes:{},
            price:0, original:0, status:'active', why:[], faq:[] };
    }
    var allProducts = window.PRODUCTS_DATA || {};
    var selected = {};
    (b.products||[]).forEach(function(s){ selected[s]=true; });

    wrap.style.display = 'block';
    wrap.innerHTML =
      '<div class="adm-card" style="border:2px solid #EC1C7D;box-shadow:4px 4px 0 #EC1C7D;padding:20px;margin-bottom:40px">'+
        '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;gap:10px;flex-wrap:wrap">'+
          '<div style="font-size:18px;font-weight:800;font-family:var(--sans)">'+(isNew?'Create New Bundle':'Edit Bundle')+'</div>'+
          '<div style="display:flex;gap:8px">'+
            '<button id="pv-bun-cancel" style="background:#fff;border:1.5px solid #0A0A0A;padding:9px 16px;font-size:12px;font-weight:800;cursor:pointer;font-family:var(--sans)">Cancel</button>'+
            '<button id="pv-bun-save" style="background:#10B981;color:#fff;border:2px solid #0A0A0A;padding:9px 20px;font-size:12px;font-weight:800;cursor:pointer;font-family:var(--sans);box-shadow:2px 2px 0 #0A0A0A">&#10003; Save Bundle</button>'+
          '</div>'+
        '</div>'+

        /* --- BASIC INFO --- */
        '<div style="background:#fafafa;border:1px solid #e5e5e5;padding:14px;margin-bottom:14px">'+
          '<div style="font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.5px;color:#555;margin-bottom:10px">Basic Info</div>'+
          '<div class="adm-fl"><label>Bundle Name</label><input id="pv-bn-name" value="'+esc(b.name)+'" placeholder="e.g. Starter Business Pack" style="width:100%;border:1.5px solid #0A0A0A;padding:9px 12px;font-size:13px;font-family:var(--sans)"></div>'+
          '<div class="adm-fl" style="margin-top:10px"><label>Tagline <span style="color:#aaa;font-size:10px">(one punchy line, shown on card + hero)</span></label><input id="pv-bn-tag" value="'+esc(b.tagline||'')+'" placeholder="e.g. The three things every new business needs." style="width:100%;border:1.5px solid #0A0A0A;padding:9px 12px;font-size:13px;font-family:var(--sans)"></div>'+
          '<div class="adm-fl" style="margin-top:10px"><label>Description <span style="color:#aaa;font-size:10px">(short, shown on listing card)</span></label><textarea id="pv-bn-desc" placeholder="e.g. Everything to start marketing your business" style="width:100%;border:1.5px solid #0A0A0A;padding:9px 12px;font-size:13px;font-family:var(--sans);min-height:60px;resize:vertical">'+esc(b.desc||'')+'</textarea></div>'+
        '</div>'+

        /* --- HERO IMAGE --- */
        '<div style="background:#fafafa;border:1px solid #e5e5e5;padding:14px;margin-bottom:14px">'+
          '<div style="font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.5px;color:#555;margin-bottom:10px">Hero Image <span style="font-weight:400;text-transform:none;letter-spacing:0;color:#aaa;font-size:10px">(shown large on bundle detail page + card thumbnail)</span></div>'+
          '<div id="pv-bn-preview" style="margin-bottom:10px">'+(b.image ? '<img src="'+b.image+'" style="max-height:180px;max-width:100%;border:1.5px solid #0A0A0A;object-fit:contain">' : '<div style="height:120px;background:#F3EEE2;border:1.5px dashed #0A0A0A;display:flex;align-items:center;justify-content:center;color:#888;font-size:12px">No image yet</div>')+'</div>'+
          '<div style="display:flex;gap:8px;flex-wrap:wrap">'+
            '<input type="file" id="pv-bn-file" accept="image/*" style="flex:1;min-width:200px">'+
            '<input id="pv-bn-url" value="'+esc(b.image||'')+'" placeholder="…or paste image URL" style="flex:2;min-width:200px;border:1.5px solid #0A0A0A;padding:8px 10px;font-size:12px;font-family:var(--sans)">'+
          '</div>'+
        '</div>'+

        /* --- PRODUCTS CHECKLIST --- */
        '<div style="background:#fafafa;border:1px solid #e5e5e5;padding:14px;margin-bottom:14px">'+
          '<div style="font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.5px;color:#555;margin-bottom:4px">Products in this Bundle <span style="font-weight:400;text-transform:none;letter-spacing:0;color:#aaa;font-size:10px">(check products to include — minimum 2)</span></div>'+
          '<input id="pv-bn-psearch" placeholder="Search products…" style="width:100%;border:1.5px solid #DDD;padding:8px 10px;font-size:12px;font-family:var(--sans);margin:8px 0 10px">'+
          '<div id="pv-bn-plist" style="max-height:280px;overflow-y:auto;border:1px solid #e5e5e5;padding:8px;background:#fff"></div>'+
        '</div>'+

        /* --- PRICING --- */
        '<div style="background:#fafafa;border:1px solid #e5e5e5;padding:14px;margin-bottom:14px">'+
          '<div style="font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.5px;color:#555;margin-bottom:10px">Pricing</div>'+
          '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px">'+
            '<div class="adm-fl" style="margin:0"><label>Bundle Price (S$)</label><input id="pv-bn-price" type="number" value="'+(b.price||'')+'" placeholder="188" style="width:100%;border:1.5px solid #0A0A0A;padding:9px 12px;font-size:13px;font-family:var(--sans)"></div>'+
            '<div class="adm-fl" style="margin:0"><label>Original Price (S$) <span style="color:#aaa;font-size:10px">(for "save" badge)</span></label><input id="pv-bn-orig" type="number" value="'+(b.original||'')+'" placeholder="236" style="width:100%;border:1.5px solid #0A0A0A;padding:9px 12px;font-size:13px;font-family:var(--sans)"></div>'+
          '</div>'+
          '<div class="adm-fl" style="margin-top:10px"><label>Status</label><select id="pv-bn-status" style="width:100%;border:1.5px solid #0A0A0A;padding:9px 12px;font-size:13px;font-family:var(--sans);background:#fff"><option value="active"'+(b.status==='active'?' selected':'')+'>Active — show on site</option><option value="draft"'+(b.status==='draft'?' selected':'')+'>Draft — hide from site</option></select></div>'+
        '</div>'+

        /* --- WHY --- */
        '<div style="background:#fafafa;border:1px solid #e5e5e5;padding:14px;margin-bottom:14px">'+
          '<div style="font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.5px;color:#555;margin-bottom:4px">"Why This Bundle" Points <span style="font-weight:400;text-transform:none;letter-spacing:0;color:#aaa;font-size:10px">(selling points shown on detail page)</span></div>'+
          '<div id="pv-bn-why" style="margin:8px 0"></div>'+
          '<button id="pv-bn-why-add" style="background:#fff;border:1.5px solid #0A0A0A;padding:7px 12px;font-size:11px;font-weight:700;cursor:pointer;font-family:var(--sans)">+ Add Point</button>'+
        '</div>'+

        /* --- FAQ --- */
        '<div style="background:#fafafa;border:1px solid #e5e5e5;padding:14px;margin-bottom:14px">'+
          '<div style="font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.5px;color:#555;margin-bottom:4px">Bundle FAQ <span style="font-weight:400;text-transform:none;letter-spacing:0;color:#aaa;font-size:10px">(question + answer pairs shown on detail page)</span></div>'+
          '<div id="pv-bn-faq" style="margin:8px 0"></div>'+
          '<button id="pv-bn-faq-add" style="background:#fff;border:1.5px solid #0A0A0A;padding:7px 12px;font-size:11px;font-weight:700;cursor:pointer;font-family:var(--sans)">+ Add FAQ</button>'+
        '</div>'+
      '</div>';

    /* Wire up product checklist */
    function renderProductChecklist(filter){
      filter = (filter||'').toLowerCase();
      var host = document.getElementById('pv-bn-plist');
      var slugs = Object.keys(allProducts).filter(function(s){
        var p = allProducts[s]; if(!p) return false;
        if(!filter) return true;
        return (p.name||s).toLowerCase().indexOf(filter)!==-1;
      });
      host.innerHTML = slugs.map(function(s){
        var p = allProducts[s];
        var checked = selected[s] ? 'checked' : '';
        var qty = (b.includes && b.includes[s] && b.includes[s].qty) || '';
        var spec = (b.includes && b.includes[s] && b.includes[s].spec) || '';
        var icon = p.icon || '&#128230;';
        return '<label style="display:flex;align-items:center;gap:8px;padding:6px 8px;border-bottom:1px solid #f3f4f6;cursor:pointer;flex-wrap:wrap">'+
          '<input type="checkbox" class="pv-bn-chk" data-slug="'+s+'" '+checked+' style="width:16px;height:16px;flex-shrink:0">'+
          '<span style="font-size:13px;font-weight:700;flex:1 1 140px;min-width:120px">'+icon+' '+esc(p.name||s)+'</span>'+
          '<input class="pv-bn-qty" data-slug="'+s+'" value="'+esc(qty)+'" placeholder="Qty (e.g. 100pc)" style="flex:1 1 120px;min-width:100px;border:1px solid #ddd;padding:5px 8px;font-size:11px;font-family:var(--sans)">'+
          '<input class="pv-bn-spec" data-slug="'+s+'" value="'+esc(spec)+'" placeholder="Spec (e.g. 350gsm)" style="flex:1 1 160px;min-width:120px;border:1px solid #ddd;padding:5px 8px;font-size:11px;font-family:var(--sans)">'+
        '</label>';
      }).join('');
      host.querySelectorAll('.pv-bn-chk').forEach(function(cb){
        cb.onchange = function(){ selected[this.dataset.slug] = this.checked; };
      });
    }
    renderProductChecklist('');
    document.getElementById('pv-bn-psearch').oninput = function(){ renderProductChecklist(this.value); };

    /* Image: file upload + URL */
    var fileInput = document.getElementById('pv-bn-file');
    var urlInput  = document.getElementById('pv-bn-url');
    function updatePreview(src){
      var prev = document.getElementById('pv-bn-preview');
      if(src) prev.innerHTML = '<img src="'+src+'" style="max-height:180px;max-width:100%;border:1.5px solid #0A0A0A;object-fit:contain">';
      else prev.innerHTML = '<div style="height:120px;background:#F3EEE2;border:1.5px dashed #0A0A0A;display:flex;align-items:center;justify-content:center;color:#888;font-size:12px">No image yet</div>';
    }
    fileInput.onchange = function(){
      var f = this.files && this.files[0]; if(!f) return;
      var r = new FileReader();
      r.onload = function(){ urlInput.value = r.result; updatePreview(r.result); };
      r.readAsDataURL(f);
    };
    urlInput.addEventListener('input', function(){ updatePreview(this.value.trim()); });

    /* Why list editor */
    function renderWhy(){
      var host = document.getElementById('pv-bn-why');
      host.innerHTML = (b.why||[]).map(function(txt, i){
        return '<div style="display:flex;gap:6px;align-items:center;margin-bottom:6px">'+
          '<input class="pv-bn-why-inp" data-i="'+i+'" value="'+esc(txt)+'" placeholder="Selling point" style="flex:1;border:1px solid #0A0A0A;padding:8px 10px;font-size:12px;font-family:var(--sans)">'+
          '<button class="pv-bn-why-del" data-i="'+i+'" style="background:#fff;border:1.5px solid #EF4444;color:#EF4444;padding:6px 10px;font-size:12px;font-weight:800;cursor:pointer">&#215;</button>'+
        '</div>';
      }).join('') || '<div style="color:#aaa;font-size:11px;padding:6px">No points yet — add one below.</div>';
      host.querySelectorAll('.pv-bn-why-inp').forEach(function(el){
        el.addEventListener('input', function(){ b.why[+this.dataset.i] = this.value; });
      });
      host.querySelectorAll('.pv-bn-why-del').forEach(function(el){
        el.onclick = function(){ b.why.splice(+this.dataset.i, 1); renderWhy(); };
      });
    }
    if(!Array.isArray(b.why)) b.why = [];
    renderWhy();
    document.getElementById('pv-bn-why-add').onclick = function(){ b.why.push(''); renderWhy(); };

    /* FAQ list editor */
    function renderFaq(){
      var host = document.getElementById('pv-bn-faq');
      host.innerHTML = (b.faq||[]).map(function(pair, i){
        var q = Array.isArray(pair) ? (pair[0]||'') : (pair.q||'');
        var a = Array.isArray(pair) ? (pair[1]||'') : (pair.a||'');
        return '<div style="border:1px solid #0A0A0A;padding:10px;margin-bottom:8px;background:#fff">'+
          '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px"><strong style="font-size:11px;text-transform:uppercase;color:#555">Q&amp;A #'+(i+1)+'</strong>'+
          '<button class="pv-bn-faq-del" data-i="'+i+'" style="background:#fff;border:1.5px solid #EF4444;color:#EF4444;padding:4px 8px;font-size:11px;font-weight:800;cursor:pointer">&#215; Remove</button></div>'+
          '<input class="pv-bn-faq-q" data-i="'+i+'" value="'+esc(q)+'" placeholder="Question" style="width:100%;border:1px solid #DDD;padding:7px 9px;font-size:12px;font-family:var(--sans);margin-bottom:6px">'+
          '<textarea class="pv-bn-faq-a" data-i="'+i+'" placeholder="Answer" style="width:100%;border:1px solid #DDD;padding:7px 9px;font-size:12px;font-family:var(--sans);min-height:50px;resize:vertical">'+esc(a)+'</textarea>'+
        '</div>';
      }).join('') || '<div style="color:#aaa;font-size:11px;padding:6px">No FAQs yet — add one below.</div>';
      host.querySelectorAll('.pv-bn-faq-q').forEach(function(el){
        el.addEventListener('input', function(){
          var i = +this.dataset.i;
          if(!Array.isArray(b.faq[i])) b.faq[i] = [b.faq[i] && b.faq[i].q || '', b.faq[i] && b.faq[i].a || ''];
          b.faq[i][0] = this.value;
        });
      });
      host.querySelectorAll('.pv-bn-faq-a').forEach(function(el){
        el.addEventListener('input', function(){
          var i = +this.dataset.i;
          if(!Array.isArray(b.faq[i])) b.faq[i] = [b.faq[i] && b.faq[i].q || '', b.faq[i] && b.faq[i].a || ''];
          b.faq[i][1] = this.value;
        });
      });
      host.querySelectorAll('.pv-bn-faq-del').forEach(function(el){
        el.onclick = function(){ b.faq.splice(+this.dataset.i, 1); renderFaq(); };
      });
    }
    if(!Array.isArray(b.faq)) b.faq = [];
    /* Normalise any object-form FAQs to [q,a] arrays */
    b.faq = b.faq.map(function(x){ return Array.isArray(x) ? x : [x.q||'', x.a||'']; });
    renderFaq();
    document.getElementById('pv-bn-faq-add').onclick = function(){ b.faq.push(['','']); renderFaq(); };

    /* Cancel */
    document.getElementById('pv-bn-cancel').onclick = function(){
      wrap.style.display = 'none'; wrap.innerHTML = '';
    };

    /* Save */
    document.getElementById('pv-bn-save').onclick = function(){
      var name = document.getElementById('pv-bn-name').value.trim();
      if(!name){ alert('Enter a bundle name.'); return; }
      var products = [];
      var includes = {};
      Object.keys(selected).forEach(function(s){
        if(selected[s]){
          products.push(s);
          var qtyEl = document.querySelector('.pv-bn-qty[data-slug="'+s+'"]');
          var specEl = document.querySelector('.pv-bn-spec[data-slug="'+s+'"]');
          includes[s] = {
            qty: qtyEl ? qtyEl.value.trim() : '',
            spec: specEl ? specEl.value.trim() : '',
            value: (b.includes && b.includes[s] && b.includes[s].value) || ''
          };
        }
      });
      if(products.length < 2){ alert('Pick at least 2 products for a bundle.'); return; }
      var price = parseFloat(document.getElementById('pv-bn-price').value) || 0;
      if(!price){ alert('Enter a bundle price.'); return; }
      var orig = parseFloat(document.getElementById('pv-bn-orig').value) || 0;

      var out = {
        id: b.id,
        name: name,
        tagline: document.getElementById('pv-bn-tag').value.trim(),
        desc: document.getElementById('pv-bn-desc').value.trim(),
        image: urlInput.value.trim(),
        products: products,
        includes: includes,
        price: price,
        original: orig,
        status: document.getElementById('pv-bn-status').value,
        why: (b.why||[]).filter(function(x){return x && x.trim();}),
        faq: (b.faq||[]).filter(function(x){ return Array.isArray(x) && (x[0]||x[1]); })
      };

      if(!window.BUNDLES) window.BUNDLES = [];
      if(isNew){
        window.BUNDLES.push(out);
      }else{
        var idx = window.BUNDLES.findIndex(function(x){return x.id===b.id;});
        if(idx > -1) window.BUNDLES[idx] = out;
        else window.BUNDLES.push(out);
      }
      persist();
      wrap.style.display = 'none'; wrap.innerHTML = '';
      renderBundlesPane();
      refreshPublicBundles();
      if(typeof window.showToast==='function') window.showToast('✓ Bundle saved — live on site');
    };
  }

  function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;'); }

  /* Boot */
  function boot(){
    hydrate();
    mountTab();
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', boot);
  else boot();
  /* Re-mount when admin screen appears (it's injected later) */
  setInterval(function(){ mountTab(); }, 1500);
  document.addEventListener('click', function(){ setTimeout(mountTab, 250); });
})();



(function(){
  var LS_KEY = 'pv_home_hero';

  /* Default values mirror the markup at lines ~7057–7095 */
  var DEFAULTS = {
    print: {
      num: '01 / 02 · PRINT',
      eyebrow: 'Printing Services',
      h1: 'Print that makes<br><em>your brand look<br>the part.</em>',
      sub: 'Name cards, flyers, banners, uniforms, signage — all under one roof at Paya Lebar Square. File check on every job. Express 24h available.',
      cta1: 'Browse Printing',
      cta2: 'WhatsApp Us',
      trust1: '24h Express',
      trust2: 'File Check',
      trust3: 'From S$28'
    },
    gifts: {
      num: '02 / 02 · GIFTS',
      eyebrow: 'Personalised Gifts',
      h1: 'Gifts that feel<br><em>made for them.</em>',
      sub: 'LED photo frames, engraved tumblers, custom tote bags, corporate hampers. Walk in with an idea — leave with a gift they\'ll keep.',
      cta1: 'Shop Gifts',
      cta2: 'WhatsApp Us',
      trust1: 'Ready in 3 Days',
      trust2: 'Custom Engraving',
      trust3: 'Gift-Wrap Available'
    }
  };

  function load(){
    try{
      var raw = localStorage.getItem(LS_KEY);
      if(!raw) return JSON.parse(JSON.stringify(DEFAULTS));
      var parsed = JSON.parse(raw);
      return {
        print: Object.assign({}, DEFAULTS.print, parsed.print||{}),
        gifts: Object.assign({}, DEFAULTS.gifts, parsed.gifts||{})
      };
    }catch(e){ return JSON.parse(JSON.stringify(DEFAULTS)); }
  }
  function save(data){
    try{ localStorage.setItem(LS_KEY, JSON.stringify(data)); }catch(e){}
  }

  /* Apply values to the live .hero-print / .hero-gifts DOM */
  function applyToDOM(data){
    var home = document.getElementById('screen-home');
    if(!home) return;
    ['print','gifts'].forEach(function(side){
      var root = home.querySelector('.hero-'+side);
      if(!root) return;
      var d = data[side];
      var num = root.querySelector('.hero-side-num');      if(num) num.textContent = d.num;
      var eb  = root.querySelector('.hero-eyebrow');       if(eb)  eb.textContent  = d.eyebrow;
      var h   = root.querySelector('.hero-h');             if(h)   h.innerHTML     = d.h1;
      var sub = root.querySelector('.hero-sub');           if(sub) sub.textContent = d.sub;
      var btns= root.querySelectorAll('.hero-btns button');
      if(btns[0]) btns[0].textContent = d.cta1;
      if(btns[1]) btns[1].textContent = d.cta2;
      var chips = root.querySelectorAll('.hero-trust span');
      if(chips[0]) chips[0].textContent = d.trust1;
      if(chips[1]) chips[1].textContent = d.trust2;
      if(chips[2]) chips[2].textContent = d.trust3;
    });
  }

  /* Boot: apply persisted values to the live homepage */
  function bootApply(){ applyToDOM(load()); }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', bootApply);
  else bootApply();

  /* Build the split-hero editor UI and inject into #pg-pane-homepage */
  function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;'); }

  function buildEditorHTML(data){
    function sideBlock(key, label, color, d){
      return ''+
      '<div style="border:2px solid '+color+';border-radius:6px;padding:14px;background:#fff">'+
        '<div style="font-size:12px;font-weight:800;text-transform:uppercase;letter-spacing:.5px;color:'+color+';margin-bottom:10px">'+label+'</div>'+
        '<div class="adm-fl"><label>Side label (top-left)</label><input data-hh="'+key+'.num" value="'+esc(d.num)+'"></div>'+
        '<div class="adm-fl"><label>Eyebrow</label><input data-hh="'+key+'.eyebrow" value="'+esc(d.eyebrow)+'"></div>'+
        '<div class="adm-fl"><label>Headline (HTML — &lt;br&gt;, &lt;em&gt; allowed)</label><textarea data-hh="'+key+'.h1" style="min-height:70px">'+esc(d.h1)+'</textarea></div>'+
        '<div class="adm-fl"><label>Sub-headline</label><textarea data-hh="'+key+'.sub" style="min-height:60px">'+esc(d.sub)+'</textarea></div>'+
        '<div class="adm-grid-2">'+
          '<div class="adm-fl"><label>CTA Button 1</label><input data-hh="'+key+'.cta1" value="'+esc(d.cta1)+'"></div>'+
          '<div class="adm-fl"><label>CTA Button 2</label><input data-hh="'+key+'.cta2" value="'+esc(d.cta2)+'"></div>'+
        '</div>'+
        '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#888;margin:8px 0 6px">Trust chips</div>'+
        '<div class="adm-grid-2">'+
          '<div class="adm-fl"><input data-hh="'+key+'.trust1" value="'+esc(d.trust1)+'"></div>'+
          '<div class="adm-fl"><input data-hh="'+key+'.trust2" value="'+esc(d.trust2)+'"></div>'+
        '</div>'+
        '<div class="adm-fl"><input data-hh="'+key+'.trust3" value="'+esc(d.trust3)+'"></div>'+
      '</div>';
    }
    return ''+
    '<div class="adm-section-title">Hero Banner (split — Print / Gifts)</div>'+
    '<p style="font-size:12px;color:#555;margin:6px 0 14px">The homepage hero is split into two sides. Edit each side separately. Changes save to localStorage and apply to the live homepage immediately.</p>'+
    '<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px">'+
      sideBlock('print','01 · Print side','#EC1C7D', data.print)+
      sideBlock('gifts','02 · Gifts side','#FFD100', data.gifts)+
    '</div>'+
    '<div style="margin-top:14px;display:flex;gap:10px;align-items:center">'+
      '<button id="pv-hh-save" class="btn-primary" style="padding:10px 18px">Save hero banner</button>'+
      '<button id="pv-hh-reset" class="btn-sec" style="padding:10px 14px">Reset to defaults</button>'+
      '<span id="pv-hh-status" style="font-size:12px;color:#16a34a;font-weight:700"></span>'+
    '</div>';
  }

  function collectFromEditor(scope){
    var data = { print:{}, gifts:{} };
    scope.querySelectorAll('[data-hh]').forEach(function(el){
      var path = el.getAttribute('data-hh').split('.');
      data[path[0]][path[1]] = el.value;
    });
    /* Fill any missing keys from defaults so we never write a partial object */
    data.print = Object.assign({}, DEFAULTS.print, data.print);
    data.gifts = Object.assign({}, DEFAULTS.gifts, data.gifts);
    return data;
  }

  function mountEditor(){
    var pane = document.getElementById('pg-pane-homepage');
    if(!pane) return;
    if(pane.dataset.pvHeroSplitMounted==='1') return;

    /* Replace the first .adm-card (legacy "Hero Section") with our split editor */
    var legacy = pane.querySelector('.adm-card');
    if(!legacy) return;

    var data = load();
    var wrap = document.createElement('div');
    wrap.className = 'adm-card';
    wrap.style.marginBottom = '12px';
    wrap.innerHTML = buildEditorHTML(data);
    legacy.parentNode.replaceChild(wrap, legacy);
    pane.dataset.pvHeroSplitMounted = '1';

    wrap.querySelector('#pv-hh-save').addEventListener('click', function(){
      var d = collectFromEditor(wrap);
      save(d);
      applyToDOM(d);
      var st = wrap.querySelector('#pv-hh-status');
      if(st){ st.textContent = '✓ Saved — live on homepage'; setTimeout(function(){ st.textContent=''; }, 2500); }
      if(typeof window.showToast==='function') window.showToast('✓ Hero banner saved');
    });
    wrap.querySelector('#pv-hh-reset').addEventListener('click', function(){
      if(!confirm('Reset hero banner to default text?')) return;
      try{ localStorage.removeItem(LS_KEY); }catch(e){}
      var d = JSON.parse(JSON.stringify(DEFAULTS));
      applyToDOM(d);
      /* Rebuild editor inputs */
      pane.dataset.pvHeroSplitMounted = '';
      wrap.remove();
      mountEditor();
    });
  }

  /* SPA mount strategy — admin screen is injected late */
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', mountEditor);
  else mountEditor();
  setInterval(mountEditor, 1500);
  document.addEventListener('click', function(){ setTimeout(mountEditor, 250); });
})();



(function(){
  /* ── 1. Slug + category utilities ─────────────────────────────── */
  function slugify(s){
    return String(s||'').toLowerCase().trim()
      .replace(/&/g,'and')
      .replace(/[^a-z0-9]+/g,'-')
      .replace(/^-+|-+$/g,'') || 'item';
  }
  window.pvSlugify = slugify;

  function productUrl(slug){
    var p = (window.PRODUCTS_DATA||{})[slug];
    if(!p) return '#';
    var cat = slugify(p.category || 'uncategorized');
    var url = '/product/' + cat + '/';
    if(p.subcategory) url += slugify(p.subcategory) + '/';
    url += (p.slug || slug) + '/';
    return url;
  }
  function bundleUrl(id){
    return '/bundle/' + slugify(id) + '/';
  }
  function categoryUrl(cat){
    return '/product/' + slugify(cat) + '/';
  }
  window.pvProductUrl = productUrl;
  window.pvBundleUrl  = bundleUrl;
  window.pvCategoryUrl = categoryUrl;

  /* ── 2. Static-mode detection ─────────────────────────────────── */
  var STATIC_MODE = !!(window.__PV_PAGE__);

  /* phase-2 nav override removed by build_static_site.py — the
   delegated click handler in each HTML page handles navigation. */
if(false){}
  /* ── 4. Hash-fallback — old #product-name-card backlinks ─────── */
  (function hashRedirect(){
    var h = location.hash || '';
    var m = h.match(/^#product-([a-z0-9-]+)/i);
    if(m){
      var slug = m[1];
      var u = productUrl(slug);
      if(u && u !== '#'){
        history.replaceState(null,'',u);
        location.reload();
      }
      return;
    }
    m = h.match(/^#bundle-([a-z0-9-]+)/i);
    if(m){ location.replace(bundleUrl(m[1])); return; }
    var scrMap = {'#shop':'/shop.html','#about':'/about.html','#contact':'/contact.html','#cart':'/cart.html'};
    if(scrMap[h]){ location.replace(scrMap[h]); }
  })();

  /* ── 5. On static page load, route to the right screen ────────── */
  if(STATIC_MODE){
    /* Inject CSS to hide pre-rendered SEO blocks visually while keeping
       them crawlable. Placed off-screen per Google guidance on alternative
       text content (not display:none, which gets discounted). */
    (function(){
      var s = document.createElement('style');
      s.textContent = '.pv-seo-static{position:absolute!important;left:-10000px!important;top:auto!important;width:1px!important;height:1px!important;overflow:hidden!important;}';
      document.head.appendChild(s);
    })();
    function routeFromPageObj(){
      var pg = window.__PV_PAGE__;
      if(!pg) return;
      /* Remove the pre-rendered SEO block once the SPA has booted.
         Its job (giving crawlers real content) is done. */
      var seo = document.querySelector('.pv-seo-static');
      if(seo) seo.remove();
      var scr = pg.screen;
      if(scr && typeof window.go==='function'){
        /* go() would now navigate away — use the ORIGINAL internal
           screen-switch logic by calling the hash-style router directly.
           Fallback: add .active class manually. */
        document.querySelectorAll('.screen').forEach(function(el){el.classList.remove('active');});
        var target = document.getElementById('screen-'+scr);
        if(target) target.classList.add('active');
      }
      if(pg.type==='product' && pg.slug){
        if(typeof window.renderProductPage==='function'){
          window._currentProductSlug = pg.slug;
          /* renderProductPage(slug, prod) requires BOTH arguments — its
             body dereferences prod.type / prod.pricing without an internal
             lookup. Pass the prod object from PRODUCTS_DATA. */
          var _prod = (window.PRODUCTS_DATA || {})[pg.slug];
          if(_prod){
            try{ window.renderProductPage(pg.slug, _prod); }catch(e){ console.error('renderProductPage failed', e); }
          }
        }
      }
      if(pg.type==='bundle' && pg.id){
        if(typeof window.renderBundlePage==='function'){
          try{ window.renderBundlePage(pg.id); }catch(e){ console.error('renderBundlePage failed', e); }
        }
      }
      if(pg.type==='shop'){
        /* Shop grid only populates on go('shop'); call it directly. */
        if(typeof window.buildShopGrid==='function'){
          try{ window.buildShopGrid(); }catch(e){ console.error('buildShopGrid failed', e); }
        }
      }
      if((pg.type==='category' || pg.type==='subcategory') && pg.category){
        if(typeof window.buildShopGrid==='function'){
          try{ window.buildShopGrid(); }catch(e){}
        }
        if(typeof window.shopFilter==='function'){
          try{ window.shopFilter(pg.category); }catch(e){}
        }
      }
    }
    if(document.readyState==='loading'){
      document.addEventListener('DOMContentLoaded', routeFromPageObj);
    }else{
      setTimeout(routeFromPageObj, 50);
    }
  }

  /* ── 6. Admin product editor — inject Slug + Category fields ──── */
  function enhanceProductEditor(){
    var ed = document.getElementById('adm-prod-editor');
    if(!ed || ed.dataset.pvSlugCatMounted==='1') return;
    var nameInput = document.getElementById('pe-name');
    if(!nameInput) return;
    ed.dataset.pvSlugCatMounted = '1';

    /* Find the current product slug being edited */
    var slug = (window.admCurrentProduct || window._editingProduct || '');
    var p = (window.PRODUCTS_DATA||{})[slug] || {};

    /* Collect unique categories */
    var cats = {};
    Object.keys(window.PRODUCTS_DATA||{}).forEach(function(k){
      var c = PRODUCTS_DATA[k].category;
      if(c) cats[c] = 1;
    });
    var catList = Object.keys(cats).sort();

    var wrap = document.createElement('div');
    wrap.className = 'pv-slugcat-wrap';
    wrap.style.cssText = 'display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:8px';
    wrap.innerHTML =
      '<div class="adm-fl">'+
        '<label>URL slug <span style="color:#888;font-weight:400">(editable)</span></label>'+
        '<input id="pe-slug" value="'+((p.slug||slug)||'').replace(/"/g,'&quot;')+'">'+
        '<div style="font-size:11px;color:#666;margin-top:4px">Preview: <code id="pe-slug-preview" style="font-size:11px">/product/…/</code></div>'+
      '</div>'+
      '<div class="adm-fl">'+
        '<label>Category</label>'+
        '<select id="pe-category" style="width:100%">'+
          catList.map(function(c){
            return '<option value="'+c.replace(/"/g,'&quot;')+'"'+(c===p.category?' selected':'')+'>'+c.replace(/</g,'&lt;')+'</option>';
          }).join('')+
          '<option value="__new__">➕ Add new category…</option>'+
        '</select>'+
        '<input id="pe-subcategory" placeholder="(optional) subcategory" value="'+((p.subcategory||'')||'').replace(/"/g,'&quot;')+'" style="margin-top:6px">'+
      '</div>';

    nameInput.parentNode.parentNode.insertBefore(wrap, nameInput.parentNode.nextSibling);

    /* Auto-slug when name changes (only if slug field is empty OR unlocked) */
    var slugInput = wrap.querySelector('#pe-slug');
    var slugLocked = !!slugInput.value;
    nameInput.addEventListener('input', function(){
      if(!slugLocked) slugInput.value = slugify(nameInput.value);
      updatePreview();
    });
    slugInput.addEventListener('input', function(){
      slugLocked = true;
      updatePreview();
    });
    var catSel = wrap.querySelector('#pe-category');
    catSel.addEventListener('change', function(){
      if(catSel.value==='__new__'){
        var nc = prompt('New category name:');
        if(nc){
          var opt = document.createElement('option');
          opt.value = nc; opt.textContent = nc; opt.selected = true;
          catSel.insertBefore(opt, catSel.querySelector('option[value="__new__"]'));
        }else{
          catSel.value = p.category || catList[0];
        }
      }
      updatePreview();
    });
    var subInput = wrap.querySelector('#pe-subcategory');
    subInput.addEventListener('input', updatePreview);
    function updatePreview(){
      var c = slugify(catSel.value==='__new__'?'':catSel.value);
      var s = slugify(subInput.value);
      var pv = '/product/' + (c||'uncategorized') + '/' + (s?(s+'/'):'') + (slugInput.value||'slug') + '/';
      var pvEl = wrap.querySelector('#pe-slug-preview');
      if(pvEl) pvEl.textContent = pv;
    }
    updatePreview();
  }

  /* Hook into admin save to capture slug+category */
  function patchProductSave(){
    if(window._pvProdSavePatched) return;
    if(typeof window.admSaveProduct !== 'function') return;
    window._pvProdSavePatched = true;
    var orig = window.admSaveProduct;
    window.admSaveProduct = function(){
      var slugV = document.getElementById('pe-slug');
      var catV  = document.getElementById('pe-category');
      var subV  = document.getElementById('pe-subcategory');
      var slug = (window.admCurrentProduct || window._editingProduct || '');
      var p = (window.PRODUCTS_DATA||{})[slug];
      if(p){
        if(slugV && slugV.value) p.slug = slugify(slugV.value);
        if(catV && catV.value && catV.value!=='__new__') p.category = catV.value;
        if(subV) p.subcategory = subV.value.trim() || null;
      }
      return orig.apply(this, arguments);
    };
  }

  /* ── 7. Categories admin tab — rename + reorder ──────────────── */
  function mountCategoriesTab(){
    var nav = document.querySelector('#screen-admin .adm-tabs, #screen-admin [class*="adm-tab"]');
    /* Fallback: find any element that contains the Products tab button */
    if(!nav){
      var prodBtn = Array.from(document.querySelectorAll('#screen-admin button')).find(function(b){
        return /products/i.test(b.textContent) && !b.dataset.pvCategoriesTab;
      });
      if(prodBtn) nav = prodBtn.parentNode;
    }
    if(!nav || nav.dataset.pvCategoriesMounted==='1') return;
    /* Check if already present */
    if(Array.from(nav.querySelectorAll('button')).find(function(b){return b.dataset.pvCategoriesTab;})) return;

    var btn = document.createElement('button');
    btn.textContent = '📂 Categories';
    btn.className = 'adm-tab';
    btn.dataset.pvCategoriesTab = '1';
    btn.style.cssText = 'padding:10px 16px;background:#fff;border:1px solid #ddd;cursor:pointer;font-size:13px';
    btn.onclick = openCategoriesEditor;
    nav.appendChild(btn);
    nav.dataset.pvCategoriesMounted = '1';
  }

  function openCategoriesEditor(){
    var panel = document.getElementById('pv-categories-pane');
    if(!panel){
      panel = document.createElement('div');
      panel.id = 'pv-categories-pane';
      panel.style.cssText = 'padding:24px;max-width:960px;margin:0 auto;background:#fff;min-height:400px';
      var host = document.getElementById('screen-admin') || document.body;
      host.appendChild(panel);
    }
    /* Hide other admin panes */
    document.querySelectorAll('#screen-admin [id^="adm-pane-"]').forEach(function(el){el.style.display='none';});
    panel.style.display = 'block';

    /* Build by scanning PRODUCTS_DATA */
    var groups = {};
    Object.keys(window.PRODUCTS_DATA||{}).forEach(function(k){
      var p = PRODUCTS_DATA[k];
      var c = p.category || 'Uncategorized';
      (groups[c] = groups[c] || []).push({slug:k, name:p.name, subcategory:p.subcategory});
    });
    var rows = Object.keys(groups).sort().map(function(cat){
      var prods = groups[cat];
      var subs = {};
      prods.forEach(function(pr){ if(pr.subcategory) subs[pr.subcategory]=(subs[pr.subcategory]||0)+1; });
      var subTxt = Object.keys(subs).length
        ? ('<div style="font-size:11px;color:#888;margin-top:4px">Sub: '+Object.keys(subs).map(function(s){return s+' ('+subs[s]+')';}).join(' · ')+'</div>')
        : '';
      return ''+
      '<div class="pv-cat-row" data-cat="'+cat.replace(/"/g,'&quot;')+'" style="border:1px solid #e0e0e0;border-radius:6px;padding:14px 16px;margin-bottom:10px;background:#fafafa">'+
        '<div style="display:flex;align-items:center;gap:12px">'+
          '<div style="flex:1">'+
            '<input class="pv-cat-name" value="'+cat.replace(/"/g,'&quot;')+'" style="width:100%;font-weight:700;font-size:15px;padding:8px;border:1px solid #ddd;border-radius:4px">'+
            '<div style="font-size:11px;color:#666;margin-top:6px">'+prods.length+' product'+(prods.length!==1?'s':'')+' · slug: <code>'+slugify(cat)+'</code> → URL: <code>/product/'+slugify(cat)+'/</code></div>'+
            subTxt+
          '</div>'+
          '<button class="pv-cat-save" style="padding:8px 14px;background:#EC1C7D;color:#fff;border:none;border-radius:4px;cursor:pointer;font-weight:700">Rename</button>'+
        '</div>'+
      '</div>';
    });

    panel.innerHTML =
      '<h2 style="margin:0 0 6px;font-family:Unbounded,sans-serif;font-size:22px">Categories</h2>'+
      '<p style="color:#666;font-size:13px;margin:0 0 18px">Rename a category — every product in it gets updated. The URL slug auto-regenerates. Old URLs get a 301 redirect on next build.</p>'+
      rows.join('')+
      '<div style="margin-top:14px;padding:14px;background:#fffbea;border:1px solid #f59e0b;border-radius:6px;font-size:12px;color:#78350f">'+
        '<strong>Note:</strong> Changes here edit <code>PRODUCTS_DATA</code> in memory and save to localStorage. Run <code>python3 build_static_site.py</code> to regenerate the static site with new URLs.'+
      '</div>';

    panel.querySelectorAll('.pv-cat-save').forEach(function(btn){
      btn.addEventListener('click', function(){
        var row = btn.closest('.pv-cat-row');
        var oldCat = row.dataset.cat;
        var newCat = row.querySelector('.pv-cat-name').value.trim();
        if(!newCat || newCat===oldCat) return;
        if(!confirm('Rename "'+oldCat+'" → "'+newCat+'"?\nAll products in this category will be updated.\nURL will change: /product/'+slugify(oldCat)+'/ → /product/'+slugify(newCat)+'/')) return;
        Object.keys(window.PRODUCTS_DATA||{}).forEach(function(k){
          if(PRODUCTS_DATA[k].category===oldCat) PRODUCTS_DATA[k].category = newCat;
        });
        try{ localStorage.setItem('pv_products_override', JSON.stringify(window.PRODUCTS_DATA)); }catch(e){}
        /* Log slug history for redirect generation */
        try{
          var hist = JSON.parse(localStorage.getItem('pv_slug_history')||'[]');
          hist.push({type:'category', oldSlug:slugify(oldCat), newSlug:slugify(newCat), at:Date.now()});
          localStorage.setItem('pv_slug_history', JSON.stringify(hist));
        }catch(e){}
        openCategoriesEditor(); /* re-render */
        if(typeof window.showToast==='function') window.showToast('✓ Category renamed. Rebuild site to publish.');
      });
    });
  }

  /* ── Boot all admin enhancements ─────────────────────────────── */
  function bootAdmin(){
    try{ enhanceProductEditor(); }catch(e){}
    try{ patchProductSave(); }catch(e){}
    try{ mountCategoriesTab(); }catch(e){}
  }
  if(document.readyState==='loading'){
    document.addEventListener('DOMContentLoaded', bootAdmin);
  }else{
    bootAdmin();
  }
  setInterval(bootAdmin, 1500);
  document.addEventListener('click', function(){ setTimeout(bootAdmin, 200); });
})();
